/* AUTO-GENERATED — Minnesota Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["MN"] = {"code":"MN","name":"Minnesota","agency":"Minnesota DVS","agencyShort":"DVS","handbook":"https://dps.mn.gov/divisions/dvs/license-and-id/cdl-cdl/cdl-forms-documents-and-resources","links":{},"en":[{"q":"What is the maximum legal width of a commercial vehicle on Minnesota highways, excluding mirrors and load-securement devices?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","8 feet 4 inches (100 inches)"],"answer":1,"explanation":"Minnesota Statute 169.80 sets the maximum total outside width at 102 inches (8 feet 6 inches). This matches the federal standard. Source: Minn. Stat. 169.80; MnDOT CVO.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle, loaded or unloaded, on Minnesota highways?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","14 feet 6 inches"],"answer":2,"explanation":"Minnesota Statute 169.81 states no vehicle unladen or with load shall exceed a height of 13 feet 6 inches. Source: Minn. Stat. 169.81; Minnesota CDL Manual.","handbook":"","hbref":""},{"q":"What is the maximum gross weight for a vehicle or combination of vehicles on Minnesota streets and highways without a permit?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"answer":1,"explanation":"Minnesota Statute 169.824 limits gross vehicle weight to 80,000 pounds on all streets and highways, consistent with the federal limit. Source: Minn. Stat. 169.824; MnDOT.","handbook":"","hbref":""},{"q":"Under Minnesota law, what is the maximum weight allowed on a single axle on a paved highway?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"Minnesota Statute 169.823 limits a single axle to 20,000 pounds on paved streets and highways. Source: Minn. Stat. 169.823; MnDOT CVO Truck Book.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a tandem axle group in Minnesota?","options":["32,000 pounds","36,000 pounds","34,000 pounds","40,000 pounds"],"answer":2,"explanation":"Minnesota follows the federal tandem-axle limit of 34,000 pounds, codified in the axle-weight schedule of Minn. Stat. 169.824. Source: Minn. Stat. 169.824; Minnesota CDL Manual.","handbook":"","hbref":""},{"q":"On a Minnesota highway, what is the maximum overall length of a single (non-articulated) vehicle, including load and bumpers?","options":["40 feet","45 feet","48 feet","53 feet"],"answer":1,"explanation":"Minnesota Statute 169.81 limits a single vehicle to 45 feet overall, including load and front and rear bumpers (mobile cranes may reach 48 feet). Source: Minn. Stat. 169.81.","handbook":"","hbref":""},{"q":"What is the maximum overall length of a two-unit (tractor-semitrailer) combination on Minnesota highways without a permit?","options":["65 feet","70 feet","75 feet","80 feet"],"answer":2,"explanation":"Minnesota Statute 169.81 sets the maximum length of a two-unit combination of vehicles at 75 feet. Source: Minn. Stat. 169.81; MnDOT CVO.","handbook":"","hbref":""},{"q":"A semitrailer in a tractor-semitrailer combination in Minnesota generally may not exceed what length?","options":["45 feet","48 feet","53 feet","57 feet"],"answer":1,"explanation":"Minnesota Statute 169.81 provides that a semitrailer generally may not exceed 48 feet, though up to 53 feet is allowed when the kingpin-to-rear-axle distance does not exceed 43 feet. Source: Minn. Stat. 169.81.","handbook":"","hbref":""},{"q":"Which formula does Minnesota use to determine the maximum allowable weight on a group of consecutive axles based on axle spacing and number of axles?","options":["The Federal Bridge Formula","The Gross Combination Rating formula","The Minnesota Tonnage Index","The Axle Load Equivalency formula"],"answer":0,"explanation":"Minnesota's axle-group weight table in Minn. Stat. 169.824 implements the Federal Bridge Formula, allowing more weight as axles and spacing increase. Source: Minn. Stat. 169.824; Minnesota CDL Manual.","handbook":"","hbref":""},{"q":"When is a MnDOT oversize/overweight (OSOW) permit required to move a load on a Minnesota highway?","options":["Only when the load exceeds 100,000 pounds","When the vehicle or load exceeds any legal size or weight limit","Only for loads wider than 10 feet","Only on Interstate highways"],"answer":1,"explanation":"A MnDOT OSOW permit is required whenever a vehicle or load exceeds a legal size or weight limit and will move on or across a Minnesota highway. Source: Minn. Stat. 169.86; MnDOT CVO Oversize/Overweight Permits.","handbook":"","hbref":""},{"q":"Beyond the 102-inch legal width, how far may rearview mirrors or load-securement devices that are not an integral part of the vehicle legally extend on each side in Minnesota?","options":["Up to 3 inches each side","Up to 6 inches each side","They may not extend at all","Up to 12 inches each side"],"answer":0,"explanation":"Minnesota Statute 169.80 allows mirrors or load-securement devices that are not integral to the vehicle to extend up to 3 inches beyond the 102-inch width on each side. Source: Minn. Stat. 169.80.","handbook":"","hbref":""},{"q":"During a winter weight increase declared by the commissioner, by how much may Minnesota seasonal gross and axle weight limits be raised on eligible roads?","options":["5 percent","10 percent","15 percent","20 percent"],"answer":1,"explanation":"Minnesota Statute 169.826 authorizes the commissioner to increase weight limits by 10 percent during the winter (frozen-road) period set for each zone. Source: Minn. Stat. 169.826; MnDOT.","handbook":"","hbref":""},{"q":"What height does a double-deck bus operating under an annual permit get to reach in Minnesota, above the standard 13-foot-6-inch limit?","options":["13 feet 9 inches","14 feet 0 inches","14 feet 3 inches","15 feet 0 inches"],"answer":2,"explanation":"Minnesota Statute 169.81 allows a double-deck bus to reach 14 feet 3 inches in height when operated under an annual permit. Source: Minn. Stat. 169.81.","handbook":"","hbref":""},{"q":"The Minnesota harvest-season 10 percent weight increase under Statute 169.826 applies to the movement of which raw agricultural products from field to first unloading point?","options":["Corn, soybeans, and wheat","Sugar beets, carrots, and potatoes","Hay, straw, and silage","Apples, grapes, and onions"],"answer":1,"explanation":"Minnesota Statute 169.826, subd. 1a, grants a harvest-season 10 percent increase for moving sugar beets, carrots, and potatoes from the field of harvest to first unloading, through November 30, with a permit. Source: Minn. Stat. 169.826.","handbook":"","hbref":""},{"q":"How are an oversize/overweight permit and trip log most commonly obtained from MnDOT?","options":["By visiting a county sheriff's office in person","Online through a MnDOT CVO web account after payment","By mailing a paper form to the legislature","Automatically issued with the CDL"],"answer":1,"explanation":"MnDOT issues annual, seasonal, or single-trip OSOW permits online; the carrier sets up a CVO web account and pays before the permit is issued. Source: MnDOT CVO Oversize/Overweight Permits.","handbook":"","hbref":""},{"q":"An extended semitrailer in Minnesota may reach 53 feet only if the distance from the kingpin to the center of the rearmost axle does not exceed what figure?","options":["40 feet","41 feet","43 feet","46 feet"],"answer":2,"explanation":"Minnesota Statute 169.81 permits a semitrailer up to 53 feet provided the kingpin-to-rear-axle-center distance does not exceed 43 feet. Source: Minn. Stat. 169.81.","handbook":"","hbref":""},{"q":"Six-axle vehicles exclusively hauling livestock may operate at up to what gross weight on Minnesota trunk highways (other than Interstates) under a permit?","options":["80,000 pounds","84,000 pounds","88,000 pounds","90,000 pounds"],"answer":2,"explanation":"Minnesota Statute 169.8261/169.824 allows a permitted gross weight up to 88,000 pounds for vehicles with six or more axles exclusively hauling livestock on trunk highways other than Interstates. Source: Minn. Stat. 169.824; MnDOT CVO.","handbook":"","hbref":""},{"q":"In Minnesota, which CDL class is required to operate a combination of vehicles with a gross combination weight rating over 26,000 pounds where the towed unit has a GVWR of more than 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"The Minnesota CDL Manual (Part A) defines Class A as any vehicle towing a unit of more than 10,000 pounds GVWR with a gross combination weight rating (truck plus trailer) over 26,000 pounds. Source: MN DVS Commercial Driver's License Manual, Part A.","handbook":"","hbref":""},{"q":"Under Minnesota rules, a single-unit vehicle with a GVWR over 26,000 pounds (towing nothing, or towing a unit 10,000 pounds or less) requires which CDL class?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"The Minnesota CDL Manual defines Class B as a single-unit vehicle that is over 26,000 pounds GVWR; it also covers towing a unit not exceeding 10,000 pounds. Source: MN DVS CDL Manual, Part A.","handbook":"","hbref":""},{"q":"In Minnesota, a Class C CDL applies to a single-unit vehicle of 26,000 pounds GVWR or less only when the vehicle is used for what purpose?","options":["Any vehicle used for hire regardless of cargo","Transporting hazardous materials requiring placards, or carrying 16 or more passengers","Towing any trailer over 10,000 pounds","Operating any vehicle outside Minnesota"],"answer":1,"explanation":"The Minnesota CDL Manual states Class C is a single-unit vehicle 26,000 pounds GVWR or less that carries hazardous materials (placarded), passengers, or is a school bus, requiring the corresponding endorsement. Source: MN DVS CDL Manual, Part A.","handbook":"","hbref":""},{"q":"Which endorsement does Minnesota require for a driver who operates a tank vehicle designed to transport liquids or gases in a tank with an individual rated capacity of more than 119 gallons and an aggregate of 1,000 gallons or more?","options":["H (Hazardous Materials)","T (Doubles/Triples)","N (Tank Vehicle)","X (Tanker and HazMat)"],"answer":2,"explanation":"The Minnesota CDL Manual defines the N (Tank Vehicle) endorsement for any CMV designed to transport liquid or gaseous materials in a tank with an individual rated capacity over 119 gallons and an aggregate rated capacity of 1,000 gallons or more. Source: MN DVS CDL Manual, Endorsements section.","handbook":"","hbref":""},{"q":"In Minnesota, which endorsement is needed to pull double or triple trailers, and which class of vehicle is it generally associated with?","options":["The T endorsement, generally for Class A drivers","The N endorsement, generally for Class B drivers","The P endorsement, generally for Class C drivers","The H endorsement, generally for Class A drivers"],"answer":0,"explanation":"The Minnesota CDL Manual states the T (Doubles/Triples) endorsement is added to the licenses of Class A drivers who wish to pull double or triple trailers, requiring a special knowledge examination. Source: MN DVS CDL Manual, Endorsements / Doubles and Triples.","handbook":"","hbref":""},{"q":"Which two endorsements does Minnesota combine into the single 'X' endorsement?","options":["Passenger and school bus","Tank vehicle and hazardous materials","Doubles/triples and tank vehicle","Hazardous materials and passenger"],"answer":1,"explanation":"The Minnesota CDL Manual lists the X endorsement as 'Tanker and Hazardous Materials,' required for drivers of tank vehicles hauling hazardous materials/waste in placarded amounts, who must pass both the tank and HazMat knowledge exams. Source: MN DVS CDL Manual, Endorsements.","handbook":"","hbref":""},{"q":"In Minnesota, what is required before a driver can be issued a hazardous materials (H) endorsement, in addition to passing the HazMat knowledge test?","options":["A road skills test in a placarded tank vehicle","A TSA security threat assessment that includes fingerprinting and a background check","Five years of verifiable interstate driving experience","A separate MnDOT oversize/overweight permit"],"answer":1,"explanation":"The Minnesota CDL Manual states the Transportation Security Administration conducts a background check (criminal, immigration, and FBI records) and requires fingerprints before a HazMat endorsement is issued or renewed. Source: MN DVS CDL Manual, Hazardous Materials / Background Check / Fingerprints.","handbook":"","hbref":""},{"q":"In Minnesota, the school bus (S) endorsement can only be added to a CDL when the driver also holds which other endorsement?","options":["Tank vehicle (N)","Doubles/triples (T)","Passenger (P)","Hazardous materials (H)"],"answer":2,"explanation":"Minnesota requires the school bus (S) endorsement to be accompanied by the passenger (P) endorsement; the Class C definition in the manual specifies 'school bus (with passenger endorsement).' Source: MN DVS CDL Manual, Part A / Endorsements.","handbook":"","hbref":""},{"q":"For a passenger (P) endorsement on a Class B CDL in Minnesota, the skills (road) test must be passed in a bus with a GVWR greater than 26,000 pounds and a passenger capacity of how many, including the driver?","options":["More than 8","More than 10","More than 15","More than 24"],"answer":2,"explanation":"The Minnesota CDL Manual states that for a passenger (or school bus) endorsement, the skills test must be passed in a bus with a GVWR greater than 26,000 pounds and a passenger capacity of more than 15, including the driver. Source: MN DVS CDL Manual, Part A (Class B).","handbook":"","hbref":""},{"q":"What is the minimum age to apply for a Minnesota CDL that is restricted to intrastate (within-Minnesota) commercial driving?","options":["16 years old","18 years old","19 years old","21 years old"],"answer":1,"explanation":"The Minnesota CDL Manual lists a minimum age of 18 to apply for an intrastate CDL (e.g., single vehicle over 26,000 lbs GVW or combination over 26,000 lbs GCW). Source: MN DVS CDL Manual, Part A (minimum age).","handbook":"","hbref":""},{"q":"Under Minnesota and federal rules, what is generally the minimum age to operate a CMV in interstate commerce or to transport hazardous materials requiring placards?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"The Minnesota CDL Manual notes that for any size vehicle requiring hazardous materials placards you must in most cases be 21, and interstate operation generally requires age 21. Source: MN DVS CDL Manual, Part A (minimum age / interstate).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Minnesota Commercial Learner Permit (CLP), and what must the applicant already hold?","options":["16, with a learner's permit","18, with a valid Minnesota driver's license","19, with a valid Minnesota driver's license","21, with a valid Class D license"],"answer":1,"explanation":"The Minnesota CDL Manual states you must be at least 18 years old and have a valid Minnesota driver's license to obtain a CLP. Source: MN DVS CDL Manual, Commercial Learner Permit.","handbook":"","hbref":""},{"q":"In Minnesota, how long must a Commercial Learner Permit (CLP) be held before the holder may take the CDL skills (road) test?","options":["7 calendar days","10 calendar days","14 calendar days","30 calendar days"],"answer":2,"explanation":"The Minnesota CDL Manual states the CLP must be held for 14 calendar days before being able to take the CDL road tests, matching the federal minimum. Source: MN DVS CDL Manual, Commercial Learner Permit.","handbook":"","hbref":""},{"q":"How long is a Minnesota Commercial Learner Permit (CLP) valid, and what is the maximum total period it may remain valid through renewal?","options":["90 days, renewable up to 6 months total","180 days, renewable provided it is not valid more than one year from initial issuance","1 year, non-renewable","2 years, renewable once"],"answer":1,"explanation":"The Minnesota CDL Manual states CLPs are valid for 180 days and may be renewed provided the CLP is not valid for more than one year from the date of initial issuance. Source: MN DVS CDL Manual, Commercial Learner Permit.","handbook":"","hbref":""},{"q":"While practice driving with a Minnesota CLP, the permit holder must be accompanied by a driver who holds what?","options":["Any valid Minnesota Class D driver's license","A CDL of the same class and endorsements or higher","A CDL instructor's certificate from MnDOT","Only a HazMat-endorsed CDL"],"answer":1,"explanation":"The Minnesota CDL Manual requires the CLP holder to be accompanied by a valid licensed driver with the same class of license and endorsements or higher while practice driving. Source: MN DVS CDL Manual, Commercial Learner Permit.","handbook":"","hbref":""},{"q":"Which of the following is a permitted activity for a Minnesota CLP holder?","options":["Transporting hazardous materials with an H endorsement on the CLP","Operating a CMV with double or triple trailers","Practicing in an empty (purged) tank vehicle to obtain the tank endorsement","Carrying paying passengers to gain experience"],"answer":2,"explanation":"The Minnesota CDL Manual allows a CLP holder practicing for a tank endorsement to operate only an empty tank vehicle purged of residue; it prohibits hauling hazardous materials, pulling double/triple trailers, and carrying passengers. Source: MN DVS CDL Manual, Commercial Learner Permit restrictions.","handbook":"","hbref":""},{"q":"Which set of endorsements does Minnesota allow to be added to a Commercial Learner Permit (CLP)?","options":["Passenger (P), School bus (S), and Tank vehicle (N)","Hazardous materials (H) and Tank vehicle (N)","Doubles/Triples (T) and Passenger (P)","All six endorsements may be added to a CLP"],"answer":0,"explanation":"The Minnesota CDL Manual states the only endorsements that may be added to a CLP are Passenger (P), School bus (S), and Tank vehicle (N). Source: MN DVS CDL Manual, Endorsements (CLP note).","handbook":"","hbref":""},{"q":"Federal Entry-Level Driver Training (ELDT), required in Minnesota, must be completed through a provider listed on what, and applies to applicants on or after what date?","options":["The FMCSA Training Provider Registry, on or after Feb. 7, 2022","The National Registry of Certified Medical Examiners, on or after May 21, 2014","The TSA Approved Trainer List, on or after March 20, 2025","The MnDOT Office of Motor Carrier Services list, on or after Jan. 1, 2020"],"answer":0,"explanation":"The Minnesota CDL Manual explains ELDT requirements apply to individuals obtaining a Class A/B CDL or an S, P, or H endorsement on or after Feb. 7, 2022, with training delivered by a provider on the FMCSA Training Provider Registry. Source: MN DVS CDL Manual, ELDT / Training Provider Registry.","handbook":"","hbref":""},{"q":"Under ELDT theory training accepted in Minnesota, what minimum score must an entry-level driver achieve on the theory assessment?","options":["At least 70%","At least 75%","At least 80%","At least 90%"],"answer":2,"explanation":"The Minnesota CDL Manual describes ELDT theory training with no minimum number of hours but requiring a score of at least 80% on the assessment. Source: MN DVS CDL Manual, ELDT (Theory Training).","handbook":"","hbref":""},{"q":"When applying for a Minnesota CLP or CDL, applicants must self-certify their medical status. Which document set must a non-exempt applicant provide along with the self-certification form?","options":["A valid medical examiner's certificate from a certified examiner on the National Registry","Only a doctor's note from any licensed physician","A TSA security threat assessment letter","An MnDOT intrastate waiver in every case"],"answer":0,"explanation":"The Minnesota CDL Manual requires CDL/CLP applicants to complete the Commercial Driver License Medical Self-Certification Form and, if subject to medical requirements, submit a valid medical examiner's certificate from an examiner listed on the National Registry of Certified Medical Examiners. Source: MN DVS CDL Manual, Medical Self-Certification.","handbook":"","hbref":""},{"q":"Under Minnesota law, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.02 percent","0.04 percent","0.08 percent","0.10 percent"],"answer":1,"explanation":"Minnesota's CDL Manual (Section 1.3.2) states it is illegal to operate a CMV with a BAC of 0.04 percent or more, half the 0.08 limit for non-commercial drivers. Source: Minnesota DVS Commercial Driver's License Manual, Sec. 1.3.2; Minn. Stat. 169A.20.","handbook":"","hbref":""},{"q":"A CMV driver in Minnesota is tested and shows a detectable amount of alcohol that is below 0.04 percent. What happens?","options":["No action is taken because the level is under the limit","The driver is placed out of service for 24 hours","The driver loses the CDL for 60 days","The driver loses the CDL for one year"],"answer":1,"explanation":"Minnesota follows the rule that any detectable alcohol below 0.04 percent results in a 24-hour out-of-service order, while 0.04 or higher is a one-year disqualification. Source: Minnesota DVS CDL Manual, Sec. 1.3.2; Minn. Stat. 169A.20.","handbook":"","hbref":""},{"q":"By driving a CMV on public roads in Minnesota, a driver has automatically consented to a test of blood, breath, or urine. What is this rule called?","options":["The implied consent law","The presumed waiver rule","The reasonable suspicion rule","The mandatory testing act"],"answer":0,"explanation":"Minnesota's CDL Manual explains that operating a CMV on public roads constitutes automatic consent to chemical testing under the Implied Consent Law. Source: Minnesota DVS CDL Manual, Implied Consent Law section; Minn. Stat. 169A.51.","handbook":"","hbref":""},{"q":"In Minnesota, what is the minimum disqualification period for a CDL holder's FIRST major offense (such as driving a CMV with a BAC of 0.04 or more) when NOT transporting placarded hazardous materials?","options":["60 days","90 days","One year","Three years"],"answer":2,"explanation":"Minnesota's CDL Manual states a driver loses the CDL for at least one year for a first major offense such as a 0.04+ BAC, DUI, refusal, leaving an accident scene, or using a CMV in a felony. Source: Minnesota DVS CDL Manual, Commercial License Disqualifications / Sec. 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a CDL holder's first disqualifying major offense occurs while operating a CMV that is placarded for hazardous materials, the minimum disqualification period increases to:","options":["One year","Two years","Three years","Five years"],"answer":2,"explanation":"Minnesota's CDL Manual states that if a first disqualifying offense occurs while operating a CMV placarded for hazardous materials, the driver loses the CDL for at least three years instead of one. Source: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period in Minnesota for a CDL holder's SECOND major (disqualifying) offense?","options":["Three years","Ten years","For life","Five years"],"answer":2,"explanation":"Minnesota's CDL Manual states that a second disqualifying offense results in losing CDL privileges for life (reinstatement may be requested after 10 years in limited circumstances). Source: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Minnesota CMV driver is lawfully asked to take a chemical test and refuses. What is the consequence for the CDL?","options":["A warning with no disqualification","Disqualification for 60 days","Disqualification for one year","Disqualification for 90 days"],"answer":2,"explanation":"Minnesota's CDL Manual states that refusing to submit to a chemical test disqualifies a driver from operating a CMV for one year, and the driver's license is also revoked for one year. Refusal is treated as a major offense. Source: Minnesota DVS CDL Manual, Implied Consent Law / Sec. 1.3.2.","handbook":"","hbref":""},{"q":"In Minnesota, using a CMV to commit a felony involving controlled substances (such as drug distribution) results in what CDL penalty?","options":["A one-year disqualification","A three-year disqualification","A lifetime disqualification with no reinstatement","A 120-day disqualification"],"answer":2,"explanation":"Minnesota's CDL Manual states a driver loses the CDL for life if a CMV is used to commit a felony involving controlled substances; this lifetime ban is not subject to the usual 10-year reinstatement. Source: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a three-year period (while operating a CMV) trigger a 60-day CDL disqualification in Minnesota?","options":["One violation","Two violations","Three violations","Four violations"],"answer":1,"explanation":"Minnesota's CDL Manual (Sec. 1.3.3) states two serious traffic violations within a three-year period result in at least a 60-day disqualification. Source: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Minnesota, three serious traffic violations committed in a CMV within a three-year period result in a CDL disqualification of at least:","options":["60 days","90 days","120 days","One year"],"answer":2,"explanation":"Minnesota's CDL Manual (Sec. 1.3.3) states that three or more serious traffic violations within a three-year period result in at least a 120-day disqualification. Source: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"According to the Minnesota CDL Manual, speeding how far above the posted limit qualifies as a 'serious traffic violation'?","options":["10 mph or more over the limit","15 mph or more over the limit","20 mph or more over the limit","25 mph or more over the limit"],"answer":1,"explanation":"Minnesota's CDL Manual (Sec. 1.3.3) defines excessive speeding as 15 mph or more above the posted limit as a serious traffic violation. Source: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.5.","handbook":"","hbref":""},{"q":"Which of the following is NOT listed as a serious traffic violation in the Minnesota CDL Manual?","options":["Following a vehicle too closely","Improper or erratic lane changes","Reckless driving","Parking in a no-parking zone"],"answer":3,"explanation":"Minnesota's CDL Manual (Sec. 1.3.3) lists serious violations as excessive speeding (15+ mph over), reckless driving, improper or erratic lane changes, and following too closely, among others; a parking violation is expressly excluded. Source: Minnesota DVS CDL Manual, Sec. 1.3.3.","handbook":"","hbref":""},{"q":"In Minnesota, what is the minimum CDL disqualification for a driver's FIRST violation of an out-of-service order?","options":["30 days","60 days","90 days","One year"],"answer":2,"explanation":"Minnesota's CDL Manual (Sec. 1.3.4) states a driver loses the CDL for at least 90 days for a first out-of-service order violation. Source: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Minnesota rules, two violations of an out-of-service order within a ten-year period result in a CDL disqualification of at least:","options":["90 days","One year","Three years","120 days"],"answer":1,"explanation":"Minnesota's CDL Manual (Sec. 1.3.4) states that two out-of-service order violations within a ten-year period result in at least a one-year disqualification. Source: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Three or more violations of an out-of-service order within a ten-year period result in a Minnesota CDL disqualification of at least:","options":["One year","Two years","Three years","Five years"],"answer":2,"explanation":"Minnesota's CDL Manual (Sec. 1.3.4) states that three or more out-of-service order violations within a ten-year period result in at least a three-year disqualification. Source: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Minnesota, a FIRST railroad-highway grade crossing violation results in a CDL disqualification of at least:","options":["30 days","60 days","90 days","120 days"],"answer":1,"explanation":"Minnesota's CDL Manual (Sec. 1.3.5) states that a first railroad-highway grade crossing violation results in at least a 60-day disqualification. Source: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Minnesota rules, a THIRD railroad-highway grade crossing violation within a three-year period results in a CDL disqualification of at least:","options":["120 days","180 days","One year","Three years"],"answer":2,"explanation":"Minnesota's CDL Manual (Sec. 1.3.5) provides 60 days for the first, 120 days for a second within three years, and at least one year for a third within a three-year period. Source: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many convictions for using a hand-held mobile phone while operating a CMV must a Minnesota driver have before the CDL is disqualified?","options":["One conviction","Two or more convictions","Three or more convictions","Five or more convictions"],"answer":1,"explanation":"Minnesota's CDL Manual states a CDL is disqualified after two or more convictions of a state law on hand-held mobile phone use while operating a CMV (60 days for the second within 3 years, 120 days for three or more). Source: Minnesota DVS CDL Manual, Sec. 2.9.4; Minn. Stat. 169.475.","handbook":"","hbref":""},{"q":"Beyond CDL disqualification, what is the maximum civil penalty a Minnesota CMV driver may face for each hand-held phone or texting violation while driving?","options":["Up to $500","Up to $1,000","Up to $2,750","Up to $11,000"],"answer":2,"explanation":"Minnesota's CDL Manual states the first and each subsequent hand-held phone or texting violation is subject to civil penalties on the driver up to $2,750 (employers who allow or require it face penalties up to $11,000). Source: Minnesota DVS CDL Manual, Sec. 2.9.4 and 2.9.5.","handbook":"","hbref":""},{"q":"A Minnesota CDL holder is found driving a non-commercial (personal) vehicle with a BAC of 0.08 percent or more. What is the effect on the CDL?","options":["No effect, since it was not a CMV","Disqualified from driving CMVs for at least one year","Disqualified for 60 days","Disqualified for 90 days"],"answer":1,"explanation":"Minnesota's CDL Manual states that a BAC of 0.08 percent or more in a non-commercial vehicle revokes Class D privileges and disqualifies the driver from operating CMVs for at least one year. Source: Minnesota DVS CDL Manual, Revocation of Class D Privileges and Disqualification of CDL Privileges; Minn. Stat. 171.165.","handbook":"","hbref":""},{"q":"When approaching a railroad grade crossing in Minnesota, a driver who is required to stop (such as a bus carrying passengers) must stop the vehicle within what distance of the nearest rail?","options":["At least 15 feet but no more than 50 feet","At least 10 feet but no more than 25 feet","At least 25 feet but no more than 75 feet","At least 5 feet but no more than 15 feet"],"answer":0,"explanation":"Minnesota's CDL manual and Minn. Stat. 169.28 require vehicles that must stop at railroad grade crossings to stop not less than 15 feet and not more than 50 feet from the nearest rail. Source: Minnesota CDL Manual (Railroad Grade Crossing); Minn. Stat. 169.28.","handbook":"","hbref":""},{"q":"Under Minnesota's CDL rules, which group of vehicles must stop at ALL railroad grade crossings whether or not a train is approaching?","options":["Buses carrying passengers, school buses (loaded or not), and placarded vehicles","Only vehicles over 26,001 pounds gross weight","Only triple-trailer combinations and tankers over 1,000 gallons","Any commercial vehicle pulling a trailer of any kind"],"answer":0,"explanation":"The Minnesota CDL manual lists the vehicles required to stop at every railroad grade crossing as buses carrying passengers, school buses (whether carrying passengers or not), and placarded vehicles. Source: Minnesota CDL Manual (Railroad Grade Crossing); 49 CFR 392.10 as adopted in Minnesota.","handbook":"","hbref":""},{"q":"On a Minnesota two-lane road carrying traffic in both directions, when a school bus is stopped with its stop arm extended and red lights flashing, an approaching driver must stop at least how far from the bus?","options":["At least 20 feet away","At least 10 feet away","At least 30 feet away","At least 50 feet away"],"answer":0,"explanation":"Minn. Stat. 169.444, subd. 1 and the Minnesota CDL manual require a driver approaching a stopped school bus displaying an extended stop-signal arm and flashing red lights to stop at least 20 feet away and remain stopped until the arm is retracted and the lights stop flashing. Source: Minn. Stat. 169.444; Minnesota CDL Manual.","handbook":"","hbref":""},{"q":"Under Minnesota law, on which type of roadway is a driver NOT required to stop for a school bus that is loading or unloading on the opposite side?","options":["A roadway with separated roadways divided by a physical barrier, raised median, or depressed median","Any road with two or more lanes in each direction","Any road with a painted centerline marking the opposing lanes","Any road with a center two-way left-turn lane"],"answer":0,"explanation":"Minn. Stat. 169.444, subd. 4 exempts a driver from stopping only when the bus is on a different roadway and the roadways are 'separated,' meaning divided by a physical barrier, raised median, or depressed median. A painted line or a center turn lane is not a separated roadway. Source: Minn. Stat. 169.444, subd. 4.","handbook":"","hbref":""},{"q":"What is the maximum statutory speed limit on a rural Minnesota interstate highway outside any urbanized area?","options":["70 mph","65 mph","75 mph","60 mph"],"answer":0,"explanation":"Minn. Stat. 169.14 sets the speed limit at 70 mph on interstate highways outside the limits of any urbanized area, and 65 mph inside an urbanized area. Source: Minn. Stat. 169.14, subd. 2; MnDOT.","handbook":"","hbref":""},{"q":"In Minnesota, what speed limit applies to a loaded semi-truck on a rural interstate highway compared with a passenger car?","options":["The same limit as cars; Minnesota sets no separate lower truck speed limit","10 mph below the posted car limit","A flat 60 mph statewide truck maximum","5 mph below the posted car limit"],"answer":0,"explanation":"Minnesota does not set a separate, lower speed limit for trucks or commercial vehicles. The posted statutory limits in Minn. Stat. 169.14 apply equally to all vehicles. Source: Minn. Stat. 169.14; MnDOT speed limit guidance.","handbook":"","hbref":""},{"q":"Under Minnesota's 'Ted Foss' Move Over law, on a road with exactly two lanes in the same direction, what must a driver do when approaching a stopped authorized vehicle displaying flashing or warning lights?","options":["Safely move to the lane farthest away from the authorized vehicle if possible","Come to a complete stop until the authorized vehicle leaves","Sound the horn and maintain the current lane and speed","Move into the lane nearest the authorized vehicle to pass closely and slowly"],"answer":0,"explanation":"Minn. Stat. 169.18, subd. 11(b) requires a driver to safely move to the lane farthest away from a stopped authorized vehicle with activated lights when there are two lanes in the same direction. Source: Minn. Stat. 169.18, subd. 11; Minnesota DPS (Ted Foss Move Over law).","handbook":"","hbref":""},{"q":"Under Minnesota's Move Over law, on a road with MORE than two lanes in the same direction, what is the driver required to do when passing a stopped authorized vehicle with its lights activated?","options":["Leave a full lane vacant between the driver and the lane the authorized vehicle occupies, if safe","Stop completely in the right-most lane","Reduce speed to exactly half the posted limit but stay in the same lane","Move into the lane immediately next to the authorized vehicle"],"answer":0,"explanation":"Minn. Stat. 169.18, subd. 11(c) requires a driver on a road with more than two lanes in the same direction to safely move so as to leave a full lane vacant between the driver and any lane the authorized vehicle occupies. Source: Minn. Stat. 169.18, subd. 11.","handbook":"","hbref":""},{"q":"Which of the following is included in Minnesota's definition of an 'authorized vehicle' protected by the Move Over law?","options":["A tow truck, utility company vehicle, or solid waste/recycling vehicle with lights activated","Only marked law-enforcement squad cars","Only ambulances and fire apparatus","Any passenger car with its parking lights on"],"answer":0,"explanation":"Minn. Stat. 169.18, subd. 11(a) defines 'authorized vehicle' broadly to include emergency vehicles, tow trucks, freeway service patrol vehicles, road maintenance vehicles, utility company vehicles, construction vehicles, postal service vehicles, and solid waste or recycling vehicles. Source: Minn. Stat. 169.18, subd. 11(a).","handbook":"","hbref":""},{"q":"If a commercial vehicle must stop on or by a one-way or divided Minnesota highway, where must the driver place the three emergency warning devices?","options":["10 feet, 100 feet, and 200 feet toward the approaching traffic","25 feet, 100 feet, and 300 feet toward the approaching traffic","10 feet, 50 feet, and 150 feet toward the approaching traffic","15 feet, 75 feet, and 250 feet toward the approaching traffic"],"answer":0,"explanation":"The Minnesota CDL manual (and 49 CFR 392.22) require that on a one-way or divided highway the three warning devices be placed 10 feet, 100 feet, and 200 feet from the vehicle toward the approaching traffic. Source: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Within how many minutes of stopping on a road or shoulder must a Minnesota commercial driver put out the required emergency warning devices?","options":["Within 10 minutes","Within 5 minutes","Within 15 minutes","Within 30 minutes"],"answer":0,"explanation":"The Minnesota CDL manual states that if you must stop on a road or shoulder you must put out your emergency warning devices within ten minutes. Source: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On an undivided two-lane Minnesota road carrying traffic in both directions, where should a stopped commercial driver place the warning devices?","options":["Within 10 feet of the front or rear corners and 100 feet behind and ahead of the vehicle","10 feet, 100 feet, and 200 feet toward approaching traffic only","Only one device 500 feet to the rear","Within 50 feet of the vehicle on the traffic side only"],"answer":0,"explanation":"The Minnesota CDL manual specifies that on a two-lane road carrying traffic in both directions (an undivided highway), place warning devices within 10 feet of the front or rear corners to mark the vehicle and 100 feet behind and ahead of the vehicle. Source: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"How many red reflective triangles does a Minnesota commercial vehicle need as its required stopped-vehicle warning devices?","options":["Three reflective triangles (or 6 fuses or 3 liquid-burning flares)","Two reflective triangles","Four reflective triangles","One reflective triangle plus one flag"],"answer":0,"explanation":"The Minnesota CDL manual requires warning devices for parked vehicles consisting of three reflective triangles, or at least 6 fuses, or 3 liquid-burning flares. Source: Minnesota CDL Manual (Warning Devices for parked vehicles); 49 CFR 393.95.","handbook":"","hbref":""},{"q":"In Minnesota, when a truck or bus is traveling on a roadway outside a business or residence district, it may not follow another vehicle more closely than what distance?","options":["500 feet","300 feet","200 feet","100 feet"],"answer":0,"explanation":"Minn. Stat. 169.18, subd. 8(b) provides that the driver of a motor truck, a bus, or a vehicle drawing another vehicle shall not follow within 500 feet of another vehicle when traveling outside a business or residence district. Source: Minn. Stat. 169.18, subd. 8.","handbook":"","hbref":""},{"q":"A school bus driver in Minnesota must activate the four-way hazard warning lights how far before the nearest rail at a railroad crossing?","options":["At least 100 feet from the nearest rail","At least 25 feet from the nearest rail","At least 300 feet from the nearest rail","At least 50 feet from the nearest rail"],"answer":0,"explanation":"The Minnesota School Bus section of the CDL manual requires the school bus driver to turn on the four-way hazard warning lights at least 100 feet from the nearest rail, with the master switch off, and prohibits using the 8-light system at a railroad crossing. Source: Minnesota CDL Manual (School Bus Railroad Crossings).","handbook":"","hbref":""},{"q":"A Minnesota driver who fails to stop for a school bus that is displaying its extended stop arm and flashing red lights is, at minimum, guilty of what offense?","options":["A misdemeanor punishable by a fine of not less than $500","A petty misdemeanor with a maximum $50 fine","An infraction with no fine for a first offense","A felony in every case"],"answer":0,"explanation":"Under Minn. Stat. 169.444 and the Minnesota CDL manual, a driver who fails to stop for a school bus as required is guilty of a misdemeanor punishable by a fine of not less than $500, with possible license suspension. Source: Minn. Stat. 169.444; Minnesota CDL Manual.","handbook":"","hbref":""},{"q":"Passing a stopped school bus on the right-hand (passenger-door) side, or passing when a child is outside on the roadway, elevates a Minnesota driver's offense to what level?","options":["A gross misdemeanor subject to license revocation","A simple traffic citation with points only","A petty misdemeanor","A civil parking violation"],"answer":0,"explanation":"Minn. Stat. 169.444 and the Minnesota CDL manual make it a gross misdemeanor, subject to revocation, to fail to stop and either pass on the right-hand passenger-door side of the bus or pass while a school child is outside on the street, highway, or adjacent sidewalk. Source: Minn. Stat. 169.444; Minnesota CDL Manual.","handbook":"","hbref":""},{"q":"Regarding tolls, which statement best describes Minnesota's interstate and highway system for commercial drivers?","options":["Minnesota has no traditional toll roads; only optional E-ZPass MN (formerly MnPASS) express lanes exist in the Twin Cities metro","All Minnesota interstates require a toll transponder for trucks","Trucks must pay a per-axle toll on every Minnesota interstate","Minnesota operates a statewide tollway network like the Indiana Toll Road"],"answer":0,"explanation":"Minnesota has no traditional toll roads; its only tolling is the optional E-ZPass Minnesota (formerly MnPASS) express lanes on I-394, I-35W, and I-35E in the Twin Cities metro, with free general-purpose lanes always available alongside. Source: MnDOT; Minnesota DPS.","handbook":"","hbref":""},{"q":"A Minnesota CDL holder convicted of a single railroad grade crossing violation while operating a commercial vehicle is disqualified from operating a CMV for at least how long?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"The Minnesota CDL manual states a driver is disqualified for 60 days for a first railroad grade crossing violation, 120 days for two in any three-year period, and one year for three or more in any three-year period. Source: Minnesota CDL Manual (Railroad Grade Crossing Violation); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"On a multi-lane Minnesota highway, what does the state's lane-use rule require of a commercial vehicle traveling slower than the normal speed of traffic?","options":["Drive in the right-hand lane or as close as practicable to the right-hand edge, except when passing or turning left","Stay in the center lane at all times so faster traffic can use both outer lanes","Occupy the left lane to keep the right lane open for merging traffic","Use the shoulder whenever traffic is heavier than usual"],"answer":0,"explanation":"Minn. Stat. 169.18, subd. 10 requires a vehicle proceeding slower than normal traffic to be driven in the right-hand lane then available, or as close as practicable to the right-hand curb or edge, except when overtaking and passing, preparing for a left turn, or where a lane is designated for a specific use. Source: Minn. Stat. 169.18, subd. 10.","handbook":"","hbref":""},{"q":"Which Minnesota agency issues commercial driver's licenses and administers CDL testing in the state?","options":["The Department of Public Safety, Driver and Vehicle Services (DVS)","The Minnesota State Patrol Commercial Vehicle Section","The Federal Motor Carrier Safety Administration (FMCSA)","The Minnesota Department of Transportation (MnDOT)"],"answer":0,"explanation":"CDLs in Minnesota are issued by the Department of Public Safety through its Driver and Vehicle Services (DVS) division, which also administers the knowledge and skills tests. MnDOT handles intrastate medical waivers and oversize/overweight permits, not licensing. Source: Minnesota CDL Manual, Part A (DVS, Department of Public Safety).","handbook":"","hbref":""},{"q":"In Minnesota, every CDL applicant must first obtain which credential that allows supervised practice driving in a commercial vehicle?","options":["A commercial learner permit (CLP)","A temporary skills-test certificate","An instructional CDL waiver","A provisional commercial endorsement"],"answer":0,"explanation":"Minnesota requires all CDL applicants to first obtain a commercial learner permit (CLP), which allows practice driving only with another properly licensed driver of the same class or higher in the vehicle. Source: Minnesota CDL Manual, Part A, Commercial Driver's License Tests.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Minnesota commercial learner permit (CLP)?","options":["18 years old","17 years old","21 years old","16 years old"],"answer":0,"explanation":"You must be at least 18 years old and hold a valid Minnesota driver's license to obtain a CLP. You must be 21 to drive a commercial vehicle in interstate commerce. Source: Minnesota CDL Manual, Part A, Commercial Driver's License Tests.","handbook":"","hbref":""},{"q":"After applying for a Minnesota CLP, how long must the applicant hold it before being allowed to take the CDL skills (road) test?","options":["14 calendar days","10 calendar days","7 calendar days","30 calendar days"],"answer":0,"explanation":"Minnesota requires the CLP to be held for 14 calendar days from the date of application before the applicant may take the CDL skills test. Source: Minnesota CDL Manual, Part A, Commercial Driver's License Tests.","handbook":"","hbref":""},{"q":"How long is a Minnesota commercial learner permit (CLP) valid from its date of issuance?","options":["1 year","2 years","90 days","180 days"],"answer":3,"explanation":"A Minnesota CLP is valid for 180 days. It may be renewed, but it cannot be valid for more than one year from the date of initial issuance. Source: Minnesota CDL Manual, Part A, Commercial Driver's License Tests.","handbook":"","hbref":""},{"q":"The Minnesota CDL skills test is divided into which three phases?","options":["Air brake check, coupling/uncoupling, and highway driving","Written exam, vision screening, and road test","Vehicle inspection, basic control skills, and the road test","Pre-trip paperwork, range backing, and a defensive-driving quiz"],"answer":2,"explanation":"The Minnesota CDL skills test has three phases: (1) the vehicle inspection (pre-trip), (2) the basic control skills test, and (3) the road test. All three must be taken in the type of vehicle for which you wish to be licensed. Source: Minnesota CDL Manual, Part A, Skills Tests.","handbook":"","hbref":""},{"q":"During the Minnesota CDL vehicle inspection phase, what must the applicant do to receive credit for each item?","options":["Complete the inspection silently within a fixed time limit","Replace any worn parts found during the check","Get under the vehicle and verify all fluid levels","Point out each item and explain what problems to look for on a cold vehicle"],"answer":3,"explanation":"On the vehicle inspection, the applicant must point out each item to the examiner and explain what problems to look for on a cold vehicle, mentioning the main points to earn credit. You are not required to get under the vehicle or check fluids. Source: Minnesota CDL Manual, Part A, Vehicle Inspection.","handbook":"","hbref":""},{"q":"How many times per day may a Minnesota CDL applicant attempt each individual knowledge test?","options":["Three times per day","Twice per day","Unlimited attempts per day","Once per day"],"answer":3,"explanation":"The CDL knowledge test is offered in English on paper or computer, and an applicant may attempt each knowledge test only once per day. Source: Minnesota CDL Manual, Part A, Knowledge Tests.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) became mandatory for first-time Minnesota Class A/Class B applicants and certain endorsements on which date?","options":["May 21, 2014","November 1, 2021","February 7, 2022","January 4, 2020"],"answer":2,"explanation":"ELDT requirements apply to individuals obtaining a Class A or B CDL (or an S, P, or H endorsement) on or after Feb. 7, 2022. An applicant whose valid CLP was issued before that date is exempt if they obtain the CDL before the CLP expires. Source: Minnesota CDL Manual, ELDT (FMCSA Training Provider Registry).","handbook":"","hbref":""},{"q":"Under the federal ELDT rule applied in Minnesota, what is required to pass the theory (classroom) portion of training?","options":["Scoring at least 70% on the theory assessment","Scoring at least 80% on the theory assessment","Passing a behind-the-wheel simulator evaluation","Completing a minimum of 30 classroom hours"],"answer":1,"explanation":"ELDT theory training has no minimum number of hours, but the trainee must score at least 80% on the theory assessment. Behind-the-wheel training has no minimum hours and is judged on proficiency by the provider. Source: Minnesota CDL Manual, ELDT (FMCSA Training Provider Registry).","handbook":"","hbref":""},{"q":"Before an entry-level driver can take the behind-the-wheel (BTW) portion of ELDT in Minnesota, what must they already have?","options":["A DOT medical examiner's certificate only","A commercial learner permit (CLP)","A full unrestricted CDL","A passing score on the CDL road test"],"answer":1,"explanation":"The behind-the-wheel portion of ELDT cannot be taken before the applicant obtains a CLP, and it must be completed within one year of the classroom (theory) training. Source: Minnesota CDL Manual / DPS DVS CLP page.","handbook":"","hbref":""},{"q":"On the Minnesota self-certification form, which category requires a driver who operates in non-exempt INTERSTATE commerce to also provide a current medical examiner's certificate?","options":["Category 4 - Exempt intrastate","Category 1 - Non-exempt interstate (subject to 49 CFR part 391)","Category 2 - Exempt interstate","Category 3 - Non-exempt intrastate (subject to Minnesota Statutes chapter 221)"],"answer":1,"explanation":"Category 1, non-exempt interstate, certifies the driver is subject to and meets the federal DOT medical requirements of 49 CFR part 391 and must provide a current medical examiner's certificate and any waivers. Source: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS).","handbook":"","hbref":""},{"q":"Which Minnesota self-certification category covers a NON-EXEMPT INTRASTATE driver who is subject to state medical examination requirements?","options":["Category 4 - Exempt intrastate","Category 2 - Exempt interstate","Category 3 - Non-exempt intrastate, under Minnesota Statutes chapter 221","Category 1 - Non-exempt interstate, under 49 CFR part 391"],"answer":2,"explanation":"Category 3, non-exempt intrastate, applies to drivers subject to the state medical examination requirements of Minnesota Statutes, chapter 221, who must also provide a current medical examiner's certificate and any waivers. Source: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS).","handbook":"","hbref":""},{"q":"How many self-certification categories does the Minnesota Commercial Driver License Medical Self-Certification Form list?","options":["Two categories","Four categories","Three categories","Five categories"],"answer":1,"explanation":"The Minnesota self-certification form lists four categories: non-exempt interstate, exempt interstate, non-exempt intrastate, and exempt intrastate. Two of the four (the non-exempt categories) require a medical examiner's certificate. Source: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS).","handbook":"","hbref":""},{"q":"Where does a Minnesota CDL holder submit the completed self-certification form and valid medical examiner's certificate?","options":["The Department of Public Safety / Driver and Vehicle Services (DVS)","MnDOT's Office of Motor Carrier Services","The Federal Motor Carrier Safety Administration (FMCSA)","The National Registry of Certified Medical Examiners"],"answer":0,"explanation":"Drivers submit the self-certification form and valid medical examiner's certificate to the Department of Public Safety / DVS CDL Unit (online at drive.mn.gov, by mail, fax, or in person at a driver exam station). The certificate information is then noted on the driving record. Source: Minnesota CDL Manual, Medical Requirements; DPS DVS Self-Certification FAQs.","handbook":"","hbref":""},{"q":"A Minnesota DOT medical examiner's certificate is generally valid for what maximum period?","options":["Five years","Three years","Up to two years","One year"],"answer":2,"explanation":"A medical examiner's certificate can be valid for up to two years, though the examiner may issue it for a shorter period based on the driver's medical history. Source: Minnesota CDL Manual, Medical Certificate Renewal; DPS DVS Self-Certification FAQs.","handbook":"","hbref":""},{"q":"How many days before a medical examiner's certificate expires does the Minnesota Department of Public Safety send a notice to the driver?","options":["45 days prior","90 days prior","60 days prior","30 days prior"],"answer":2,"explanation":"The Department of Public Safety sends a notice to the driver's last known address 60 days prior to the expiration date of the medical examiner's certificate or waiver on file. Source: Minnesota CDL Manual, Medical Certificate Renewal.","handbook":"","hbref":""},{"q":"If a Minnesota CDL is downgraded for failing to submit a required medical examiner's certificate, within what period may the driver reinstate the CDL simply by submitting a valid certificate?","options":["Within two years","Within 6 months","Within 30 days","Within one year"],"answer":3,"explanation":"A driver may reinstate a downgraded CDL and endorsements within one year by submitting a valid medical examiner's certificate with the self-certification form. If downgraded or surrendered for more than one year, the driver must retake the applicable knowledge and road tests. Source: Minnesota CDL Manual, Medical Certificate Renewal; DPS DVS FAQs.","handbook":"","hbref":""},{"q":"How long is a Minnesota commercial driver's license valid before it must be renewed?","options":["Two years","Four years","Five years","Eight years"],"answer":1,"explanation":"A Minnesota CDL (Class A, B, or C) is valid for four years and then must be renewed, the same cycle as a regular Class D license. Source: DPS DVS CDL Class pages (Department of Public Safety).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная допустимая ширина коммерческого транспортного средства на автодорогах Миннесоты, без учёта зеркал и устройств крепления груза?","options":["8 футов 0 дюймов (96 inches)","8 футов 6 дюймов (102 inches)","9 футов 0 дюймов (108 inches)","8 футов 4 дюйма (100 inches)"],"explanation":"Закон Миннесоты (Minn. Stat. 169.80) устанавливает максимальную общую наружную ширину в 102 inches (8 футов 6 дюймов). Это соответствует федеральному стандарту. Источник: Minn. Stat. 169.80; MnDOT CVO."},"1":{"q":"Какова максимальная допустимая высота транспортного средства, гружёного или порожнего, на автодорогах Миннесоты?","options":["13 футов 0 дюймов","14 футов 0 дюймов","13 футов 6 дюймов","14 футов 6 дюймов"],"explanation":"Закон Миннесоты (Minn. Stat. 169.81) гласит, что ни одно транспортное средство, порожнее или с грузом, не должно превышать высоту 13 футов 6 дюймов. Источник: Minn. Stat. 169.81; Minnesota CDL Manual."},"2":{"q":"Какова максимальная полная масса транспортного средства или состава транспортных средств на улицах и автодорогах Миннесоты без специального разрешения?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"Закон Миннесоты (Minn. Stat. 169.824) ограничивает полную массу транспортного средства величиной 80,000 pounds на всех улицах и автодорогах, что соответствует федеральному пределу. Источник: Minn. Stat. 169.824; MnDOT."},"3":{"q":"Согласно закону Миннесоты, какова максимально допустимая нагрузка на одиночную ось на дороге с твёрдым покрытием?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Закон Миннесоты (Minn. Stat. 169.823) ограничивает нагрузку на одиночную ось величиной 20,000 pounds на улицах и автодорогах с твёрдым покрытием. Источник: Minn. Stat. 169.823; MnDOT CVO Truck Book."},"4":{"q":"Какова максимально допустимая нагрузка на группу спаренных осей (тандем) в Миннесоте?","options":["32,000 pounds","36,000 pounds","34,000 pounds","40,000 pounds"],"explanation":"Миннесота следует федеральному пределу для тандемной оси в 34,000 pounds, закреплённому в таблице осевых нагрузок Minn. Stat. 169.824. Источник: Minn. Stat. 169.824; Minnesota CDL Manual."},"5":{"q":"Какова максимальная общая длина одиночного (несочленённого) транспортного средства на автодороге Миннесоты, включая груз и бамперы?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"Закон Миннесоты (Minn. Stat. 169.81) ограничивает длину одиночного транспортного средства величиной 45 feet в целом, включая груз, передний и задний бамперы (автокраны могут достигать 48 feet). Источник: Minn. Stat. 169.81."},"6":{"q":"Какова максимальная общая длина двухзвенного состава (тягач с полуприцепом) на автодорогах Миннесоты без специального разрешения?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"Закон Миннесоты (Minn. Stat. 169.81) устанавливает максимальную длину двухзвенного состава транспортных средств в 75 feet. Источник: Minn. Stat. 169.81; MnDOT CVO."},"7":{"q":"Полуприцеп в составе тягача с полуприцепом в Миннесоте, как правило, не может превышать какую длину?","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"Закон Миннесоты (Minn. Stat. 169.81) предусматривает, что полуприцеп, как правило, не может превышать 48 feet, хотя допускается длина до 53 feet, когда расстояние от шкворня до задней оси не превышает 43 feet. Источник: Minn. Stat. 169.81."},"8":{"q":"Какую формулу использует Миннесота для определения максимально допустимой нагрузки на группу последовательных осей в зависимости от расстояния между осями и их количества?","options":["Федеральная мостовая формула (Federal Bridge Formula)","Формула полной массы автопоезда (Gross Combination Rating)","Тоннажный индекс Миннесоты (Minnesota Tonnage Index)","Формула эквивалентности осевой нагрузки (Axle Load Equivalency)"],"explanation":"Таблица весов для групп осей Миннесоты в Minn. Stat. 169.824 реализует Федеральную мостовую формулу (Federal Bridge Formula), допуская больший вес по мере увеличения числа осей и расстояния между ними. Источник: Minn. Stat. 169.824; Minnesota CDL Manual."},"9":{"q":"Когда требуется разрешение MnDOT на негабарит/перегруз (OSOW) для перемещения груза по автодороге Миннесоты?","options":["Только когда груз превышает 100,000 pounds","Когда транспортное средство или груз превышает любой законный предел по габаритам или весу","Только для грузов шире 10 feet","Только на межштатных автомагистралях (Interstate)"],"explanation":"Разрешение MnDOT OSOW требуется всякий раз, когда транспортное средство или груз превышает законный предел по габаритам или весу и будет двигаться по автодороге Миннесоты или пересекать её. Источник: Minn. Stat. 169.86; MnDOT CVO Oversize/Overweight Permits."},"10":{"q":"Сверх законной ширины в 102 inches, насколько далеко могут законно выступать с каждой стороны зеркала заднего вида или устройства крепления груза, не являющиеся неотъемлемой частью транспортного средства, в Миннесоте?","options":["До 3 inches с каждой стороны","До 6 inches с каждой стороны","Они вообще не могут выступать","До 12 inches с каждой стороны"],"explanation":"Закон Миннесоты (Minn. Stat. 169.80) допускает, чтобы зеркала или устройства крепления груза, не являющиеся неотъемлемой частью транспортного средства, выступали до 3 inches за пределы ширины в 102 inches с каждой стороны. Источник: Minn. Stat. 169.80."},"11":{"q":"Во время зимнего повышения весовых лимитов, объявленного комиссаром, насколько могут быть повышены сезонные пределы полной массы и осевой нагрузки в Миннесоте на подходящих дорогах?","options":["5 percent","10 percent","15 percent","20 percent"],"explanation":"Закон Миннесоты (Minn. Stat. 169.826) уполномочивает комиссара повышать весовые лимиты на 10 percent в зимний период (период промёрзших дорог), установленный для каждой зоны. Источник: Minn. Stat. 169.826; MnDOT."},"12":{"q":"Какой высоты может достигать двухэтажный автобус, эксплуатируемый по годовому разрешению в Миннесоте, сверх стандартного предела в 13 футов 6 дюймов?","options":["13 футов 9 дюймов","14 футов 0 дюймов","14 футов 3 дюйма","15 футов 0 дюймов"],"explanation":"Закон Миннесоты (Minn. Stat. 169.81) допускает, чтобы двухэтажный автобус достигал высоты 14 футов 3 дюйма при эксплуатации по годовому разрешению. Источник: Minn. Stat. 169.81."},"13":{"q":"Повышение веса на 10 percent в период сбора урожая в Миннесоте согласно Minn. Stat. 169.826 применяется к перевозке каких необработанных сельскохозяйственных продуктов от поля до первого пункта разгрузки?","options":["Кукуруза, соя и пшеница","Сахарная свёкла, морковь и картофель","Сено, солома и силос","Яблоки, виноград и лук"],"explanation":"Закон Миннесоты (Minn. Stat. 169.826, subd. 1a) предоставляет повышение на 10 percent в период сбора урожая для перевозки сахарной свёклы, моркови и картофеля от поля сбора урожая до первого пункта разгрузки, до 30 ноября, при наличии разрешения. Источник: Minn. Stat. 169.826."},"14":{"q":"Как чаще всего получают от MnDOT разрешение на негабарит/перегруз и путевой журнал?","options":["Посетив лично офис шерифа округа","Онлайн через веб-аккаунт MnDOT CVO после оплаты","Отправив бумажную форму по почте в законодательное собрание","Автоматически выдаётся вместе с CDL"],"explanation":"MnDOT выдаёт годовые, сезонные или разовые разрешения OSOW онлайн; перевозчик создаёт веб-аккаунт CVO и оплачивает до выдачи разрешения. Источник: MnDOT CVO Oversize/Overweight Permits."},"15":{"q":"Удлинённый полуприцеп в Миннесоте может достигать 53 feet только если расстояние от шкворня до центра самой задней оси не превышает какую величину?","options":["40 feet","41 feet","43 feet","46 feet"],"explanation":"Закон Миннесоты (Minn. Stat. 169.81) допускает полуприцеп длиной до 53 feet при условии, что расстояние от шкворня до центра задней оси не превышает 43 feet. Источник: Minn. Stat. 169.81."},"16":{"q":"Шестиосные транспортные средства, перевозящие исключительно живой скот, могут эксплуатироваться при полной массе до скольки на магистральных дорогах Миннесоты (кроме межштатных) при наличии разрешения?","options":["80,000 pounds","84,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"Закон Миннесоты (Minn. Stat. 169.8261/169.824) допускает разрешённую полную массу до 88,000 pounds для транспортных средств с шестью или более осями, перевозящих исключительно живой скот, на магистральных дорогах, кроме межштатных. Источник: Minn. Stat. 169.824; MnDOT CVO."},"17":{"q":"В Миннесоте какой класс CDL требуется для управления составом транспортных средств с полной массой автопоезда более 26,000 pounds, где буксируемое звено имеет GVWR более 10,000 pounds?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Minnesota CDL Manual (Part A) определяет Класс A как любое транспортное средство, буксирующее звено с GVWR более 10,000 pounds при полной массе автопоезда (грузовик плюс прицеп) более 26,000 pounds. Источник: MN DVS Commercial Driver's License Manual, Part A."},"18":{"q":"Согласно правилам Миннесоты, одиночное транспортное средство с GVWR более 26,000 pounds (ничего не буксирующее или буксирующее звено в 10,000 pounds или менее) требует какого класса CDL?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"Minnesota CDL Manual определяет Класс B как одиночное транспортное средство с GVWR более 26,000 pounds; он также охватывает буксировку звена, не превышающего 10,000 pounds. Источник: MN DVS CDL Manual, Part A."},"19":{"q":"В Миннесоте CDL класса C применяется к одиночному транспортному средству с GVWR 26,000 pounds или менее только когда транспортное средство используется для какой цели?","options":["Любое транспортное средство, используемое по найму, независимо от груза","Перевозка опасных материалов, требующих знаков-табличек, или перевозка 16 или более пассажиров","Буксировка любого прицепа свыше 10,000 pounds","Управление любым транспортным средством за пределами Миннесоты"],"explanation":"Minnesota CDL Manual гласит, что Класс C — это одиночное транспортное средство с GVWR 26,000 pounds или менее, которое перевозит опасные материалы (с табличками), пассажиров либо является школьным автобусом, что требует соответствующего эндорсмента. Источник: MN DVS CDL Manual, Part A."},"20":{"q":"Какой эндорсмент требует Миннесота для водителя, управляющего цистерной, предназначенной для перевозки жидкостей или газов в ёмкости с индивидуальной номинальной вместимостью более 119 gallons и суммарной 1,000 gallons или более?","options":["H (опасные материалы, HazMat)","T (двойные/тройные прицепы)","N (цистерна, Tank Vehicle)","X (цистерна и HazMat)"],"explanation":"Minnesota CDL Manual определяет эндорсмент N (Tank Vehicle) для любого CMV, предназначенного для перевозки жидких или газообразных материалов в ёмкости с индивидуальной номинальной вместимостью более 119 gallons и суммарной номинальной вместимостью 1,000 gallons или более. Источник: MN DVS CDL Manual, Endorsements section."},"21":{"q":"В Миннесоте какой эндорсмент необходим для буксировки двойных или тройных прицепов, и с каким классом транспортного средства он обычно связан?","options":["Эндорсмент T, обычно для водителей Класса A","Эндорсмент N, обычно для водителей Класса B","Эндорсмент P, обычно для водителей Класса C","Эндорсмент H, обычно для водителей Класса A"],"explanation":"Minnesota CDL Manual гласит, что эндорсмент T (двойные/тройные прицепы) добавляется к правам водителей Класса A, желающих буксировать двойные или тройные прицепы, и требует специального экзамена на знания. Источник: MN DVS CDL Manual, Endorsements / Doubles and Triples."},"22":{"q":"Какие два эндорсмента Миннесота объединяет в единый эндорсмент «X»?","options":["Пассажирский и школьный автобус","Цистерна и опасные материалы","Двойные/тройные прицепы и цистерна","Опасные материалы и пассажирский"],"explanation":"Minnesota CDL Manual перечисляет эндорсмент X как «Tanker and Hazardous Materials» (цистерна и опасные материалы), требуемый для водителей цистерн, перевозящих опасные материалы/отходы в количествах, требующих табличек, и которые должны сдать оба экзамена на знания — по цистернам и по HazMat. Источник: MN DVS CDL Manual, Endorsements."},"23":{"q":"В Миннесоте что требуется до того, как водителю может быть выдан эндорсмент на опасные материалы (H), помимо сдачи экзамена на знания HazMat?","options":["Практический экзамен по вождению цистерны с табличками","Оценка угрозы безопасности TSA, включающая снятие отпечатков пальцев и проверку биографии","Пять лет подтверждённого опыта межштатного вождения","Отдельное разрешение MnDOT на негабарит/перегруз"],"explanation":"Minnesota CDL Manual гласит, что Управление транспортной безопасности (TSA) проводит проверку биографии (уголовные, иммиграционные записи и записи ФБР) и требует отпечатки пальцев до выдачи или продления эндорсмента HazMat. Источник: MN DVS CDL Manual, Hazardous Materials / Background Check / Fingerprints."},"24":{"q":"В Миннесоте эндорсмент на школьный автобус (S) может быть добавлен к CDL только когда водитель также имеет какой другой эндорсмент?","options":["Цистерна (N)","Двойные/тройные прицепы (T)","Пассажирский (P)","Опасные материалы (H)"],"explanation":"Миннесота требует, чтобы эндорсмент на школьный автобус (S) сопровождался пассажирским эндорсментом (P); определение Класса C в руководстве указывает «школьный автобус (с пассажирским эндорсментом)». Источник: MN DVS CDL Manual, Part A / Endorsements."},"25":{"q":"Для пассажирского эндорсмента (P) на CDL Класса B в Миннесоте практический экзамен (по вождению) должен быть сдан на автобусе с GVWR более 26,000 pounds и пассажировместимостью какой, включая водителя?","options":["Более 8","Более 10","Более 15","Более 24"],"explanation":"Minnesota CDL Manual гласит, что для пассажирского эндорсмента (или эндорсмента на школьный автобус) практический экзамен должен быть сдан на автобусе с GVWR более 26,000 pounds и пассажировместимостью более 15, включая водителя. Источник: MN DVS CDL Manual, Part A (Class B)."},"26":{"q":"Каков минимальный возраст для подачи заявления на CDL Миннесоты, ограниченный внутриштатным (в пределах Миннесоты) коммерческим вождением?","options":["16 лет","18 лет","19 лет","21 год"],"explanation":"Minnesota CDL Manual указывает минимальный возраст 18 лет для подачи заявления на внутриштатный CDL (например, одиночное транспортное средство свыше 26,000 lbs GVW или состав свыше 26,000 lbs GCW). Источник: MN DVS CDL Manual, Part A (minimum age)."},"27":{"q":"Согласно правилам Миннесоты и федеральным правилам, каков обычно минимальный возраст для управления CMV в межштатной торговле или для перевозки опасных материалов, требующих знаков-табличек?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Minnesota CDL Manual отмечает, что для транспортного средства любого размера, требующего знаков-табличек опасных материалов, в большинстве случаев необходимо быть 21 года, а межштатная эксплуатация обычно требует возраста 21 год. Источник: MN DVS CDL Manual, Part A (minimum age / interstate)."},"28":{"q":"Каков минимальный возраст для получения учебного коммерческого разрешения Миннесоты (CLP), и что уже должен иметь заявитель?","options":["16, с ученическим разрешением (learner's permit)","18, с действующими водительскими правами Миннесоты","19, с действующими водительскими правами Миннесоты","21, с действующими правами Класса D"],"explanation":"Minnesota CDL Manual гласит, что вам должно быть не менее 18 лет и вы должны иметь действующие водительские права Миннесоты для получения CLP. Источник: MN DVS CDL Manual, Commercial Learner Permit."},"29":{"q":"В Миннесоте как долго необходимо владеть учебным коммерческим разрешением (CLP), прежде чем владелец сможет сдать практический экзамен CDL (по вождению)?","options":["7 calendar days","10 calendar days","14 calendar days","30 calendar days"],"explanation":"Minnesota CDL Manual гласит, что CLP необходимо удерживать 14 calendar days, прежде чем можно будет сдавать дорожные экзамены CDL, что соответствует федеральному минимуму. Источник: MN DVS CDL Manual, Commercial Learner Permit."},"30":{"q":"Как долго действует учебное коммерческое разрешение Миннесоты (CLP), и каков максимальный общий срок, в течение которого оно может оставаться действительным с учётом продления?","options":["90 days, продлевается до 6 months в общей сложности","180 days, продлевается при условии, что оно действует не более одного года с момента первоначальной выдачи","1 year, без возможности продления","2 years, продлевается один раз"],"explanation":"Minnesota CDL Manual гласит, что CLP действуют 180 days и могут быть продлены при условии, что CLP действует не более одного года с даты первоначальной выдачи. Источник: MN DVS CDL Manual, Commercial Learner Permit."},"31":{"q":"Во время практического вождения с CLP Миннесоты владелец разрешения должен сопровождаться водителем, который имеет что?","options":["Любые действующие водительские права Класса D Миннесоты","CDL того же класса и с теми же эндорсментами или выше","Сертификат инструктора CDL от MnDOT","Только CDL с эндорсментом HazMat"],"explanation":"Minnesota CDL Manual требует, чтобы владелец CLP во время практического вождения сопровождался действующим лицензированным водителем с теми же классом прав и эндорсментами или выше. Источник: MN DVS CDL Manual, Commercial Learner Permit."},"32":{"q":"Что из перечисленного является разрешённой деятельностью для владельца CLP Миннесоты?","options":["Перевозка опасных материалов с эндорсментом H на CLP","Управление CMV с двойными или тройными прицепами","Практика на пустой (продутой) цистерне для получения эндорсмента на цистерну","Перевозка платных пассажиров для приобретения опыта"],"explanation":"Minnesota CDL Manual разрешает владельцу CLP, практикующемуся для эндорсмента на цистерну, управлять только пустой цистерной, продутой от остатков; запрещается перевозка опасных материалов, буксировка двойных/тройных прицепов и перевозка пассажиров. Источник: MN DVS CDL Manual, Commercial Learner Permit restrictions."},"33":{"q":"Какой набор эндорсментов Миннесота разрешает добавлять к учебному коммерческому разрешению (CLP)?","options":["Пассажирский (P), школьный автобус (S) и цистерна (N)","Опасные материалы (H) и цистерна (N)","Двойные/тройные прицепы (T) и пассажирский (P)","Все шесть эндорсментов могут быть добавлены к CLP"],"explanation":"Minnesota CDL Manual гласит, что единственные эндорсменты, которые могут быть добавлены к CLP, — это пассажирский (P), школьный автобус (S) и цистерна (N). Источник: MN DVS CDL Manual, Endorsements (CLP note)."},"34":{"q":"Федеральное начальное обучение водителей (ELDT), требуемое в Миннесоте, должно быть пройдено через провайдера, внесённого в какой реестр, и применяется к заявителям начиная с какой даты?","options":["Реестр провайдеров обучения FMCSA (FMCSA Training Provider Registry), начиная с Feb. 7, 2022","Национальный реестр сертифицированных медицинских экспертов, начиная с May 21, 2014","Список утверждённых инструкторов TSA, начиная с March 20, 2025","Список Управления услуг автоперевозчикам MnDOT, начиная с Jan. 1, 2020"],"explanation":"Minnesota CDL Manual поясняет, что требования ELDT применяются к лицам, получающим CDL Класса A/B или эндорсмент S, P или H начиная с Feb. 7, 2022, при этом обучение проводится провайдером, внесённым в FMCSA Training Provider Registry. Источник: MN DVS CDL Manual, ELDT / Training Provider Registry."},"35":{"q":"Согласно теоретическому обучению ELDT, принимаемому в Миннесоте, какой минимальный балл должен набрать начинающий водитель на теоретической оценке?","options":["Не менее 70%","Не менее 75%","Не менее 80%","Не менее 90%"],"explanation":"Minnesota CDL Manual описывает теоретическое обучение ELDT без минимального количества часов, но требующее балла не менее 80% на оценке. Источник: MN DVS CDL Manual, ELDT (Theory Training)."},"36":{"q":"При подаче заявления на CLP или CDL Миннесоты заявители должны самостоятельно удостоверить свой медицинский статус. Какой набор документов должен предоставить заявитель, не имеющий освобождения, вместе с формой самоудостоверения?","options":["Действующий сертификат медицинского эксперта от сертифицированного эксперта из National Registry","Только справку от любого лицензированного врача","Письмо TSA об оценке угрозы безопасности","Внутриштатный отказ MnDOT в каждом случае"],"explanation":"Minnesota CDL Manual требует, чтобы заявители на CDL/CLP заполнили форму самоудостоверения медицинского статуса коммерческого водителя (Commercial Driver License Medical Self-Certification Form) и, если на них распространяются медицинские требования, предоставили действующий сертификат медицинского эксперта от эксперта, внесённого в National Registry of Certified Medical Examiners. Источник: MN DVS CDL Manual, Medical Self-Certification."},"37":{"q":"Согласно закону Миннесоты, какова максимальная концентрация алкоголя в крови (BAC), при которой лицо может законно управлять коммерческим транспортным средством (CMV)?","options":["0.02 percent","0.04 percent","0.08 percent","0.10 percent"],"explanation":"Minnesota CDL Manual (Section 1.3.2) гласит, что управление CMV с BAC 0.04 percent или более является незаконным, что составляет половину предела 0.08 для некоммерческих водителей. Источник: Minnesota DVS Commercial Driver's License Manual, Sec. 1.3.2; Minn. Stat. 169A.20."},"38":{"q":"Водитель CMV в Миннесоте проходит тест, и он показывает обнаружимое количество алкоголя ниже 0.04 percent. Что происходит?","options":["Никаких мер не принимается, поскольку уровень ниже предела","Водитель отстраняется от работы на 24 hours","Водитель теряет CDL на 60 days","Водитель теряет CDL на один год"],"explanation":"Миннесота следует правилу, согласно которому любое обнаружимое количество алкоголя ниже 0.04 percent влечёт за собой приказ об отстранении от работы на 24 hours, тогда как 0.04 или выше влечёт дисквалификацию на один год. Источник: Minnesota DVS CDL Manual, Sec. 1.3.2; Minn. Stat. 169A.20."},"39":{"q":"Управляя CMV по дорогам общего пользования в Миннесоте, водитель автоматически даёт согласие на анализ крови, выдыхаемого воздуха или мочи. Как называется это правило?","options":["Закон о подразумеваемом согласии (implied consent law)","Правило презюмируемого отказа","Правило обоснованного подозрения","Акт об обязательном тестировании"],"explanation":"Minnesota CDL Manual поясняет, что управление CMV по дорогам общего пользования представляет собой автоматическое согласие на химическое тестирование согласно Закону о подразумеваемом согласии (Implied Consent Law). Источник: Minnesota DVS CDL Manual, Implied Consent Law section; Minn. Stat. 169A.51."},"40":{"q":"В Миннесоте каков минимальный срок дисквалификации для ПЕРВОГО серьёзного нарушения держателя CDL (например, управление CMV с BAC 0.04 или более), когда НЕ перевозятся опасные материалы со знаками-табличками?","options":["60 days","90 days","Один год","Три года"],"explanation":"Minnesota CDL Manual гласит, что водитель теряет CDL не менее чем на один год за первое серьёзное нарушение, такое как BAC 0.04+, DUI, отказ, оставление места ДТП или использование CMV в фелонии. Источник: Minnesota DVS CDL Manual, Commercial License Disqualifications / Sec. 1.3.2; 49 CFR 383.51."},"41":{"q":"Если первое дисквалифицирующее серьёзное нарушение держателя CDL происходит во время управления CMV со знаками-табличками опасных материалов, минимальный срок дисквалификации увеличивается до:","options":["Одного года","Двух лет","Трёх лет","Пяти лет"],"explanation":"Minnesota CDL Manual гласит, что если первое дисквалифицирующее нарушение происходит во время управления CMV со знаками-табличками опасных материалов, водитель теряет CDL не менее чем на три года вместо одного. Источник: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51."},"42":{"q":"Каков срок дисквалификации в Миннесоте за ВТОРОЕ серьёзное (дисквалифицирующее) нарушение держателя CDL?","options":["Три года","Десять лет","Пожизненно","Пять лет"],"explanation":"Minnesota CDL Manual гласит, что второе дисквалифицирующее нарушение влечёт пожизненную потерю привилегий CDL (восстановление может быть запрошено через 10 лет в ограниченных обстоятельствах). Источник: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51."},"43":{"q":"Водителя CMV в Миннесоте на законных основаниях просят пройти химический тест, и он отказывается. Каковы последствия для CDL?","options":["Предупреждение без дисквалификации","Дисквалификация на 60 days","Дисквалификация на один год","Дисквалификация на 90 days"],"explanation":"Minnesota CDL Manual гласит, что отказ пройти химический тест дисквалифицирует водителя от управления CMV на один год, а водительские права также аннулируются на один год. Отказ рассматривается как серьёзное нарушение. Источник: Minnesota DVS CDL Manual, Implied Consent Law / Sec. 1.3.2."},"44":{"q":"В Миннесоте использование CMV для совершения фелонии, связанной с контролируемыми веществами (например, распространение наркотиков), влечёт какое наказание для CDL?","options":["Дисквалификацию на один год","Дисквалификацию на три года","Пожизненную дисквалификацию без возможности восстановления","Дисквалификацию на 120 days"],"explanation":"Minnesota CDL Manual гласит, что водитель теряет CDL пожизненно, если CMV используется для совершения фелонии, связанной с контролируемыми веществами; этот пожизненный запрет не подпадает под обычное восстановление через 10 лет. Источник: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51."},"45":{"q":"Сколько серьёзных нарушений правил дорожного движения в течение трёхлетнего периода (при управлении CMV) влекут 60-дневную дисквалификацию CDL в Миннесоте?","options":["Одно нарушение","Два нарушения","Три нарушения","Четыре нарушения"],"explanation":"Minnesota CDL Manual (Sec. 1.3.3) гласит, что два серьёзных нарушения правил дорожного движения в течение трёхлетнего периода влекут как минимум 60-дневную дисквалификацию. Источник: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51."},"46":{"q":"В Миннесоте три серьёзных нарушения правил дорожного движения, совершённых на CMV в течение трёхлетнего периода, влекут дисквалификацию CDL как минимум на:","options":["60 days","90 days","120 days","Один год"],"explanation":"Minnesota CDL Manual (Sec. 1.3.3) гласит, что три или более серьёзных нарушений правил дорожного движения в течение трёхлетнего периода влекут как минимум 120-дневную дисквалификацию. Источник: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51."},"47":{"q":"Согласно Minnesota CDL Manual, превышение скорости на сколько выше установленного предела квалифицируется как «серьёзное нарушение правил дорожного движения»?","options":["10 mph или более выше предела","15 mph или более выше предела","20 mph или более выше предела","25 mph или более выше предела"],"explanation":"Minnesota CDL Manual (Sec. 1.3.3) определяет чрезмерное превышение скорости как 15 mph или более выше установленного предела как серьёзное нарушение правил дорожного движения. Источник: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.5."},"48":{"q":"Что из перечисленного НЕ указано как серьёзное нарушение правил дорожного движения в Minnesota CDL Manual?","options":["Слишком близкое следование за транспортным средством","Неправильная или беспорядочная смена полос","Безрассудное вождение","Парковка в зоне, где парковка запрещена"],"explanation":"Minnesota CDL Manual (Sec. 1.3.3) перечисляет в числе серьёзных нарушений чрезмерное превышение скорости (15+ mph выше), безрассудное вождение, неправильную или беспорядочную смену полос и слишком близкое следование; нарушение правил парковки прямо исключено. Источник: Minnesota DVS CDL Manual, Sec. 1.3.3."},"49":{"q":"В Миннесоте какова минимальная дисквалификация CDL за ПЕРВОЕ нарушение приказа об отстранении от работы (out-of-service order)?","options":["30 days","60 days","90 days","Один год"],"explanation":"Minnesota CDL Manual (Sec. 1.3.4) гласит, что водитель теряет CDL как минимум на 90 days за первое нарушение приказа об отстранении от работы. Источник: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51."},"50":{"q":"Согласно правилам Миннесоты, два нарушения приказа об отстранении от работы в течение десятилетнего периода влекут дисквалификацию CDL как минимум на:","options":["90 days","Один год","Три года","120 days"],"explanation":"Minnesota CDL Manual (Sec. 1.3.4) гласит, что два нарушения приказа об отстранении от работы в течение десятилетнего периода влекут как минимум одногодичную дисквалификацию. Источник: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51."},"51":{"q":"Три или более нарушений приказа об отстранении от работы в течение десятилетнего периода влекут дисквалификацию CDL в Миннесоте как минимум на:","options":["Один год","Два года","Три года","Пять лет"],"explanation":"Minnesota CDL Manual (Sec. 1.3.4) гласит, что три или более нарушений приказа об отстранении от работы в течение десятилетнего периода влекут как минимум трёхлетнюю дисквалификацию. Источник: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51."},"52":{"q":"В Миннесоте ПЕРВОЕ нарушение на железнодорожном переезде влечёт дисквалификацию CDL как минимум на:","options":["30 days","60 days","90 days","120 days"],"explanation":"Minnesota CDL Manual (Sec. 1.3.5) гласит, что первое нарушение на железнодорожном переезде влечёт как минимум 60-дневную дисквалификацию. Источник: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51."},"53":{"q":"Согласно правилам Миннесоты, ТРЕТЬЕ нарушение на железнодорожном переезде в течение трёхлетнего периода влечёт дисквалификацию CDL как минимум на:","options":["120 days","180 days","Один год","Три года"],"explanation":"Minnesota CDL Manual (Sec. 1.3.5) предусматривает 60 days за первое, 120 days за второе в течение трёх лет и не менее одного года за третье в течение трёхлетнего периода. Источник: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51."},"54":{"q":"Сколько обвинительных приговоров за использование ручного мобильного телефона во время управления CMV должен иметь водитель Миннесоты, прежде чем CDL будет дисквалифицирован?","options":["Один приговор","Два или более приговоров","Три или более приговоров","Пять или более приговоров"],"explanation":"Minnesota CDL Manual гласит, что CDL дисквалифицируется после двух или более обвинительных приговоров по закону штата об использовании ручного мобильного телефона во время управления CMV (60 days за второе в течение 3 лет, 120 days за три или более). Источник: Minnesota DVS CDL Manual, Sec. 2.9.4; Minn. Stat. 169.475."},"55":{"q":"Помимо дисквалификации CDL, каков максимальный гражданский штраф, который может грозить водителю CMV в Миннесоте за каждое нарушение, связанное с использованием ручного телефона или отправкой текстовых сообщений за рулём?","options":["До $500","До $1,000","До $2,750","До $11,000"],"explanation":"Minnesota CDL Manual гласит, что первое и каждое последующее нарушение, связанное с использованием ручного телефона или отправкой текстовых сообщений, подлежит гражданским штрафам на водителя до $2,750 (работодатели, которые это допускают или требуют, подвергаются штрафам до $11,000). Источник: Minnesota DVS CDL Manual, Sec. 2.9.4 and 2.9.5."},"56":{"q":"Держатель CDL Миннесоты обнаружен за управлением некоммерческим (личным) транспортным средством с BAC 0.08 percent или более. Каково последствие для CDL?","options":["Никаких последствий, поскольку это не было CMV","Дисквалификация от управления CMV как минимум на один год","Дисквалификация на 60 days","Дисквалификация на 90 days"],"explanation":"Minnesota CDL Manual гласит, что BAC 0.08 percent или более в некоммерческом транспортном средстве аннулирует привилегии Класса D и дисквалифицирует водителя от управления CMV как минимум на один год. Источник: Minnesota DVS CDL Manual, Revocation of Class D Privileges and Disqualification of CDL Privileges; Minn. Stat. 171.165."},"57":{"q":"При приближении к железнодорожному переезду в Миннесоте водитель, обязанный остановиться (например, автобус с пассажирами), должен остановить транспортное средство на каком расстоянии от ближайшего рельса?","options":["Не менее 15 футов, но не более 50 футов","Не менее 10 футов, но не более 25 футов","Не менее 25 футов, но не более 75 футов","Не менее 5 футов, но не более 15 футов"],"explanation":"Руководство CDL Миннесоты и Minn. Stat. 169.28 требуют, чтобы транспортные средства, обязанные останавливаться на железнодорожных переездах, останавливались не ближе 15 футов и не дальше 50 футов от ближайшего рельса. Источник: Minnesota CDL Manual (Railroad Grade Crossing); Minn. Stat. 169.28."},"58":{"q":"Согласно правилам CDL Миннесоты, какая группа транспортных средств должна останавливаться на ВСЕХ железнодорожных переездах независимо от того, приближается ли поезд?","options":["Автобусы с пассажирами, школьные автобусы (с пассажирами или без) и транспортные средства с табличками об опасном грузе","Только транспортные средства с полной массой более 26 001 фунта","Только сцепки с тремя прицепами и цистерны объемом более 1000 галлонов","Любое коммерческое транспортное средство, тянущее прицеп любого типа"],"explanation":"Руководство CDL Миннесоты перечисляет транспортные средства, обязанные останавливаться на каждом железнодорожном переезде: автобусы с пассажирами, школьные автобусы (с пассажирами или без) и транспортные средства с табличками об опасном грузе. Источник: Minnesota CDL Manual (Railroad Grade Crossing); 49 CFR 392.10, принятый в Миннесоте."},"59":{"q":"На двухполосной дороге Миннесоты с движением в обоих направлениях, когда школьный автобус остановился с выдвинутым знаком «Стоп» и мигающими красными огнями, приближающийся водитель должен остановиться на каком минимальном расстоянии от автобуса?","options":["Не менее чем в 20 футах","Не менее чем в 10 футах","Не менее чем в 30 футах","Не менее чем в 50 футах"],"explanation":"Minn. Stat. 169.444, subd. 1 и Руководство CDL Миннесоты требуют, чтобы водитель, приближающийся к остановившемуся школьному автобусу с выдвинутым знаком «Стоп» и мигающими красными огнями, остановился не менее чем в 20 футах и оставался на месте, пока знак не будет убран, а огни не перестанут мигать. Источник: Minn. Stat. 169.444; Minnesota CDL Manual."},"60":{"q":"Согласно законодательству Миннесоты, на каком типе проезжей части водитель НЕ обязан останавливаться перед школьным автобусом, который производит посадку или высадку на противоположной стороне?","options":["Проезжая часть с раздельными полосами, разделенными физическим барьером, приподнятым или заглубленным разделителем","Любая дорога с двумя или более полосами в каждом направлении","Любая дорога с нанесенной осевой линией, разделяющей встречные полосы","Любая дорога с центральной полосой для левых поворотов в обоих направлениях"],"explanation":"Minn. Stat. 169.444, subd. 4 освобождает водителя от обязанности останавливаться только в том случае, если автобус находится на другой проезжей части и проезжие части «разделены», то есть отделены физическим барьером, приподнятым или заглубленным разделителем. Нанесенная линия или центральная полоса для поворотов не являются раздельной проезжей частью. Источник: Minn. Stat. 169.444, subd. 4."},"61":{"q":"Каково максимальное установленное законом ограничение скорости на сельской межштатной автомагистрали Миннесоты за пределами какой-либо урбанизированной территории?","options":["70 миль/ч","65 миль/ч","75 миль/ч","60 миль/ч"],"explanation":"Minn. Stat. 169.14 устанавливает ограничение скорости в 70 миль/ч на межштатных автомагистралях за пределами какой-либо урбанизированной территории и 65 миль/ч в пределах урбанизированной территории. Источник: Minn. Stat. 169.14, subd. 2; MnDOT."},"62":{"q":"В Миннесоте какое ограничение скорости применяется к груженому тягачу с полуприцепом на сельской межштатной автомагистрали по сравнению с легковым автомобилем?","options":["То же ограничение, что и для легковых автомобилей; Миннесота не устанавливает отдельного пониженного ограничения скорости для грузовиков","На 10 миль/ч ниже установленного ограничения для легковых автомобилей","Единый максимум 60 миль/ч для грузовиков по всему штату","На 5 миль/ч ниже установленного ограничения для легковых автомобилей"],"explanation":"Миннесота не устанавливает отдельного пониженного ограничения скорости для грузовиков или коммерческих транспортных средств. Установленные законом ограничения в Minn. Stat. 169.14 применяются одинаково ко всем транспортным средствам. Источник: Minn. Stat. 169.14; рекомендации MnDOT по ограничениям скорости."},"63":{"q":"Согласно закону Миннесоты «Ted Foss» о смене полосы (Move Over), на дороге с ровно двумя полосами в одном направлении, что должен сделать водитель при приближении к остановившемуся уполномоченному транспортному средству с мигающими или предупредительными огнями?","options":["Безопасно перестроиться в полосу, наиболее удаленную от уполномоченного транспортного средства, если это возможно","Полностью остановиться, пока уполномоченное транспортное средство не уедет","Подать звуковой сигнал и сохранять текущую полосу и скорость","Перестроиться в полосу, ближайшую к уполномоченному транспортному средству, чтобы проехать вплотную и медленно"],"explanation":"Minn. Stat. 169.18, subd. 11(b) требует, чтобы водитель безопасно перестроился в полосу, наиболее удаленную от остановившегося уполномоченного транспортного средства с включенными огнями, когда в одном направлении есть две полосы. Источник: Minn. Stat. 169.18, subd. 11; Minnesota DPS (Ted Foss Move Over law)."},"64":{"q":"Согласно закону Миннесоты о смене полосы (Move Over), на дороге с БОЛЕЕ чем двумя полосами в одном направлении, что обязан сделать водитель при проезде мимо остановившегося уполномоченного транспортного средства с включенными огнями?","options":["Оставить целую свободную полосу между водителем и полосой, занимаемой уполномоченным транспортным средством, если это безопасно","Полностью остановиться в крайней правой полосе","Снизить скорость ровно до половины установленного ограничения, но оставаться в той же полосе","Перестроиться в полосу, непосредственно прилегающую к уполномоченному транспортному средству"],"explanation":"Minn. Stat. 169.18, subd. 11(c) требует, чтобы водитель на дороге с более чем двумя полосами в одном направлении безопасно перестроился так, чтобы оставить целую свободную полосу между собой и любой полосой, занимаемой уполномоченным транспортным средством. Источник: Minn. Stat. 169.18, subd. 11."},"65":{"q":"Что из перечисленного включено в определение «уполномоченного транспортного средства» в Миннесоте, защищаемого законом о смене полосы (Move Over)?","options":["Эвакуатор, транспортное средство коммунальной компании или машина для вывоза мусора/переработки с включенными огнями","Только маркированные патрульные автомобили правоохранительных органов","Только машины скорой помощи и пожарная техника","Любой легковой автомобиль с включенными габаритными огнями"],"explanation":"Minn. Stat. 169.18, subd. 11(a) широко определяет «уполномоченное транспортное средство», включая аварийные транспортные средства, эвакуаторы, машины дорожно-патрульной службы на автомагистралях, машины дорожного обслуживания, транспортные средства коммунальных компаний, строительную технику, транспортные средства почтовой службы и машины для вывоза мусора или переработки. Источник: Minn. Stat. 169.18, subd. 11(a)."},"66":{"q":"Если коммерческое транспортное средство вынуждено остановиться на односторонней или разделенной автомагистрали Миннесоты или возле нее, где водитель должен разместить три аварийных предупреждающих устройства?","options":["В 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта","В 25 футах, 100 футах и 300 футах в сторону приближающегося транспорта","В 10 футах, 50 футах и 150 футах в сторону приближающегося транспорта","В 15 футах, 75 футах и 250 футах в сторону приближающегося транспорта"],"explanation":"Руководство CDL Миннесоты (и 49 CFR 392.22) требуют, чтобы на односторонней или разделенной автомагистрали три предупреждающих устройства размещались в 10 футах, 100 футах и 200 футах от транспортного средства в сторону приближающегося транспорта. Источник: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22."},"67":{"q":"В течение скольких минут после остановки на дороге или обочине коммерческий водитель в Миннесоте должен выставить требуемые аварийные предупреждающие устройства?","options":["В течение 10 минут","В течение 5 минут","В течение 15 минут","В течение 30 минут"],"explanation":"Руководство CDL Миннесоты гласит, что если вы вынуждены остановиться на дороге или обочине, вы должны выставить аварийные предупреждающие устройства в течение десяти минут. Источник: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22."},"68":{"q":"На неразделенной двухполосной дороге Миннесоты с движением в обоих направлениях, где остановившийся коммерческий водитель должен разместить предупреждающие устройства?","options":["В пределах 10 футов от передних или задних углов и в 100 футах позади и впереди транспортного средства","В 10 футах, 100 футах и 200 футах только в сторону приближающегося транспорта","Только одно устройство в 500 футах позади","В пределах 50 футов от транспортного средства только со стороны движения"],"explanation":"Руководство CDL Миннесоты указывает, что на двухполосной дороге с движением в обоих направлениях (неразделенная автомагистраль) предупреждающие устройства размещаются в пределах 10 футов от передних или задних углов для обозначения транспортного средства и в 100 футах позади и впереди транспортного средства. Источник: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22."},"69":{"q":"Сколько красных светоотражающих треугольников требуется коммерческому транспортному средству в Миннесоте в качестве обязательных предупреждающих устройств для остановившегося транспортного средства?","options":["Три светоотражающих треугольника (или 6 фальшфейеров, или 3 жидкостных горящих сигнальных огня)","Два светоотражающих треугольника","Четыре светоотражающих треугольника","Один светоотражающий треугольник плюс один флажок"],"explanation":"Руководство CDL Миннесоты требует наличия предупреждающих устройств для припаркованных транспортных средств, состоящих из трех светоотражающих треугольников, или не менее 6 фальшфейеров, или 3 жидкостных горящих сигнальных огней. Источник: Minnesota CDL Manual (Warning Devices for parked vehicles); 49 CFR 393.95."},"70":{"q":"В Миннесоте, когда грузовик или автобус движется по проезжей части за пределами делового или жилого района, он не может следовать за другим транспортным средством ближе какого расстояния?","options":["500 футов","300 футов","200 футов","100 футов"],"explanation":"Minn. Stat. 169.18, subd. 8(b) предусматривает, что водитель грузового автомобиля, автобуса или транспортного средства, тянущего другое транспортное средство, не должен следовать ближе 500 футов за другим транспортным средством при движении за пределами делового или жилого района. Источник: Minn. Stat. 169.18, subd. 8."},"71":{"q":"Водитель школьного автобуса в Миннесоте должен включить четырехстороннюю аварийную сигнализацию на каком расстоянии перед ближайшим рельсом на железнодорожном переезде?","options":["Не менее чем за 100 футов от ближайшего рельса","Не менее чем за 25 футов от ближайшего рельса","Не менее чем за 300 футов от ближайшего рельса","Не менее чем за 50 футов от ближайшего рельса"],"explanation":"Раздел о школьных автобусах в Руководстве CDL Миннесоты требует, чтобы водитель школьного автобуса включал четырехстороннюю аварийную сигнализацию не менее чем за 100 футов от ближайшего рельса, с выключенным главным переключателем, и запрещает использовать 8-фонарную систему на железнодорожном переезде. Источник: Minnesota CDL Manual (School Bus Railroad Crossings)."},"72":{"q":"Водитель в Миннесоте, не остановившийся перед школьным автобусом с выдвинутым знаком «Стоп» и мигающими красными огнями, как минимум, виновен в каком правонарушении?","options":["Мисдиминор, наказуемый штрафом не менее $500","Малозначительный мисдиминор с максимальным штрафом $50","Нарушение без штрафа за первое правонарушение","Фелония в каждом случае"],"explanation":"Согласно Minn. Stat. 169.444 и Руководству CDL Миннесоты, водитель, не остановившийся перед школьным автобусом, как это требуется, виновен в мисдиминоре, наказуемом штрафом не менее $500, с возможным приостановлением действия лицензии. Источник: Minn. Stat. 169.444; Minnesota CDL Manual."},"73":{"q":"Объезд остановившегося школьного автобуса с правой стороны (со стороны пассажирской двери) или объезд, когда ребенок находится снаружи на проезжей части, повышает правонарушение водителя в Миннесоте до какого уровня?","options":["Тяжкий мисдиминор (gross misdemeanor) с возможностью аннулирования лицензии","Обычная дорожная квитанция только со штрафными баллами","Малозначительный мисдиминор","Гражданское нарушение правил парковки"],"explanation":"Minn. Stat. 169.444 и Руководство CDL Миннесоты квалифицируют как тяжкий мисдиминор (gross misdemeanor), влекущий аннулирование лицензии, неостановку с объездом автобуса с правой стороны (со стороны пассажирской двери) или объезд, когда школьник находится снаружи на улице, шоссе или прилегающем тротуаре. Источник: Minn. Stat. 169.444; Minnesota CDL Manual."},"74":{"q":"Что касается платных дорог, какое утверждение лучше всего описывает систему межштатных автомагистралей и шоссе Миннесоты для коммерческих водителей?","options":["В Миннесоте нет традиционных платных дорог; существуют только опциональные скоростные полосы E-ZPass MN (ранее MnPASS) в агломерации Twin Cities","Все межштатные автомагистрали Миннесоты требуют наличия транспондера для платы для грузовиков","Грузовики должны платить пошлину за каждую ось на каждой межштатной автомагистрали Миннесоты","Миннесота управляет общегосударственной сетью платных дорог, как Indiana Toll Road"],"explanation":"В Миннесоте нет традиционных платных дорог; ее единственное взимание платы — это опциональные скоростные полосы E-ZPass Minnesota (ранее MnPASS) на I-394, I-35W и I-35E в агломерации Twin Cities, при этом рядом всегда доступны бесплатные полосы общего пользования. Источник: MnDOT; Minnesota DPS."},"75":{"q":"Держатель CDL в Миннесоте, осужденный за единичное нарушение на железнодорожном переезде при управлении коммерческим транспортным средством, лишается права управления CMV как минимум на какой срок?","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Руководство CDL Миннесоты гласит, что водитель лишается права управления на 60 дней за первое нарушение на железнодорожном переезде, на 120 дней за два нарушения в любой трехлетний период и на один год за три или более нарушений в любой трехлетний период. Источник: Minnesota CDL Manual (Railroad Grade Crossing Violation); 49 CFR 383.51."},"76":{"q":"На многополосной автомагистрали Миннесоты что требует от коммерческого транспортного средства, движущегося медленнее обычной скорости потока, правило штата об использовании полос?","options":["Двигаться по правой полосе или как можно ближе к правому краю, за исключением обгона или поворота налево","Все время держаться в центральной полосе, чтобы более быстрый поток мог использовать обе внешние полосы","Занимать левую полосу, чтобы правая полоса оставалась свободной для въезжающего транспорта","Использовать обочину всякий раз, когда движение интенсивнее обычного"],"explanation":"Minn. Stat. 169.18, subd. 10 требует, чтобы транспортное средство, движущееся медленнее обычного потока, двигалось по доступной в этот момент правой полосе или как можно ближе к правому бордюру или краю, за исключением обгона, подготовки к левому повороту или там, где полоса предназначена для конкретного использования. Источник: Minn. Stat. 169.18, subd. 10."},"77":{"q":"Какое агентство Миннесоты выдает коммерческие водительские удостоверения и проводит тестирование на CDL в штате?","options":["Департамент общественной безопасности, Driver and Vehicle Services (DVS)","Секция коммерческого транспорта Дорожного патруля штата Миннесота","Federal Motor Carrier Safety Administration (FMCSA)","Департамент транспорта Миннесоты (MnDOT)"],"explanation":"CDL в Миннесоте выдаются Департаментом общественной безопасности через его подразделение Driver and Vehicle Services (DVS), которое также проводит тесты на знания и навыки. MnDOT занимается медицинскими освобождениями для перевозок внутри штата и разрешениями на негабаритные/перегруженные грузы, а не выдачей лицензий. Источник: Minnesota CDL Manual, Part A (DVS, Department of Public Safety)."},"78":{"q":"В Миннесоте каждый соискатель CDL должен сначала получить какое удостоверение, позволяющее практиковать вождение коммерческого транспортного средства под наблюдением?","options":["Коммерческое ученическое разрешение (CLP)","Временный сертификат о сдаче теста на навыки","Инструкторское освобождение для CDL","Временную коммерческую отметку (endorsement)"],"explanation":"Миннесота требует, чтобы все соискатели CDL сначала получили коммерческое ученическое разрешение (CLP), которое позволяет практиковать вождение только при наличии в транспортном средстве другого водителя с соответствующей лицензией того же класса или выше. Источник: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"79":{"q":"Каков минимальный возраст для получения коммерческого ученического разрешения (CLP) в Миннесоте?","options":["18 лет","17 лет","21 год","16 лет"],"explanation":"Вам должно быть не менее 18 лет и вы должны иметь действующее водительское удостоверение Миннесоты, чтобы получить CLP. Вам должен быть 21 год, чтобы управлять коммерческим транспортным средством в межштатных перевозках. Источник: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"80":{"q":"После подачи заявления на CLP в Миннесоте, как долго соискатель должен владеть им, прежде чем ему будет разрешено сдавать тест на навыки CDL (дорожный тест)?","options":["14 календарных дней","10 календарных дней","7 календарных дней","30 календарных дней"],"explanation":"Миннесота требует, чтобы CLP находился во владении 14 календарных дней с даты подачи заявления, прежде чем соискатель сможет сдавать тест на навыки CDL. Источник: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"81":{"q":"Сколько времени действует коммерческое ученическое разрешение (CLP) Миннесоты с даты его выдачи?","options":["1 год","2 года","90 дней","180 дней"],"explanation":"CLP Миннесоты действует 180 дней. Он может быть продлен, но не может действовать более одного года с даты первоначальной выдачи. Источник: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"82":{"q":"Тест на навыки CDL в Миннесоте делится на какие три этапа?","options":["Проверка пневматических тормозов, сцепка/расцепка и вождение по автомагистрали","Письменный экзамен, проверка зрения и дорожный тест","Осмотр транспортного средства, базовые навыки управления и дорожный тест","Предрейсовая документация, заезд задним ходом на площадке и тест по безопасному вождению"],"explanation":"Тест на навыки CDL в Миннесоте состоит из трех этапов: (1) осмотр транспортного средства (предрейсовый), (2) тест на базовые навыки управления и (3) дорожный тест. Все три должны сдаваться на том типе транспортного средства, для которого вы хотите получить лицензию. Источник: Minnesota CDL Manual, Part A, Skills Tests."},"83":{"q":"Во время этапа осмотра транспортного средства на CDL в Миннесоте, что должен сделать соискатель, чтобы получить зачет по каждому пункту?","options":["Завершить осмотр молча в установленный срок","Заменить любые изношенные детали, обнаруженные во время проверки","Залезть под транспортное средство и проверить все уровни жидкостей","Указать на каждый пункт и объяснить, какие проблемы искать на холодном транспортном средстве"],"explanation":"При осмотре транспортного средства соискатель должен указать экзаменатору на каждый пункт и объяснить, какие проблемы искать на холодном транспортном средстве, упомянув основные моменты, чтобы получить зачет. От вас не требуется залезать под транспортное средство или проверять жидкости. Источник: Minnesota CDL Manual, Part A, Vehicle Inspection."},"84":{"q":"Сколько раз в день соискатель CDL в Миннесоте может проходить каждый отдельный тест на знания?","options":["Три раза в день","Дважды в день","Неограниченное количество попыток в день","Один раз в день"],"explanation":"Тест на знания CDL предлагается на английском языке на бумаге или на компьютере, и соискатель может проходить каждый тест на знания только один раз в день. Источник: Minnesota CDL Manual, Part A, Knowledge Tests."},"85":{"q":"Обучение водителей начального уровня (ELDT) стало обязательным для впервые подающих заявление соискателей Class A/Class B в Миннесоте и для определенных отметок (endorsements) с какой даты?","options":["21 мая 2014 года","1 ноября 2021 года","7 февраля 2022 года","4 января 2020 года"],"explanation":"Требования ELDT применяются к лицам, получающим CDL Class A или B (или отметку S, P или H) 7 февраля 2022 года или после этой даты. Соискатель, чей действующий CLP был выдан до этой даты, освобождается от требований, если он получает CDL до истечения срока действия CLP. Источник: Minnesota CDL Manual, ELDT (FMCSA Training Provider Registry)."},"86":{"q":"Согласно федеральному правилу ELDT, применяемому в Миннесоте, что требуется для прохождения теоретической (аудиторной) части обучения?","options":["Набрать не менее 70% на теоретической оценке","Набрать не менее 80% на теоретической оценке","Пройти оценку на симуляторе вождения","Завершить минимум 30 аудиторных часов"],"explanation":"Теоретическое обучение ELDT не имеет минимального количества часов, но обучающийся должен набрать не менее 80% на теоретической оценке. Практическое обучение за рулем не имеет минимального количества часов и оценивается провайдером по уровню владения навыками. Источник: Minnesota CDL Manual, ELDT (FMCSA Training Provider Registry)."},"87":{"q":"Прежде чем водитель начального уровня сможет пройти практическую часть за рулем (BTW) обучения ELDT в Миннесоте, что у него уже должно быть?","options":["Только сертификат медицинского эксперта DOT","Коммерческое ученическое разрешение (CLP)","Полноценный CDL без ограничений","Сданный дорожный тест на CDL"],"explanation":"Практическую часть за рулем обучения ELDT нельзя проходить до того, как соискатель получит CLP, и она должна быть завершена в течение одного года после аудиторного (теоретического) обучения. Источник: Minnesota CDL Manual / DPS DVS CLP page."},"88":{"q":"В форме самосертификации Миннесоты какая категория требует, чтобы водитель, осуществляющий неосвобожденные МЕЖШТАТНЫЕ перевозки, также предоставлял действующий сертификат медицинского эксперта?","options":["Категория 4 — Освобожденные внутриштатные","Категория 1 — Неосвобожденные межштатные (подпадающие под 49 CFR part 391)","Категория 2 — Освобожденные межштатные","Категория 3 — Неосвобожденные внутриштатные (подпадающие под главу 221 Статутов Миннесоты)"],"explanation":"Категория 1, неосвобожденные межштатные, удостоверяет, что водитель подпадает под федеральные медицинские требования DOT по 49 CFR part 391 и соответствует им, и должен предоставить действующий сертификат медицинского эксперта и любые освобождения (waivers). Источник: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS)."},"89":{"q":"Какая категория самосертификации Миннесоты охватывает НЕОСВОБОЖДЕННОГО ВНУТРИШТАТНОГО водителя, который подпадает под требования штата о медицинском освидетельствовании?","options":["Категория 4 — Освобожденные внутриштатные","Категория 2 — Освобожденные межштатные","Категория 3 — Неосвобожденные внутриштатные, по главе 221 Статутов Миннесоты","Категория 1 — Неосвобожденные межштатные, по 49 CFR part 391"],"explanation":"Категория 3, неосвобожденные внутриштатные, применяется к водителям, подпадающим под требования штата о медицинском освидетельствовании согласно главе 221 Статутов Миннесоты, которые также должны предоставить действующий сертификат медицинского эксперта и любые освобождения (waivers). Источник: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS)."},"90":{"q":"Сколько категорий самосертификации перечислено в форме медицинской самосертификации коммерческого водительского удостоверения Миннесоты?","options":["Две категории","Четыре категории","Три категории","Пять категорий"],"explanation":"Форма самосертификации Миннесоты перечисляет четыре категории: неосвобожденные межштатные, освобожденные межштатные, неосвобожденные внутриштатные и освобожденные внутриштатные. Две из четырех (неосвобожденные категории) требуют сертификата медицинского эксперта. Источник: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS)."},"91":{"q":"Куда держатель CDL в Миннесоте подает заполненную форму самосертификации и действующий сертификат медицинского эксперта?","options":["Департамент общественной безопасности / Driver and Vehicle Services (DVS)","Управление по обслуживанию автоперевозчиков MnDOT","Federal Motor Carrier Safety Administration (FMCSA)","National Registry of Certified Medical Examiners"],"explanation":"Водители подают форму самосертификации и действующий сертификат медицинского эксперта в Департамент общественной безопасности / отдел CDL DVS (онлайн на drive.mn.gov, по почте, факсу или лично в экзаменационном пункте для водителей). Затем информация о сертификате вносится в водительскую запись. Источник: Minnesota CDL Manual, Medical Requirements; DPS DVS Self-Certification FAQs."},"92":{"q":"Сертификат медицинского эксперта DOT в Миннесоте обычно действителен в течение какого максимального срока?","options":["Пять лет","Три года","До двух лет","Один год"],"explanation":"Сертификат медицинского эксперта может быть действителен до двух лет, хотя эксперт может выдать его на более короткий срок в зависимости от медицинской истории водителя. Источник: Minnesota CDL Manual, Medical Certificate Renewal; DPS DVS Self-Certification FAQs."},"93":{"q":"За сколько дней до истечения срока действия сертификата медицинского эксперта Департамент общественной безопасности Миннесоты направляет водителю уведомление?","options":["За 45 дней","За 90 дней","За 60 дней","За 30 дней"],"explanation":"Департамент общественной безопасности направляет уведомление по последнему известному адресу водителя за 60 дней до даты истечения срока действия сертификата медицинского эксперта или освобождения (waiver), имеющегося в деле. Источник: Minnesota CDL Manual, Medical Certificate Renewal."},"94":{"q":"Если CDL в Миннесоте понижен в классе (downgraded) из-за непредоставления требуемого сертификата медицинского эксперта, в течение какого срока водитель может восстановить CDL, просто предоставив действующий сертификат?","options":["В течение двух лет","В течение 6 месяцев","В течение 30 дней","В течение одного года"],"explanation":"Водитель может восстановить пониженный в классе CDL и отметки (endorsements) в течение одного года, предоставив действующий сертификат медицинского эксперта вместе с формой самосертификации. Если класс был понижен или лицензия сдана на срок более одного года, водитель должен заново сдать соответствующие тесты на знания и дорожный тест. Источник: Minnesota CDL Manual, Medical Certificate Renewal; DPS DVS FAQs."},"95":{"q":"Сколько времени действует коммерческое водительское удостоверение Миннесоты, прежде чем его необходимо продлить?","options":["Два года","Четыре года","Пять лет","Восемь лет"],"explanation":"CDL Миннесоты (Class A, B или C) действует четыре года, после чего его необходимо продлить — тот же цикл, что и у обычной лицензии Class D. Источник: DPS DVS CDL Class pages (Department of Public Safety)."}},"tr":{"0":{"q":"Aynalar ve yük sabitleme aygıtları hariç olmak üzere, Minnesota karayollarında bir ticari aracın yasal azami genişliği nedir?","options":["8 fit 0 inç (96 inç)","8 fit 6 inç (102 inç)","9 fit 0 inç (108 inç)","8 fit 4 inç (100 inç)"],"explanation":"Minnesota Statute 169.80, azami toplam dış genişliği 102 inç (8 fit 6 inç) olarak belirler. Bu, federal standartla aynıdır. Kaynak: Minn. Stat. 169.80; MnDOT CVO."},"1":{"q":"Yüklü ya da yüksüz bir aracın Minnesota karayollarında yasal azami yüksekliği nedir?","options":["13 fit 0 inç","14 fit 0 inç","13 fit 6 inç","14 fit 6 inç"],"explanation":"Minnesota Statute 169.81, hiçbir aracın yüksüz veya yüklü olarak 13 fit 6 inç yüksekliği aşamayacağını belirtir. Kaynak: Minn. Stat. 169.81; Minnesota CDL Kılavuzu."},"2":{"q":"İzin (permit) olmaksızın bir aracın veya araç kombinasyonunun Minnesota cadde ve karayollarındaki azami brüt ağırlığı nedir?","options":["73.280 pound","80.000 pound","84.000 pound","88.000 pound"],"explanation":"Minnesota Statute 169.824, federal sınırla uyumlu olarak tüm cadde ve karayollarında brüt araç ağırlığını 80.000 pound ile sınırlar. Kaynak: Minn. Stat. 169.824; MnDOT."},"3":{"q":"Minnesota yasalarına göre, asfalt bir karayolunda tek bir aks üzerinde izin verilen azami ağırlık nedir?","options":["18.000 pound","20.000 pound","22.400 pound","34.000 pound"],"explanation":"Minnesota Statute 169.823, asfalt cadde ve karayollarında tek aksı 20.000 pound ile sınırlar. Kaynak: Minn. Stat. 169.823; MnDOT CVO Truck Book."},"4":{"q":"Minnesota'da bir ikiz aks (tandem) grubunda izin verilen azami ağırlık nedir?","options":["32.000 pound","36.000 pound","34.000 pound","40.000 pound"],"explanation":"Minnesota, Minn. Stat. 169.824'ün aks ağırlığı çizelgesinde düzenlenen federal ikiz aks sınırı olan 34.000 pound'u uygular. Kaynak: Minn. Stat. 169.824; Minnesota CDL Kılavuzu."},"5":{"q":"Bir Minnesota karayolunda, yük ve tamponlar dahil olmak üzere tek (mafsalsız) bir aracın azami toplam uzunluğu nedir?","options":["40 fit","45 fit","48 fit","53 fit"],"explanation":"Minnesota Statute 169.81, tek bir aracı yük ile ön ve arka tamponlar dahil olmak üzere toplam 45 fit ile sınırlar (mobil vinçler 48 fite ulaşabilir). Kaynak: Minn. Stat. 169.81."},"6":{"q":"İzin (permit) olmaksızın bir iki birimli (çekici-yarı römork) kombinasyonun Minnesota karayollarındaki azami toplam uzunluğu nedir?","options":["65 fit","70 fit","75 fit","80 fit"],"explanation":"Minnesota Statute 169.81, iki birimli bir araç kombinasyonunun azami uzunluğunu 75 fit olarak belirler. Kaynak: Minn. Stat. 169.81; MnDOT CVO."},"7":{"q":"Minnesota'da çekici-yarı römork kombinasyonundaki bir yarı römork genellikle hangi uzunluğu aşamaz?","options":["45 fit","48 fit","53 fit","57 fit"],"explanation":"Minnesota Statute 169.81, bir yarı römorkun genellikle 48 fiti aşamayacağını, ancak kingpin'den arka aksa olan mesafe 43 fiti aşmadığında 53 fite kadar izin verildiğini öngörür. Kaynak: Minn. Stat. 169.81."},"8":{"q":"Minnesota, aks aralığına ve aks sayısına dayanarak ardışık akslar grubu üzerindeki azami izin verilen ağırlığı belirlemek için hangi formülü kullanır?","options":["Federal Köprü Formülü (Federal Bridge Formula)","Brüt Kombinasyon Derecelendirme formülü","Minnesota Tonaj Endeksi","Aks Yükü Eşdeğerliği formülü"],"explanation":"Minnesota'nın Minn. Stat. 169.824'teki aks grubu ağırlık tablosu, akslar ve aralık arttıkça daha fazla ağırlığa izin veren Federal Köprü Formülü'nü (Federal Bridge Formula) uygular. Kaynak: Minn. Stat. 169.824; Minnesota CDL Kılavuzu."},"9":{"q":"Bir Minnesota karayolunda yük taşımak için MnDOT'un aşırı boyut/aşırı ağırlık (OSOW) iznine ne zaman ihtiyaç vardır?","options":["Yalnızca yük 100.000 pound'u aştığında","Araç veya yük herhangi bir yasal boyut veya ağırlık sınırını aştığında","Yalnızca 10 fitten geniş yükler için","Yalnızca Eyaletlerarası (Interstate) karayollarında"],"explanation":"Bir araç veya yük yasal bir boyut veya ağırlık sınırını aştığında ve bir Minnesota karayolu üzerinde veya karşısında hareket edeceğinde her zaman bir MnDOT OSOW izni gereklidir. Kaynak: Minn. Stat. 169.86; MnDOT CVO Oversize/Overweight Permits."},"10":{"q":"102 inçlik yasal genişliğin ötesinde, aracın ayrılmaz bir parçası olmayan dikiz aynaları veya yük sabitleme aygıtları Minnesota'da her bir tarafta yasal olarak ne kadar uzanabilir?","options":["Her bir tarafta en fazla 3 inç","Her bir tarafta en fazla 6 inç","Hiç uzanamazlar","Her bir tarafta en fazla 12 inç"],"explanation":"Minnesota Statute 169.80, aracın ayrılmaz parçası olmayan aynaların veya yük sabitleme aygıtlarının her bir tarafta 102 inçlik genişliğin ötesine 3 inçe kadar uzanmasına izin verir. Kaynak: Minn. Stat. 169.80."},"11":{"q":"Komiser (commissioner) tarafından ilan edilen bir kış ağırlık artışı sırasında, Minnesota mevsimsel brüt ve aks ağırlık sınırları uygun yollarda ne kadar artırılabilir?","options":["Yüzde 5","Yüzde 10","Yüzde 15","Yüzde 20"],"explanation":"Minnesota Statute 169.826, komisere her bölge için belirlenen kış (donmuş yol) dönemi boyunca ağırlık sınırlarını yüzde 10 artırma yetkisi verir. Kaynak: Minn. Stat. 169.826; MnDOT."},"12":{"q":"Minnesota'da yıllık izinle çalışan bir çift katlı otobüs, standart 13 fit 6 inç sınırının üzerinde hangi yüksekliğe ulaşabilir?","options":["13 fit 9 inç","14 fit 0 inç","14 fit 3 inç","15 fit 0 inç"],"explanation":"Minnesota Statute 169.81, yıllık izinle çalıştırıldığında bir çift katlı otobüsün 14 fit 3 inç yüksekliğe ulaşmasına izin verir. Kaynak: Minn. Stat. 169.81."},"13":{"q":"Minnesota Statute 169.826 kapsamındaki hasat sezonu yüzde 10 ağırlık artışı, tarladan ilk boşaltma noktasına hangi ham tarım ürünlerinin taşınmasına uygulanır?","options":["Mısır, soya fasulyesi ve buğday","Şeker pancarı, havuç ve patates","Saman, kuru ot ve silaj","Elma, üzüm ve soğan"],"explanation":"Minnesota Statute 169.826, subd. 1a, şeker pancarı, havuç ve patatesin hasat tarlasından ilk boşaltmaya kadar taşınması için 30 Kasım'a kadar, izinle birlikte hasat sezonu yüzde 10 artışı sağlar. Kaynak: Minn. Stat. 169.826."},"14":{"q":"MnDOT'tan aşırı boyut/aşırı ağırlık izni ve sefer kaydı (trip log) en yaygın olarak nasıl alınır?","options":["Bir ilçe şerif ofisini şahsen ziyaret ederek","Ödeme sonrası bir MnDOT CVO web hesabı üzerinden çevrimiçi olarak","Yasama meclisine bir kağıt form göndererek","CDL ile otomatik olarak verilir"],"explanation":"MnDOT, yıllık, mevsimsel veya tek seferlik OSOW izinlerini çevrimiçi olarak verir; taşıyıcı bir CVO web hesabı oluşturur ve izin verilmeden önce ödeme yapar. Kaynak: MnDOT CVO Oversize/Overweight Permits."},"15":{"q":"Minnesota'da uzatılmış bir yarı römork, yalnızca kingpin'den en arkadaki aksın merkezine olan mesafe hangi değeri aşmadığında 53 fite ulaşabilir?","options":["40 fit","41 fit","43 fit","46 fit"],"explanation":"Minnesota Statute 169.81, kingpin'den arka aks merkezine olan mesafenin 43 fiti aşmaması koşuluyla 53 fite kadar bir yarı römorka izin verir. Kaynak: Minn. Stat. 169.81."},"16":{"q":"Yalnızca canlı hayvan taşıyan altı akslı araçlar, izinle birlikte Minnesota ana karayollarında (Eyaletlerarası karayolları dışında) hangi brüt ağırlığa kadar çalışabilir?","options":["80.000 pound","84.000 pound","88.000 pound","90.000 pound"],"explanation":"Minnesota Statute 169.8261/169.824, yalnızca canlı hayvan taşıyan altı veya daha fazla akslı araçlar için Eyaletlerarası dışındaki ana karayollarında 88.000 pound'a kadar izinli bir brüt ağırlığa olanak tanır. Kaynak: Minn. Stat. 169.824; MnDOT CVO."},"17":{"q":"Minnesota'da, çekilen birimin 10.000 pound'dan fazla GVWR'ye sahip olduğu ve brüt kombinasyon ağırlık derecesi 26.000 pound'u aşan bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf D"],"explanation":"Minnesota CDL Kılavuzu (Bölüm A), Sınıf A'yı brüt kombinasyon ağırlık derecesi (kamyon artı römork) 26.000 pound'u aşan, 10.000 pound'dan fazla GVWR'ye sahip bir birim çeken herhangi bir araç olarak tanımlar. Kaynak: MN DVS Commercial Driver's License Manual, Part A."},"18":{"q":"Minnesota kurallarına göre, GVWR'si 26.000 pound'u aşan tek birimli bir araç (hiçbir şey çekmeyen veya 10.000 pound ya da daha az bir birim çeken) hangi CDL sınıfını gerektirir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf M"],"explanation":"Minnesota CDL Kılavuzu, Sınıf B'yi GVWR'si 26.000 pound'un üzerinde olan tek birimli bir araç olarak tanımlar; ayrıca 10.000 pound'u aşmayan bir birimin çekilmesini de kapsar. Kaynak: MN DVS CDL Manual, Part A."},"19":{"q":"Minnesota'da, 26.000 pound veya daha az GVWR'ye sahip tek birimli bir araç için Sınıf C CDL, yalnızca araç hangi amaçla kullanıldığında geçerlidir?","options":["Yükten bağımsız olarak ücret karşılığı kullanılan herhangi bir araç","Levha (placard) gerektiren tehlikeli maddelerin taşınması veya 16 ya da daha fazla yolcunun taşınması","10.000 pound'dan fazla herhangi bir römorkun çekilmesi","Minnesota dışında herhangi bir aracın kullanılması"],"explanation":"Minnesota CDL Kılavuzu, Sınıf C'nin tehlikeli madde (levhalı), yolcu taşıyan veya bir okul otobüsü olan, ilgili onayı (endorsement) gerektiren, 26.000 pound veya daha az GVWR'ye sahip tek birimli bir araç olduğunu belirtir. Kaynak: MN DVS CDL Manual, Part A."},"20":{"q":"Minnesota, bireysel anma kapasitesi 119 galondan fazla ve toplam 1.000 galon veya daha fazla olan bir tankta sıvı veya gaz taşımak üzere tasarlanmış bir tank aracı kullanan bir sürücü için hangi onayı (endorsement) gerektirir?","options":["H (Tehlikeli Maddeler)","T (İkili/Üçlü Römorklar)","N (Tank Aracı)","X (Tanker ve HazMat)"],"explanation":"Minnesota CDL Kılavuzu, bireysel anma kapasitesi 119 galonun üzerinde ve toplam anma kapasitesi 1.000 galon veya daha fazla olan bir tankta sıvı ya da gaz halindeki maddeleri taşımak üzere tasarlanmış herhangi bir CMV için N (Tank Aracı) onayını tanımlar. Kaynak: MN DVS CDL Manual, Endorsements section."},"21":{"q":"Minnesota'da, ikili veya üçlü römork çekmek için hangi onay (endorsement) gereklidir ve bu genellikle hangi araç sınıfıyla ilişkilendirilir?","options":["T onayı, genellikle Sınıf A sürücüleri için","N onayı, genellikle Sınıf B sürücüleri için","P onayı, genellikle Sınıf C sürücüleri için","H onayı, genellikle Sınıf A sürücüleri için"],"explanation":"Minnesota CDL Kılavuzu, T (İkili/Üçlü Römorklar) onayının, ikili veya üçlü römork çekmek isteyen Sınıf A sürücülerinin ehliyetlerine özel bir bilgi sınavı gerektirilerek eklendiğini belirtir. Kaynak: MN DVS CDL Manual, Endorsements / Doubles and Triples."},"22":{"q":"Minnesota hangi iki onayı (endorsement) tek bir 'X' onayında birleştirir?","options":["Yolcu ve okul otobüsü","Tank aracı ve tehlikeli maddeler","İkili/üçlü römork ve tank aracı","Tehlikeli maddeler ve yolcu"],"explanation":"Minnesota CDL Kılavuzu, X onayını 'Tanker ve Tehlikeli Maddeler' olarak listeler; bu, hem tank hem de HazMat bilgi sınavlarını geçmesi gereken, levhalı miktarlarda tehlikeli madde/atık taşıyan tank aracı sürücüleri için gereklidir. Kaynak: MN DVS CDL Manual, Endorsements."},"23":{"q":"Minnesota'da, HazMat bilgi testini geçmenin yanı sıra, bir sürücüye tehlikeli maddeler (H) onayının verilebilmesi için ne gereklidir?","options":["Levhalı bir tank aracında bir yol becerileri testi","Parmak izi alımı ve geçmiş kontrolü içeren bir TSA güvenlik tehdit değerlendirmesi","Beş yıllık doğrulanabilir eyaletlerarası sürüş deneyimi","Ayrı bir MnDOT aşırı boyut/aşırı ağırlık izni"],"explanation":"Minnesota CDL Kılavuzu, bir HazMat onayı verilmeden veya yenilenmeden önce Ulaştırma Güvenliği İdaresi'nin (TSA) bir geçmiş kontrolü (sabıka, göçmenlik ve FBI kayıtları) yaptığını ve parmak izi gerektirdiğini belirtir. Kaynak: MN DVS CDL Manual, Hazardous Materials / Background Check / Fingerprints."},"24":{"q":"Minnesota'da, okul otobüsü (S) onayı bir CDL'ye yalnızca sürücü hangi diğer onaya da sahip olduğunda eklenebilir?","options":["Tank aracı (N)","İkili/üçlü römork (T)","Yolcu (P)","Tehlikeli maddeler (H)"],"explanation":"Minnesota, okul otobüsü (S) onayının yolcu (P) onayı ile birlikte bulunmasını gerektirir; kılavuzdaki Sınıf C tanımı 'okul otobüsü (yolcu onayı ile)' ifadesini belirtir. Kaynak: MN DVS CDL Manual, Part A / Endorsements."},"25":{"q":"Minnesota'da bir Sınıf B CDL üzerindeki yolcu (P) onayı için, beceri (yol) testi GVWR'si 26.000 pound'dan fazla olan ve sürücü dahil kaç yolcu kapasitesine sahip bir otobüste geçilmelidir?","options":["8'den fazla","10'dan fazla","15'ten fazla","24'ten fazla"],"explanation":"Minnesota CDL Kılavuzu, yolcu (veya okul otobüsü) onayı için beceri testinin, GVWR'si 26.000 pound'dan fazla ve sürücü dahil 15'ten fazla yolcu kapasitesine sahip bir otobüste geçilmesi gerektiğini belirtir. Kaynak: MN DVS CDL Manual, Part A (Class B)."},"26":{"q":"Eyalet içi (Minnesota içi) ticari sürüşle sınırlı bir Minnesota CDL'sine başvurmak için asgari yaş nedir?","options":["16 yaşında","18 yaşında","19 yaşında","21 yaşında"],"explanation":"Minnesota CDL Kılavuzu, eyalet içi bir CDL'ye (örneğin 26.000 lbs GVW'yi aşan tek araç veya 26.000 lbs GCW'yi aşan kombinasyon) başvurmak için asgari 18 yaşı listeler. Kaynak: MN DVS CDL Manual, Part A (minimum age)."},"27":{"q":"Minnesota ve federal kurallara göre, eyaletlerarası ticarette bir CMV kullanmak veya levha gerektiren tehlikeli maddeleri taşımak için genellikle asgari yaş nedir?","options":["18 yaşında","19 yaşında","20 yaşında","21 yaşında"],"explanation":"Minnesota CDL Kılavuzu, tehlikeli madde levhası gerektiren herhangi bir boyuttaki araç için çoğu durumda 21 yaşında olmanız gerektiğini ve eyaletlerarası işletmenin genellikle 21 yaşını gerektirdiğini belirtir. Kaynak: MN DVS CDL Manual, Part A (minimum age / interstate)."},"28":{"q":"Bir Minnesota Ticari Öğrenci İzni (CLP) almak için asgari yaş nedir ve başvuru sahibinin halihazırda neye sahip olması gerekir?","options":["16, bir öğrenci izni ile","18, geçerli bir Minnesota sürücü ehliyeti ile","19, geçerli bir Minnesota sürücü ehliyeti ile","21, geçerli bir Sınıf D ehliyeti ile"],"explanation":"Minnesota CDL Kılavuzu, bir CLP almak için en az 18 yaşında olmanız ve geçerli bir Minnesota sürücü ehliyetine sahip olmanız gerektiğini belirtir. Kaynak: MN DVS CDL Manual, Commercial Learner Permit."},"29":{"q":"Minnesota'da, sahibinin CDL beceri (yol) testine girebilmesi için bir Ticari Öğrenci İzni (CLP) ne kadar süre tutulmalıdır?","options":["7 takvim günü","10 takvim günü","14 takvim günü","30 takvim günü"],"explanation":"Minnesota CDL Kılavuzu, CDL yol testlerine girebilmek için CLP'nin federal asgari süreyle uyumlu olarak 14 takvim günü tutulması gerektiğini belirtir. Kaynak: MN DVS CDL Manual, Commercial Learner Permit."},"30":{"q":"Bir Minnesota Ticari Öğrenci İzni (CLP) ne kadar süre geçerlidir ve yenileme yoluyla geçerli kalabileceği azami toplam süre nedir?","options":["90 gün, toplam 6 aya kadar yenilenebilir","180 gün, ilk verildiği tarihten itibaren bir yıldan fazla geçerli olmaması koşuluyla yenilenebilir","1 yıl, yenilenemez","2 yıl, bir kez yenilenebilir"],"explanation":"Minnesota CDL Kılavuzu, CLP'lerin 180 gün geçerli olduğunu ve ilk veriliş tarihinden itibaren bir yıldan fazla geçerli olmaması koşuluyla yenilenebileceğini belirtir. Kaynak: MN DVS CDL Manual, Commercial Learner Permit."},"31":{"q":"Bir Minnesota CLP ile pratik sürüş yaparken, izin sahibine neye sahip olan bir sürücünün eşlik etmesi gerekir?","options":["Herhangi bir geçerli Minnesota Sınıf D sürücü ehliyeti","Aynı sınıf ve onaylara (endorsement) veya daha üstüne sahip bir CDL","MnDOT'tan bir CDL eğitmeni sertifikası","Yalnızca HazMat onaylı bir CDL"],"explanation":"Minnesota CDL Kılavuzu, pratik sürüş yaparken CLP sahibine aynı ehliyet sınıfına ve onaylarına veya daha üstüne sahip geçerli ehliyetli bir sürücünün eşlik etmesini gerektirir. Kaynak: MN DVS CDL Manual, Commercial Learner Permit."},"32":{"q":"Aşağıdakilerden hangisi bir Minnesota CLP sahibi için izin verilen bir faaliyettir?","options":["CLP üzerinde bir H onayı ile tehlikeli madde taşımak","İkili veya üçlü römorklu bir CMV kullanmak","Tank onayını almak için boş (temizlenmiş) bir tank aracında pratik yapmak","Deneyim kazanmak için ücretli yolcu taşımak"],"explanation":"Minnesota CDL Kılavuzu, tank onayı için pratik yapan bir CLP sahibinin yalnızca kalıntıdan arındırılmış boş bir tank aracı kullanmasına izin verir; tehlikeli madde taşımayı, ikili/üçlü römork çekmeyi ve yolcu taşımayı yasaklar. Kaynak: MN DVS CDL Manual, Commercial Learner Permit restrictions."},"33":{"q":"Minnesota, bir Ticari Öğrenci İznine (CLP) hangi onay (endorsement) setinin eklenmesine izin verir?","options":["Yolcu (P), Okul otobüsü (S) ve Tank aracı (N)","Tehlikeli maddeler (H) ve Tank aracı (N)","İkili/Üçlü Römorklar (T) ve Yolcu (P)","Altı onayın tümü bir CLP'ye eklenebilir"],"explanation":"Minnesota CDL Kılavuzu, bir CLP'ye eklenebilecek tek onayların Yolcu (P), Okul otobüsü (S) ve Tank aracı (N) olduğunu belirtir. Kaynak: MN DVS CDL Manual, Endorsements (CLP note)."},"34":{"q":"Minnesota'da gerekli olan Federal Giriş Seviyesi Sürücü Eğitimi (ELDT), neyin üzerinde listelenmiş bir sağlayıcı aracılığıyla tamamlanmalıdır ve hangi tarihte veya sonrasında başvuran kişilere uygulanır?","options":["FMCSA Training Provider Registry, 7 Şubat 2022 tarihinde veya sonrasında","National Registry of Certified Medical Examiners, 21 Mayıs 2014 tarihinde veya sonrasında","TSA Approved Trainer List, 20 Mart 2025 tarihinde veya sonrasında","MnDOT Office of Motor Carrier Services listesi, 1 Ocak 2020 tarihinde veya sonrasında"],"explanation":"Minnesota CDL Kılavuzu, ELDT gerekliliklerinin 7 Şubat 2022 tarihinde veya sonrasında bir Sınıf A/B CDL ya da S, P veya H onayı alan kişilere uygulandığını ve eğitimin FMCSA Training Provider Registry'de yer alan bir sağlayıcı tarafından verildiğini açıklar. Kaynak: MN DVS CDL Manual, ELDT / Training Provider Registry."},"35":{"q":"Minnesota'da kabul edilen ELDT teori eğitimi kapsamında, bir giriş seviyesi sürücünün teori değerlendirmesinde elde etmesi gereken asgari puan nedir?","options":["En az %70","En az %75","En az %80","En az %90"],"explanation":"Minnesota CDL Kılavuzu, ELDT teori eğitimini asgari saat sayısı olmadan ancak değerlendirmede en az %80 puan gerektirerek açıklar. Kaynak: MN DVS CDL Manual, ELDT (Theory Training)."},"36":{"q":"Bir Minnesota CLP veya CDL'sine başvururken, başvuru sahipleri tıbbi durumlarını kendileri beyan etmelidir (self-certify). Muaf olmayan bir başvuru sahibinin kendi beyan formuyla birlikte hangi belge setini sunması gerekir?","options":["National Registry'de yer alan onaylı bir uzmandan geçerli bir tıbbi muayene sertifikası (medical examiner's certificate)","Yalnızca herhangi bir ruhsatlı hekimden bir doktor notu","Bir TSA güvenlik tehdit değerlendirmesi mektubu","Her durumda bir MnDOT eyalet içi muafiyeti"],"explanation":"Minnesota CDL Kılavuzu, CDL/CLP başvuru sahiplerinin Commercial Driver License Medical Self-Certification Form'u doldurmasını ve tıbbi gerekliliklere tabi iseler National Registry of Certified Medical Examiners'da listelenen bir uzmandan geçerli bir tıbbi muayene sertifikası sunmasını gerektirir. Kaynak: MN DVS CDL Manual, Medical Self-Certification."},"37":{"q":"Minnesota yasalarına göre, bir kişinin yasal olarak bir ticari motorlu araç (CMV) kullanabileceği azami kandaki alkol konsantrasyonu (BAC) nedir?","options":["yüzde 0,02","yüzde 0,04","yüzde 0,08","yüzde 0,10"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.2), yüzde 0,04 veya daha yüksek bir BAC ile bir CMV kullanmanın yasa dışı olduğunu belirtir; bu, ticari olmayan sürücüler için geçerli olan 0,08 sınırının yarısıdır. Kaynak: Minnesota DVS Commercial Driver's License Manual, Sec. 1.3.2; Minn. Stat. 169A.20."},"38":{"q":"Minnesota'da bir CMV sürücüsü test edilir ve yüzde 0,04'ün altında, tespit edilebilir miktarda alkol gösterir. Ne olur?","options":["Seviye sınırın altında olduğu için hiçbir işlem yapılmaz","Sürücü 24 saatliğine hizmet dışı (out of service) bırakılır","Sürücü CDL'sini 60 gün kaybeder","Sürücü CDL'sini bir yıl kaybeder"],"explanation":"Minnesota, yüzde 0,04'ün altındaki tespit edilebilir herhangi bir alkolün 24 saatlik bir hizmet dışı (out-of-service) emriyle sonuçlandığı, yüzde 0,04 veya daha yükseğinin ise bir yıllık diskalifiye olduğu kuralı izler. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.2; Minn. Stat. 169A.20."},"39":{"q":"Minnesota'da halka açık yollarda bir CMV kullanarak, bir sürücü otomatik olarak kan, nefes veya idrar testine rıza göstermiş olur. Bu kurala ne ad verilir?","options":["Zımni rıza yasası (implied consent law)","Varsayılan feragat kuralı","Makul şüphe kuralı","Zorunlu test yasası"],"explanation":"Minnesota'nın CDL Kılavuzu, halka açık yollarda bir CMV kullanmanın Zımni Rıza Yasası (Implied Consent Law) kapsamında kimyasal teste otomatik rıza oluşturduğunu açıklar. Kaynak: Minnesota DVS CDL Manual, Implied Consent Law section; Minn. Stat. 169A.51."},"40":{"q":"Minnesota'da, levhalı tehlikeli madde taşımazken bir CDL sahibinin İLK büyük ihlali (örneğin yüzde 0,04 veya daha yüksek BAC ile bir CMV kullanmak) için asgari diskalifiye süresi nedir?","options":["60 gün","90 gün","Bir yıl","Üç yıl"],"explanation":"Minnesota'nın CDL Kılavuzu, 0,04+ BAC, DUI, reddetme, kaza yerini terk etme veya bir CMV'yi ağır bir suçta kullanma gibi ilk büyük ihlal için sürücünün CDL'sini en az bir yıl kaybettiğini belirtir. Kaynak: Minnesota DVS CDL Manual, Commercial License Disqualifications / Sec. 1.3.2; 49 CFR 383.51."},"41":{"q":"Bir CDL sahibinin ilk diskalifiye edici büyük ihlali, tehlikeli maddeler için levhalı bir CMV kullanırken meydana gelirse, asgari diskalifiye süresi şuna yükselir:","options":["Bir yıl","İki yıl","Üç yıl","Beş yıl"],"explanation":"Minnesota'nın CDL Kılavuzu, bir ilk diskalifiye edici ihlalin tehlikeli maddeler için levhalı bir CMV kullanırken meydana gelmesi durumunda, sürücünün CDL'sini bir yıl yerine en az üç yıl kaybettiğini belirtir. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51."},"42":{"q":"Minnesota'da bir CDL sahibinin İKİNCİ büyük (diskalifiye edici) ihlali için diskalifiye süresi nedir?","options":["Üç yıl","On yıl","Ömür boyu","Beş yıl"],"explanation":"Minnesota'nın CDL Kılavuzu, ikinci bir diskalifiye edici ihlalin CDL ayrıcalıklarının ömür boyu kaybıyla sonuçlandığını belirtir (sınırlı durumlarda 10 yıl sonra yeniden tesis (reinstatement) talep edilebilir). Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51."},"43":{"q":"Minnesota'da bir CMV sürücüsünden yasal olarak bir kimyasal testi yapması istenir ve sürücü reddeder. CDL için sonuç nedir?","options":["Diskalifiye olmaksızın bir uyarı","60 günlük diskalifiye","Bir yıllık diskalifiye","90 günlük diskalifiye"],"explanation":"Minnesota'nın CDL Kılavuzu, bir kimyasal testi vermeyi reddetmenin sürücüyü bir yıl boyunca bir CMV kullanmaktan diskalifiye ettiğini ve sürücünün ehliyetinin de bir yıl iptal edildiğini belirtir. Reddetme bir büyük ihlal olarak ele alınır. Kaynak: Minnesota DVS CDL Manual, Implied Consent Law / Sec. 1.3.2."},"44":{"q":"Minnesota'da, kontrollü maddelerle ilgili bir ağır suç (örneğin uyuşturucu dağıtımı) işlemek için bir CMV kullanmak hangi CDL cezasıyla sonuçlanır?","options":["Bir yıllık diskalifiye","Üç yıllık diskalifiye","Yeniden tesis edilemeyen ömür boyu diskalifiye","120 günlük diskalifiye"],"explanation":"Minnesota'nın CDL Kılavuzu, kontrollü maddelerle ilgili bir ağır suç işlemek için bir CMV kullanılırsa sürücünün CDL'sini ömür boyu kaybettiğini belirtir; bu ömür boyu yasak, olağan 10 yıllık yeniden tesise tabi değildir. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51."},"45":{"q":"Üç yıllık bir süre içinde (bir CMV kullanırken) kaç ciddi trafik ihlali Minnesota'da 60 günlük bir CDL diskalifiyesini tetikler?","options":["Bir ihlal","İki ihlal","Üç ihlal","Dört ihlal"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.3), üç yıllık bir süre içinde iki ciddi trafik ihlalinin en az 60 günlük bir diskalifiye ile sonuçlandığını belirtir. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51."},"46":{"q":"Minnesota'da, üç yıllık bir süre içinde bir CMV'de işlenen üç ciddi trafik ihlali, en az şu kadar bir CDL diskalifiyesi ile sonuçlanır:","options":["60 gün","90 gün","120 gün","Bir yıl"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.3), üç yıllık bir süre içinde üç veya daha fazla ciddi trafik ihlalinin en az 120 günlük bir diskalifiye ile sonuçlandığını belirtir. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51."},"47":{"q":"Minnesota CDL Kılavuzu'na göre, belirtilen sınırın ne kadar üzerinde hız yapmak bir 'ciddi trafik ihlali' olarak nitelendirilir?","options":["Sınırın 10 mph veya daha fazla üzerinde","Sınırın 15 mph veya daha fazla üzerinde","Sınırın 20 mph veya daha fazla üzerinde","Sınırın 25 mph veya daha fazla üzerinde"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.3), belirtilen sınırın 15 mph veya daha fazla üzerindeki aşırı hızı bir ciddi trafik ihlali olarak tanımlar. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.5."},"48":{"q":"Aşağıdakilerden hangisi Minnesota CDL Kılavuzu'nda ciddi trafik ihlali olarak listelenmemiştir?","options":["Bir aracı çok yakından takip etmek","Uygunsuz veya düzensiz şerit değişiklikleri","Tedbirsiz sürüş (reckless driving)","Park yasağı olan bir bölgede park etmek"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.3), ciddi ihlaller arasında aşırı hız (15+ mph üzeri), tedbirsiz sürüş, uygunsuz veya düzensiz şerit değişiklikleri ve çok yakından takip etmeyi sayar; bir park ihlali açıkça hariç tutulmuştur. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.3."},"49":{"q":"Minnesota'da, bir hizmet dışı (out-of-service) emrinin İLK ihlali için asgari CDL diskalifiyesi nedir?","options":["30 gün","60 gün","90 gün","Bir yıl"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.4), bir sürücünün ilk hizmet dışı emir ihlali için CDL'sini en az 90 gün kaybettiğini belirtir. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51."},"50":{"q":"Minnesota kurallarına göre, on yıllık bir süre içinde bir hizmet dışı (out-of-service) emrinin iki ihlali, en az şu kadar bir CDL diskalifiyesi ile sonuçlanır:","options":["90 gün","Bir yıl","Üç yıl","120 gün"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.4), on yıllık bir süre içinde iki hizmet dışı emir ihlalinin en az bir yıllık bir diskalifiye ile sonuçlandığını belirtir. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51."},"51":{"q":"On yıllık bir süre içinde bir hizmet dışı (out-of-service) emrinin üç veya daha fazla ihlali, en az şu kadar bir Minnesota CDL diskalifiyesi ile sonuçlanır:","options":["Bir yıl","İki yıl","Üç yıl","Beş yıl"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.4), on yıllık bir süre içinde üç veya daha fazla hizmet dışı emir ihlalinin en az üç yıllık bir diskalifiye ile sonuçlandığını belirtir. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51."},"52":{"q":"Minnesota'da, İLK demiryolu-karayolu hemzemin geçit ihlali en az şu kadar bir CDL diskalifiyesi ile sonuçlanır:","options":["30 gün","60 gün","90 gün","120 gün"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.5), ilk demiryolu-karayolu hemzemin geçit ihlalinin en az 60 günlük bir diskalifiye ile sonuçlandığını belirtir. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51."},"53":{"q":"Minnesota kurallarına göre, üç yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali en az şu kadar bir CDL diskalifiyesi ile sonuçlanır:","options":["120 gün","180 gün","Bir yıl","Üç yıl"],"explanation":"Minnesota'nın CDL Kılavuzu (Bölüm 1.3.5), birincisi için 60 gün, üç yıl içindeki ikincisi için 120 gün ve üç yıllık bir süre içindeki üçüncüsü için en az bir yıl öngörür. Kaynak: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51."},"54":{"q":"Bir Minnesota sürücüsünün CDL'sinin diskalifiye edilmesinden önce, bir CMV kullanırken el tipi (hand-held) cep telefonu kullanmaktan kaç mahkumiyeti olması gerekir?","options":["Bir mahkumiyet","İki veya daha fazla mahkumiyet","Üç veya daha fazla mahkumiyet","Beş veya daha fazla mahkumiyet"],"explanation":"Minnesota'nın CDL Kılavuzu, bir CMV kullanırken el tipi cep telefonu kullanımına ilişkin bir eyalet yasasının iki veya daha fazla mahkumiyetinden sonra bir CDL'nin diskalifiye edildiğini belirtir (3 yıl içindeki ikincisi için 60 gün, üç veya daha fazlası için 120 gün). Kaynak: Minnesota DVS CDL Manual, Sec. 2.9.4; Minn. Stat. 169.475."},"55":{"q":"CDL diskalifiyesinin ötesinde, bir Minnesota CMV sürücüsünün sürüş sırasında her el tipi telefon veya mesajlaşma ihlali için karşılaşabileceği azami hukuki ceza nedir?","options":["500 dolara kadar","1.000 dolara kadar","2.750 dolara kadar","11.000 dolara kadar"],"explanation":"Minnesota'nın CDL Kılavuzu, ilk ve sonraki her el tipi telefon veya mesajlaşma ihlalinin sürücü üzerinde 2.750 dolara kadar hukuki cezaya tabi olduğunu belirtir (buna izin veren veya bunu gerektiren işverenler 11.000 dolara kadar ceza ile karşılaşır). Kaynak: Minnesota DVS CDL Manual, Sec. 2.9.4 and 2.9.5."},"56":{"q":"Bir Minnesota CDL sahibi, ticari olmayan (kişisel) bir araçta yüzde 0,08 veya daha yüksek bir BAC ile araç kullanırken yakalanır. CDL üzerindeki etkisi nedir?","options":["Bir CMV olmadığı için hiçbir etkisi yok","En az bir yıl boyunca CMV kullanmaktan diskalifiye","60 gün diskalifiye","90 gün diskalifiye"],"explanation":"Minnesota'nın CDL Kılavuzu, ticari olmayan bir araçta yüzde 0,08 veya daha yüksek bir BAC'nin Sınıf D ayrıcalıklarını iptal ettiğini ve sürücüyü en az bir yıl boyunca CMV kullanmaktan diskalifiye ettiğini belirtir. Kaynak: Minnesota DVS CDL Manual, Revocation of Class D Privileges and Disqualification of CDL Privileges; Minn. Stat. 171.165."},"57":{"q":"Minnesota'da bir demir yolu hemzemin geçidine yaklaşırken, durmak zorunda olan bir sürücü (örneğin yolcu taşıyan bir otobüs) aracı en yakın raya ne kadar mesafe içinde durdurmalıdır?","options":["En az 15 feet ancak en fazla 50 feet","En az 10 feet ancak en fazla 25 feet","En az 25 feet ancak en fazla 75 feet","En az 5 feet ancak en fazla 15 feet"],"explanation":"Minnesota'nın CDL kılavuzu ve Minn. Stat. 169.28, demir yolu hemzemin geçitlerinde durmak zorunda olan araçların en yakın raydan 15 feet'ten az ve 50 feet'ten fazla olmamak üzere durmasını gerektirir. Kaynak: Minnesota CDL Manual (Railroad Grade Crossing); Minn. Stat. 169.28."},"58":{"q":"Minnesota'nın CDL kurallarına göre, bir tren yaklaşsa da yaklaşmasa da TÜM demir yolu hemzemin geçitlerinde hangi araç grubu durmak zorundadır?","options":["Yolcu taşıyan otobüsler, okul otobüsleri (dolu veya boş) ve plakartlı (tehlike levhalı) araçlar","Yalnızca brüt ağırlığı 26,001 pounds'un üzerindeki araçlar","Yalnızca üçlü römork kombinasyonları ve 1,000 gallon üzerindeki tankerler","Herhangi bir tür römork çeken her ticari araç"],"explanation":"Minnesota CDL kılavuzu, her demir yolu hemzemin geçidinde durmak zorunda olan araçları yolcu taşıyan otobüsler, okul otobüsleri (yolcu taşısın ya da taşımasın) ve plakartlı (tehlike levhalı) araçlar olarak sıralar. Kaynak: Minnesota CDL Manual (Railroad Grade Crossing); Minnesota'da kabul edildiği haliyle 49 CFR 392.10."},"59":{"q":"Her iki yönde trafik taşıyan iki şeritli bir Minnesota yolunda, bir okul otobüsü durdurma kolu açık ve kırmızı ışıkları yanıp sönerek durmuşken, yaklaşan bir sürücü otobüsten en az ne kadar mesafede durmalıdır?","options":["En az 20 feet uzakta","En az 10 feet uzakta","En az 30 feet uzakta","En az 50 feet uzakta"],"explanation":"Minn. Stat. 169.444, subd. 1 ve Minnesota CDL kılavuzu, durdurma kolu açık ve kırmızı ışıkları yanıp sönen duran bir okul otobüsüne yaklaşan bir sürücünün en az 20 feet uzakta durmasını ve kol geri çekilip ışıklar yanıp sönmeyi bırakana kadar durmaya devam etmesini gerektirir. Kaynak: Minn. Stat. 169.444; Minnesota CDL Manual."},"60":{"q":"Minnesota yasalarına göre, karşı tarafta yolcu indirip bindiren bir okul otobüsü için bir sürücünün durmak zorunda OLMADIĞI yol türü hangisidir?","options":["Fiziksel bir bariyer, yükseltilmiş refüj veya alçaltılmış refüjle ayrılmış, ayrı taşıt yollarına sahip bir yol","Her yönde iki veya daha fazla şeridi olan herhangi bir yol","Karşı şeritleri işaretleyen boyalı bir orta çizgiye sahip herhangi bir yol","Ortada iki yönlü sola dönüş şeridi bulunan herhangi bir yol"],"explanation":"Minn. Stat. 169.444, subd. 4, yalnızca otobüs farklı bir taşıt yolundayken ve taşıt yolları 'ayrılmış' (yani fiziksel bir bariyer, yükseltilmiş refüj veya alçaltılmış refüjle bölünmüş) olduğunda sürücüyü durmaktan muaf tutar. Boyalı bir çizgi veya orta dönüş şeridi, ayrılmış bir taşıt yolu değildir. Kaynak: Minn. Stat. 169.444, subd. 4."},"61":{"q":"Herhangi bir kentleşmiş alanın dışındaki kırsal bir Minnesota eyaletler arası otoyolunda yasal azami hız sınırı nedir?","options":["70 mph","65 mph","75 mph","60 mph"],"explanation":"Minn. Stat. 169.14, herhangi bir kentleşmiş alanın sınırları dışındaki eyaletler arası otoyollarda hız sınırını 70 mph, kentleşmiş alan içinde ise 65 mph olarak belirler. Kaynak: Minn. Stat. 169.14, subd. 2; MnDOT."},"62":{"q":"Minnesota'da, kırsal bir eyaletler arası otoyolda yüklü bir yarı römorklu kamyona, bir binek otomobile kıyasla hangi hız sınırı uygulanır?","options":["Otomobillerle aynı sınır; Minnesota kamyonlar için ayrı bir daha düşük hız sınırı belirlemez","Yayınlanan otomobil sınırının 10 mph altında","Eyalet genelinde sabit 60 mph kamyon azamisi","Yayınlanan otomobil sınırının 5 mph altında"],"explanation":"Minnesota, kamyonlar veya ticari araçlar için ayrı, daha düşük bir hız sınırı belirlemez. Minn. Stat. 169.14'teki yayınlanan yasal sınırlar tüm araçlara eşit olarak uygulanır. Kaynak: Minn. Stat. 169.14; MnDOT hız sınırı rehberi."},"63":{"q":"Minnesota'nın 'Ted Foss' Yana Geç (Move Over) yasasına göre, aynı yönde tam olarak iki şeridi olan bir yolda, yanıp sönen veya uyarı ışıkları yanan duran yetkili bir araca yaklaşan bir sürücü ne yapmalıdır?","options":["Mümkünse yetkili araçtan en uzaktaki şeride güvenli bir şekilde geçmeli","Yetkili araç ayrılana kadar tamamen durmalı","Korna çalmalı ve mevcut şeridi ile hızını korumalı","Yakından ve yavaşça geçmek için yetkili araca en yakın şeride geçmeli"],"explanation":"Minn. Stat. 169.18, subd. 11(b), aynı yönde iki şerit olduğunda bir sürücünün ışıkları yanan, duran yetkili bir araçtan en uzaktaki şeride güvenli bir şekilde geçmesini gerektirir. Kaynak: Minn. Stat. 169.18, subd. 11; Minnesota DPS (Ted Foss Move Over law)."},"64":{"q":"Minnesota'nın Yana Geç (Move Over) yasasına göre, aynı yönde İKİDEN FAZLA şeridi olan bir yolda, ışıkları yanan, duran yetkili bir aracın yanından geçerken sürücünün ne yapması gerekir?","options":["Güvenliyse, sürücü ile yetkili aracın bulunduğu şerit arasında tam bir şerit boş bırakmalı","En sağdaki şeritte tamamen durmalı","Hızı yayınlanan sınırın tam yarısına düşürmeli ancak aynı şeritte kalmalı","Yetkili aracın hemen yanındaki şeride geçmeli"],"explanation":"Minn. Stat. 169.18, subd. 11(c), aynı yönde ikiden fazla şeridi olan bir yolda sürücünün, kendisi ile yetkili aracın bulunduğu herhangi bir şerit arasında tam bir şerit boş kalacak şekilde güvenli bir şekilde geçmesini gerektirir. Kaynak: Minn. Stat. 169.18, subd. 11."},"65":{"q":"Aşağıdakilerden hangisi Minnesota'nın Yana Geç (Move Over) yasasıyla korunan 'yetkili araç' tanımına dahildir?","options":["Işıkları yanan bir çekici (vinç), kamu hizmeti şirketi aracı veya katı atık/geri dönüşüm aracı","Yalnızca işaretli kolluk kuvveti devriye arabaları","Yalnızca ambulanslar ve itfaiye araçları","Park lambaları yanan herhangi bir binek otomobil"],"explanation":"Minn. Stat. 169.18, subd. 11(a), 'yetkili araç'ı geniş bir şekilde tanımlar; buna acil durum araçları, çekiciler (vinçler), otoyol servis devriye araçları, yol bakım araçları, kamu hizmeti şirketi araçları, inşaat araçları, posta hizmeti araçları ve katı atık veya geri dönüşüm araçları dahildir. Kaynak: Minn. Stat. 169.18, subd. 11(a)."},"66":{"q":"Bir ticari araç tek yönlü veya bölünmüş bir Minnesota otoyolunda ya da yanında durmak zorunda kalırsa, sürücü üç acil durum uyarı cihazını nereye yerleştirmelidir?","options":["Yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e","Yaklaşan trafiğe doğru 25 feet, 100 feet ve 300 feet'e","Yaklaşan trafiğe doğru 10 feet, 50 feet ve 150 feet'e","Yaklaşan trafiğe doğru 15 feet, 75 feet ve 250 feet'e"],"explanation":"Minnesota CDL kılavuzu (ve 49 CFR 392.22), tek yönlü veya bölünmüş bir otoyolda üç uyarı cihazının araçtan yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e yerleştirilmesini gerektirir. Kaynak: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22."},"67":{"q":"Bir Minnesota ticari sürücüsü, bir yolda veya banketta durduktan sonra gerekli acil durum uyarı cihazlarını kaç dakika içinde yerleştirmelidir?","options":["10 dakika içinde","5 dakika içinde","15 dakika içinde","30 dakika içinde"],"explanation":"Minnesota CDL kılavuzu, bir yolda veya banketta durmak zorunda kalırsanız acil durum uyarı cihazlarınızı on dakika içinde yerleştirmeniz gerektiğini belirtir. Kaynak: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22."},"68":{"q":"Her iki yönde trafik taşıyan bölünmemiş iki şeritli bir Minnesota yolunda, duran bir ticari sürücü uyarı cihazlarını nereye yerleştirmelidir?","options":["Ön veya arka köşelerin 10 feet içine ve aracın 100 feet arkasına ve önüne","Yalnızca yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e","Yalnızca arkaya 500 feet'e tek bir cihaz","Yalnızca trafik tarafında aracın 50 feet içine"],"explanation":"Minnesota CDL kılavuzu, her iki yönde trafik taşıyan iki şeritli bir yolda (bölünmemiş bir otoyol), aracı işaretlemek için uyarı cihazlarını ön veya arka köşelerin 10 feet içine ve aracın 100 feet arkasına ve önüne yerleştirmeyi belirtir. Kaynak: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22."},"69":{"q":"Bir Minnesota ticari aracı, gerekli duran araç uyarı cihazları olarak kaç adet kırmızı yansıtıcı üçgene ihtiyaç duyar?","options":["Üç yansıtıcı üçgen (veya 6 fişek ya da 3 sıvı yanıcı işaret fişeği)","İki yansıtıcı üçgen","Dört yansıtıcı üçgen","Bir yansıtıcı üçgen artı bir bayrak"],"explanation":"Minnesota CDL kılavuzu, park edilmiş araçlar için üç yansıtıcı üçgen veya en az 6 fişek ya da 3 sıvı yanıcı işaret fişeğinden oluşan uyarı cihazlarını gerektirir. Kaynak: Minnesota CDL Manual (Warning Devices for parked vehicles); 49 CFR 393.95."},"70":{"q":"Minnesota'da, bir kamyon veya otobüs bir iş veya konut bölgesinin dışındaki bir yolda seyahat ederken, başka bir aracı ne kadar mesafeden daha yakın takip edemez?","options":["500 feet","300 feet","200 feet","100 feet"],"explanation":"Minn. Stat. 169.18, subd. 8(b), bir kamyon, otobüs veya başka bir aracı çeken aracın sürücüsünün, bir iş veya konut bölgesinin dışında seyahat ederken başka bir aracı 500 feet içinde takip etmemesini öngörür. Kaynak: Minn. Stat. 169.18, subd. 8."},"71":{"q":"Minnesota'da bir okul otobüsü sürücüsü, bir demir yolu geçidinde en yakın raydan ne kadar önce dörtlü flaşör (tehlike uyarı) ışıklarını yakmalıdır?","options":["En yakın raydan en az 100 feet önce","En yakın raydan en az 25 feet önce","En yakın raydan en az 300 feet önce","En yakın raydan en az 50 feet önce"],"explanation":"CDL kılavuzunun Minnesota Okul Otobüsü bölümü, okul otobüsü sürücüsünün en yakın raydan en az 100 feet önce, ana anahtar kapalı olarak dörtlü flaşör (tehlike uyarı) ışıklarını yakmasını gerektirir ve bir demir yolu geçidinde 8 ışıklı sistemin kullanılmasını yasaklar. Kaynak: Minnesota CDL Manual (School Bus Railroad Crossings)."},"72":{"q":"Durdurma kolu açık ve kırmızı ışıkları yanıp sönen bir okul otobüsü için durmayan bir Minnesota sürücüsü, en azından hangi suçtan suçlu bulunur?","options":["En az $500 para cezası ile cezalandırılan bir kabahat (misdemeanor)","Azami $50 para cezalı bir hafif kabahat (petty misdemeanor)","İlk suç için para cezası olmayan bir ihlal","Her durumda bir ağır suç (felony)"],"explanation":"Minn. Stat. 169.444 ve Minnesota CDL kılavuzuna göre, gerektiği gibi bir okul otobüsü için durmayan bir sürücü, en az $500 para cezası ile cezalandırılan bir kabahatten (misdemeanor) suçlu bulunur ve olası ehliyet askıya alma cezası uygulanır. Kaynak: Minn. Stat. 169.444; Minnesota CDL Manual."},"73":{"q":"Duran bir okul otobüsünü sağ (yolcu kapısı) tarafından geçmek veya yolda dışarıda bir çocuk varken geçmek, bir Minnesota sürücüsünün suçunu hangi seviyeye yükseltir?","options":["Ehliyet iptaline tabi bir ağır kabahat (gross misdemeanor)","Yalnızca puanlı basit bir trafik cezası","Bir hafif kabahat (petty misdemeanor)","Bir hukuki park ihlali"],"explanation":"Minn. Stat. 169.444 ve Minnesota CDL kılavuzu, durmamayı ve otobüsün sağ yolcu kapısı tarafından geçmeyi ya da bir okul çocuğu sokakta, otoyolda veya bitişik kaldırımda dışarıdayken geçmeyi, iptale tabi bir ağır kabahat (gross misdemeanor) haline getirir. Kaynak: Minn. Stat. 169.444; Minnesota CDL Manual."},"74":{"q":"Geçiş ücretleriyle ilgili olarak, aşağıdaki ifadelerden hangisi Minnesota'nın ticari sürücüler için eyaletler arası ve otoyol sistemini en iyi şekilde tanımlar?","options":["Minnesota'nın geleneksel paralı yolları yoktur; yalnızca Twin Cities metro bölgesinde isteğe bağlı E-ZPass MN (eski adıyla MnPASS) ekspres şeritleri bulunur","Tüm Minnesota eyaletler arası otoyolları kamyonlar için bir geçiş ücreti transponderı gerektirir","Kamyonlar her Minnesota eyaletler arası otoyolunda aks başına geçiş ücreti ödemek zorundadır","Minnesota, Indiana Toll Road gibi eyalet genelinde bir paralı yol ağı işletir"],"explanation":"Minnesota'nın geleneksel paralı yolları yoktur; tek geçiş ücreti uygulaması, Twin Cities metro bölgesinde I-394, I-35W ve I-35E üzerindeki isteğe bağlı E-ZPass Minnesota (eski adıyla MnPASS) ekspres şeritleridir ve yanında her zaman ücretsiz genel amaçlı şeritler mevcuttur. Kaynak: MnDOT; Minnesota DPS."},"75":{"q":"Ticari bir araç kullanırken tek bir demir yolu hemzemin geçidi ihlalinden hüküm giyen bir Minnesota CDL sahibi, bir CMV kullanmaktan en az ne kadar süre men edilir?","options":["60 days","30 days","120 days","1 year"],"explanation":"Minnesota CDL kılavuzu, bir sürücünün ilk demir yolu hemzemin geçidi ihlali için 60 days, herhangi bir üç yıllık dönemde iki ihlal için 120 days ve herhangi bir üç yıllık dönemde üç veya daha fazla ihlal için bir yıl süreyle men edileceğini belirtir. Kaynak: Minnesota CDL Manual (Railroad Grade Crossing Violation); 49 CFR 383.51."},"76":{"q":"Çok şeritli bir Minnesota otoyolunda, eyaletin şerit kullanım kuralı, normal trafik hızından daha yavaş seyahat eden ticari bir araçtan ne yapmasını ister?","options":["Geçiş yapma veya sola dönme dışında, sağ şeritte veya mümkün olduğunca sağ kenara yakın sürmeli","Daha hızlı trafiğin her iki dış şeridi de kullanabilmesi için her zaman orta şeritte kalmalı","Birleşen trafik için sağ şeridi açık tutmak amacıyla sol şeridi işgal etmeli","Trafik normalden yoğun olduğunda banketi kullanmalı"],"explanation":"Minn. Stat. 169.18, subd. 10, normal trafikten daha yavaş ilerleyen bir aracın, geçiş yaparken, sola dönüşe hazırlanırken veya bir şerit belirli bir kullanım için ayrılmış olduğu durumlar dışında, o sırada mevcut sağ şeritte ya da mümkün olduğunca sağ bordüre veya kenara yakın sürülmesini gerektirir. Kaynak: Minn. Stat. 169.18, subd. 10."},"77":{"q":"Minnesota'da ticari sürücü belgelerini veren ve eyalette CDL sınavlarını yürüten kurum hangisidir?","options":["Kamu Güvenliği Departmanı, Sürücü ve Araç Hizmetleri (DVS)","Minnesota Eyalet Polisi Ticari Araç Bölümü","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)","Minnesota Ulaştırma Departmanı (MnDOT)"],"explanation":"Minnesota'da CDL'ler, Kamu Güvenliği Departmanı tarafından Sürücü ve Araç Hizmetleri (DVS) birimi aracılığıyla verilir; bu birim aynı zamanda bilgi ve beceri sınavlarını da yürütür. MnDOT, lisanslamayı değil, eyalet içi tıbbi muafiyetleri ve büyük boyutlu/aşırı yüklü araç izinlerini yönetir. Kaynak: Minnesota CDL Manual, Part A (DVS, Department of Public Safety)."},"78":{"q":"Minnesota'da her CDL başvurusunda bulunan kişi, önce ticari bir araçta gözetim altında alıştırma sürüşü yapmaya olanak tanıyan hangi belgeyi almalıdır?","options":["Bir ticari öğrenci ehliyeti (CLP)","Geçici bir beceri sınavı sertifikası","Bir eğitimsel CDL muafiyeti","Bir geçici ticari onay (endorsement)"],"explanation":"Minnesota, tüm CDL başvuru sahiplerinin önce bir ticari öğrenci ehliyeti (CLP) almasını gerektirir; bu belge, alıştırma sürüşüne yalnızca araçta aynı sınıf veya daha üst sınıfta usulüne uygun ehliyetli başka bir sürücü ile izin verir. Kaynak: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"79":{"q":"Bir Minnesota ticari öğrenci ehliyeti (CLP) almak için asgari yaş nedir?","options":["18 yaşında","17 yaşında","21 yaşında","16 yaşında"],"explanation":"Bir CLP almak için en az 18 yaşında olmanız ve geçerli bir Minnesota sürücü belgesine sahip olmanız gerekir. Eyaletler arası ticarette ticari bir araç kullanmak için 21 yaşında olmanız gerekir. Kaynak: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"80":{"q":"Bir Minnesota CLP'sine başvurduktan sonra, başvuru sahibinin CDL beceri (yol) sınavına girmesine izin verilmeden önce belgeyi ne kadar süre elinde tutması gerekir?","options":["14 takvim günü","10 takvim günü","7 takvim günü","30 takvim günü"],"explanation":"Minnesota, başvuru sahibinin CDL beceri sınavına girebilmesi için CLP'nin başvuru tarihinden itibaren 14 takvim günü süreyle elinde tutulmasını gerektirir. Kaynak: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"81":{"q":"Bir Minnesota ticari öğrenci ehliyeti (CLP), veriliş tarihinden itibaren ne kadar süre geçerlidir?","options":["1 yıl","2 yıl","90 days","180 days"],"explanation":"Bir Minnesota CLP'si 180 days geçerlidir. Yenilenebilir, ancak ilk veriliş tarihinden itibaren bir yıldan fazla geçerli olamaz. Kaynak: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"82":{"q":"Minnesota CDL beceri sınavı hangi üç aşamaya ayrılır?","options":["Hava freni kontrolü, bağlama/ayırma ve otoyol sürüşü","Yazılı sınav, görme taraması ve yol sınavı","Araç muayenesi, temel kontrol becerileri ve yol sınavı","Yolculuk öncesi evrak işleri, alanda geri manevra ve bir savunmacı sürüş testi"],"explanation":"Minnesota CDL beceri sınavının üç aşaması vardır: (1) araç muayenesi (yolculuk öncesi), (2) temel kontrol becerileri sınavı ve (3) yol sınavı. Üçünün de, ehliyet almak istediğiniz araç türünde yapılması gerekir. Kaynak: Minnesota CDL Manual, Part A, Skills Tests."},"83":{"q":"Minnesota CDL araç muayenesi aşamasında, başvuru sahibi her bir madde için kredi (puan) alabilmek için ne yapmalıdır?","options":["Muayeneyi belirli bir süre sınırı içinde sessizce tamamlamalı","Kontrol sırasında bulunan yıpranmış parçaları değiştirmeli","Aracın altına girip tüm sıvı seviyelerini doğrulamalı","Her bir maddeyi işaret etmeli ve soğuk bir araçta hangi sorunlara bakılacağını açıklamalı"],"explanation":"Araç muayenesinde, başvuru sahibi her bir maddeyi muayene memuruna işaret etmeli ve soğuk bir araçta hangi sorunlara bakılacağını açıklamalı, kredi (puan) kazanmak için ana noktalardan söz etmelidir. Aracın altına girmeniz veya sıvıları kontrol etmeniz gerekmez. Kaynak: Minnesota CDL Manual, Part A, Vehicle Inspection."},"84":{"q":"Bir Minnesota CDL başvuru sahibi, her bir bilgi sınavına günde kaç kez girebilir?","options":["Günde üç kez","Günde iki kez","Günde sınırsız deneme","Günde bir kez"],"explanation":"CDL bilgi sınavı kağıt üzerinde veya bilgisayarda İngilizce olarak sunulur ve bir başvuru sahibi her bir bilgi sınavına günde yalnızca bir kez girebilir. Kaynak: Minnesota CDL Manual, Part A, Knowledge Tests."},"85":{"q":"Başlangıç Düzeyi Sürücü Eğitimi (ELDT), ilk kez Minnesota Class A/Class B başvuru sahipleri ve belirli onaylar (endorsement) için hangi tarihte zorunlu hale geldi?","options":["May 21, 2014","November 1, 2021","February 7, 2022","January 4, 2020"],"explanation":"ELDT gereklilikleri, Feb. 7, 2022 tarihinde veya sonrasında Class A veya B CDL (ya da S, P veya H onayı) alan kişiler için geçerlidir. Geçerli CLP'si bu tarihten önce verilmiş bir başvuru sahibi, CLP süresi dolmadan önce CDL'yi alırsa muaftır. Kaynak: Minnesota CDL Manual, ELDT (FMCSA Training Provider Registry)."},"86":{"q":"Minnesota'da uygulanan federal ELDT kuralına göre, eğitimin teori (sınıf) bölümünü geçmek için ne gerekir?","options":["Teori değerlendirmesinden en az %70 almak","Teori değerlendirmesinden en az %80 almak","Direksiyon başında bir simülatör değerlendirmesini geçmek","En az 30 sınıf saati tamamlamak"],"explanation":"ELDT teori eğitiminin asgari bir saat sayısı yoktur, ancak eğitim alan kişinin teori değerlendirmesinden en az %80 alması gerekir. Direksiyon başı eğitiminin asgari saati yoktur ve eğitim sağlayıcısı tarafından yeterlilik esasına göre değerlendirilir. Kaynak: Minnesota CDL Manual, ELDT (FMCSA Training Provider Registry)."},"87":{"q":"Başlangıç düzeyindeki bir sürücü, Minnesota'da ELDT'nin direksiyon başı (BTW) bölümünü alabilmeden önce, halihazırda neye sahip olmalıdır?","options":["Yalnızca bir DOT tıbbi muayene memuru sertifikası","Bir ticari öğrenci ehliyeti (CLP)","Tam, kısıtlamasız bir CDL","CDL yol sınavından geçer bir puan"],"explanation":"ELDT'nin direksiyon başı bölümü, başvuru sahibi bir CLP almadan önce alınamaz ve sınıf (teori) eğitiminden sonraki bir yıl içinde tamamlanmalıdır. Kaynak: Minnesota CDL Manual / DPS DVS CLP page."},"88":{"q":"Minnesota öz beyan (self-certification) formunda, muaf olmayan EYALETLER ARASI ticarette faaliyet gösteren bir sürücünün ayrıca güncel bir tıbbi muayene memuru sertifikası sağlamasını gerektiren kategori hangisidir?","options":["Category 4 - Muaf eyalet içi","Category 1 - Muaf olmayan eyaletler arası (49 CFR part 391'e tabi)","Category 2 - Muaf eyaletler arası","Category 3 - Muaf olmayan eyalet içi (Minnesota Statutes chapter 221'e tabi)"],"explanation":"Category 1, muaf olmayan eyaletler arası, sürücünün 49 CFR part 391'in federal DOT tıbbi gerekliliklerine tabi olduğunu ve bunları karşıladığını belgeler ve güncel bir tıbbi muayene memuru sertifikası ile varsa muafiyetlerin sağlanmasını gerektirir. Kaynak: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS)."},"89":{"q":"Hangi Minnesota öz beyan (self-certification) kategorisi, eyalet tıbbi muayene gerekliliklerine tabi olan MUAF OLMAYAN EYALET İÇİ bir sürücüyü kapsar?","options":["Category 4 - Muaf eyalet içi","Category 2 - Muaf eyaletler arası","Category 3 - Muaf olmayan eyalet içi, Minnesota Statutes chapter 221 kapsamında","Category 1 - Muaf olmayan eyaletler arası, 49 CFR part 391 kapsamında"],"explanation":"Category 3, muaf olmayan eyalet içi, Minnesota Statutes, chapter 221'in eyalet tıbbi muayene gerekliliklerine tabi olan sürücülere uygulanır; bu sürücüler ayrıca güncel bir tıbbi muayene memuru sertifikası ve varsa muafiyetler sağlamalıdır. Kaynak: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS)."},"90":{"q":"Minnesota Ticari Sürücü Belgesi Tıbbi Öz Beyan (Self-Certification) Formu kaç öz beyan kategorisi listeler?","options":["İki kategori","Dört kategori","Üç kategori","Beş kategori"],"explanation":"Minnesota öz beyan formu dört kategori listeler: muaf olmayan eyaletler arası, muaf eyaletler arası, muaf olmayan eyalet içi ve muaf eyalet içi. Dördünden ikisi (muaf olmayan kategoriler) bir tıbbi muayene memuru sertifikası gerektirir. Kaynak: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS)."},"91":{"q":"Bir Minnesota CDL sahibi, doldurulmuş öz beyan formunu ve geçerli tıbbi muayene memuru sertifikasını nereye gönderir?","options":["Kamu Güvenliği Departmanı / Sürücü ve Araç Hizmetleri (DVS)","MnDOT'un Motorlu Taşıyıcı Hizmetleri Ofisi","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)","Sertifikalı Tıbbi Muayene Memurları Ulusal Sicili"],"explanation":"Sürücüler, öz beyan formunu ve geçerli tıbbi muayene memuru sertifikasını Kamu Güvenliği Departmanı / DVS CDL Birimine (drive.mn.gov üzerinden çevrimiçi, posta, faks veya bir sürücü sınav istasyonunda şahsen) gönderir. Sertifika bilgileri daha sonra sürücü siciline işlenir. Kaynak: Minnesota CDL Manual, Medical Requirements; DPS DVS Self-Certification FAQs."},"92":{"q":"Bir Minnesota DOT tıbbi muayene memuru sertifikası genellikle en fazla ne kadar süre geçerlidir?","options":["Beş yıl","Üç yıl","En fazla iki yıl","Bir yıl"],"explanation":"Bir tıbbi muayene memuru sertifikası en fazla iki yıl geçerli olabilir, ancak muayene memuru, sürücünün tıbbi geçmişine bağlı olarak daha kısa bir süre için de düzenleyebilir. Kaynak: Minnesota CDL Manual, Medical Certificate Renewal; DPS DVS Self-Certification FAQs."},"93":{"q":"Minnesota Kamu Güvenliği Departmanı, bir tıbbi muayene memuru sertifikasının süresi dolmadan kaç gün önce sürücüye bir bildirim gönderir?","options":["45 days önce","90 days önce","60 days önce","30 days önce"],"explanation":"Kamu Güvenliği Departmanı, dosyadaki tıbbi muayene memuru sertifikası veya muafiyetin son kullanma tarihinden 60 days önce sürücünün bilinen son adresine bir bildirim gönderir. Kaynak: Minnesota CDL Manual, Medical Certificate Renewal."},"94":{"q":"Bir Minnesota CDL'si, gerekli bir tıbbi muayene memuru sertifikasını sunmadığı için derecesi düşürülürse (downgrade), sürücü hangi süre içinde yalnızca geçerli bir sertifika sunarak CDL'yi yeniden etkinleştirebilir?","options":["İki yıl içinde","6 ay içinde","30 days içinde","Bir yıl içinde"],"explanation":"Bir sürücü, öz beyan formuyla birlikte geçerli bir tıbbi muayene memuru sertifikası sunarak derecesi düşürülen bir CDL'yi ve onayları (endorsement) bir yıl içinde yeniden etkinleştirebilir. Bir yıldan uzun süre derecesi düşürülmüş veya teslim edilmişse, sürücünün ilgili bilgi ve yol sınavlarını tekrar girmesi gerekir. Kaynak: Minnesota CDL Manual, Medical Certificate Renewal; DPS DVS FAQs."},"95":{"q":"Bir Minnesota ticari sürücü belgesi, yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["İki yıl","Dört yıl","Beş yıl","Sekiz yıl"],"explanation":"Bir Minnesota CDL'si (Class A, B veya C) dört yıl geçerlidir ve ardından yenilenmesi gerekir; bu, normal bir Class D ehliyetiyle aynı döngüdür. Kaynak: DPS DVS CDL Class pages (Department of Public Safety)."}},"es":{"0":{"q":"¿Cuál es el ancho máximo legal de un vehículo comercial en las carreteras de Minnesota, sin contar los espejos ni los dispositivos de sujeción de la carga?","options":["8 pies 0 pulgadas (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies 0 pulgadas (108 pulgadas)","8 pies 4 pulgadas (100 pulgadas)"],"explanation":"El Estatuto 169.80 de Minnesota establece el ancho exterior total máximo en 102 pulgadas (8 pies 6 pulgadas). Esto coincide con la norma federal. Fuente: Minn. Stat. 169.80; MnDOT CVO."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo, cargado o sin carga, en las carreteras de Minnesota?","options":["13 pies 0 pulgadas","14 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 6 pulgadas"],"explanation":"El Estatuto 169.81 de Minnesota establece que ningún vehículo, sin carga o con carga, debe exceder una altura de 13 pies 6 pulgadas. Fuente: Minn. Stat. 169.81; Manual CDL de Minnesota."},"2":{"q":"¿Cuál es el peso bruto máximo para un vehículo o combinación de vehículos en las calles y carreteras de Minnesota sin un permiso?","options":["73,280 libras","80,000 libras","84,000 libras","88,000 libras"],"explanation":"El Estatuto 169.824 de Minnesota limita el peso bruto vehicular a 80,000 libras en todas las calles y carreteras, en concordancia con el límite federal. Fuente: Minn. Stat. 169.824; MnDOT."},"3":{"q":"Según la ley de Minnesota, ¿cuál es el peso máximo permitido sobre un solo eje en una carretera pavimentada?","options":["18,000 libras","20,000 libras","22,400 libras","34,000 libras"],"explanation":"El Estatuto 169.823 de Minnesota limita un solo eje a 20,000 libras en las calles y carreteras pavimentadas. Fuente: Minn. Stat. 169.823; MnDOT CVO Truck Book."},"4":{"q":"¿Cuál es el peso máximo permitido sobre un grupo de ejes en tándem en Minnesota?","options":["32,000 libras","36,000 libras","34,000 libras","40,000 libras"],"explanation":"Minnesota sigue el límite federal de eje en tándem de 34,000 libras, codificado en la tabla de pesos por eje del Minn. Stat. 169.824. Fuente: Minn. Stat. 169.824; Manual CDL de Minnesota."},"5":{"q":"En una carretera de Minnesota, ¿cuál es la longitud total máxima de un vehículo individual (no articulado), incluyendo la carga y los parachoques?","options":["40 pies","45 pies","48 pies","53 pies"],"explanation":"El Estatuto 169.81 de Minnesota limita un vehículo individual a 45 pies en total, incluyendo la carga y los parachoques delantero y trasero (las grúas móviles pueden alcanzar 48 pies). Fuente: Minn. Stat. 169.81."},"6":{"q":"¿Cuál es la longitud total máxima de una combinación de dos unidades (tractocamión con semirremolque) en las carreteras de Minnesota sin un permiso?","options":["65 pies","70 pies","75 pies","80 pies"],"explanation":"El Estatuto 169.81 de Minnesota establece la longitud máxima de una combinación de dos unidades de vehículos en 75 pies. Fuente: Minn. Stat. 169.81; MnDOT CVO."},"7":{"q":"Un semirremolque en una combinación de tractocamión con semirremolque en Minnesota generalmente no puede exceder qué longitud?","options":["45 pies","48 pies","53 pies","57 pies"],"explanation":"El Estatuto 169.81 de Minnesota dispone que un semirremolque generalmente no puede exceder los 48 pies, aunque se permiten hasta 53 pies cuando la distancia del pivote de enganche al eje trasero no excede los 43 pies. Fuente: Minn. Stat. 169.81."},"8":{"q":"¿Qué fórmula usa Minnesota para determinar el peso máximo permitido sobre un grupo de ejes consecutivos según el espaciamiento de los ejes y el número de ejes?","options":["La Fórmula Federal de Puentes","La fórmula de Clasificación de Combinación Bruta","El Índice de Tonelaje de Minnesota","La fórmula de Equivalencia de Carga por Eje"],"explanation":"La tabla de pesos por grupo de ejes de Minnesota en el Minn. Stat. 169.824 implementa la Fórmula Federal de Puentes, permitiendo más peso a medida que aumentan los ejes y el espaciamiento. Fuente: Minn. Stat. 169.824; Manual CDL de Minnesota."},"9":{"q":"¿Cuándo se requiere un permiso de tamaño/peso excesivo (OSOW) de MnDOT para transportar una carga en una carretera de Minnesota?","options":["Solo cuando la carga excede las 100,000 libras","Cuando el vehículo o la carga excede cualquier límite legal de tamaño o peso","Solo para cargas de más de 10 pies de ancho","Solo en carreteras interestatales"],"explanation":"Se requiere un permiso OSOW de MnDOT cada vez que un vehículo o carga excede un límite legal de tamaño o peso y va a circular por o cruzar una carretera de Minnesota. Fuente: Minn. Stat. 169.86; MnDOT CVO Oversize/Overweight Permits."},"10":{"q":"Más allá del ancho legal de 102 pulgadas, ¿cuánto pueden extenderse legalmente a cada lado en Minnesota los espejos retrovisores o los dispositivos de sujeción de la carga que no son parte integral del vehículo?","options":["Hasta 3 pulgadas a cada lado","Hasta 6 pulgadas a cada lado","No pueden extenderse en absoluto","Hasta 12 pulgadas a cada lado"],"explanation":"El Estatuto 169.80 de Minnesota permite que los espejos o dispositivos de sujeción de la carga que no son parte integral del vehículo se extiendan hasta 3 pulgadas más allá del ancho de 102 pulgadas a cada lado. Fuente: Minn. Stat. 169.80."},"11":{"q":"Durante un aumento de peso de invierno declarado por el comisionado, ¿en qué porcentaje pueden elevarse los límites estacionales de peso bruto y por eje de Minnesota en las vías elegibles?","options":["5 por ciento","10 por ciento","15 por ciento","20 por ciento"],"explanation":"El Estatuto 169.826 de Minnesota autoriza al comisionado a aumentar los límites de peso en un 10 por ciento durante el período invernal (de caminos congelados) establecido para cada zona. Fuente: Minn. Stat. 169.826; MnDOT."},"12":{"q":"¿Qué altura puede alcanzar un autobús de dos pisos que opera bajo un permiso anual en Minnesota, por encima del límite estándar de 13 pies 6 pulgadas?","options":["13 pies 9 pulgadas","14 pies 0 pulgadas","14 pies 3 pulgadas","15 pies 0 pulgadas"],"explanation":"El Estatuto 169.81 de Minnesota permite que un autobús de dos pisos alcance 14 pies 3 pulgadas de altura cuando se opera bajo un permiso anual. Fuente: Minn. Stat. 169.81."},"13":{"q":"El aumento de peso del 10 por ciento de la temporada de cosecha de Minnesota bajo el Estatuto 169.826 aplica al traslado de cuáles productos agrícolas sin procesar desde el campo hasta el primer punto de descarga?","options":["Maíz, soya y trigo","Remolacha azucarera, zanahorias y papas","Heno, paja y ensilaje","Manzanas, uvas y cebollas"],"explanation":"El Estatuto 169.826, subd. 1a, de Minnesota concede un aumento del 10 por ciento durante la temporada de cosecha para el traslado de remolacha azucarera, zanahorias y papas desde el campo de cosecha hasta la primera descarga, hasta el 30 de noviembre, con un permiso. Fuente: Minn. Stat. 169.826."},"14":{"q":"¿Cómo se obtiene más comúnmente de MnDOT un permiso de tamaño/peso excesivo y un registro de viaje?","options":["Visitando en persona la oficina del sheriff del condado","En línea a través de una cuenta web de MnDOT CVO después del pago","Enviando por correo un formulario en papel a la legislatura","Se emite automáticamente con el CDL"],"explanation":"MnDOT emite permisos OSOW anuales, estacionales o de un solo viaje en línea; el transportista crea una cuenta web de CVO y paga antes de que se emita el permiso. Fuente: MnDOT CVO Oversize/Overweight Permits."},"15":{"q":"Un semirremolque extendido en Minnesota puede alcanzar 53 pies solo si la distancia desde el pivote de enganche hasta el centro del eje más trasero no excede qué cifra?","options":["40 pies","41 pies","43 pies","46 pies"],"explanation":"El Estatuto 169.81 de Minnesota permite un semirremolque de hasta 53 pies siempre que la distancia del pivote de enganche al centro del eje trasero no exceda los 43 pies. Fuente: Minn. Stat. 169.81."},"16":{"q":"Los vehículos de seis ejes que transportan exclusivamente ganado pueden operar hasta qué peso bruto en las carreteras troncales de Minnesota (que no sean interestatales) bajo un permiso?","options":["80,000 libras","84,000 libras","88,000 libras","90,000 libras"],"explanation":"El Estatuto 169.8261/169.824 de Minnesota permite un peso bruto autorizado de hasta 88,000 libras para vehículos con seis o más ejes que transportan exclusivamente ganado en carreteras troncales que no sean interestatales. Fuente: Minn. Stat. 169.824; MnDOT CVO."},"17":{"q":"En Minnesota, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una clasificación de peso bruto combinado superior a 26,000 libras donde la unidad remolcada tiene un GVWR de más de 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"El Manual CDL de Minnesota (Parte A) define la Clase A como cualquier vehículo que remolca una unidad de más de 10,000 libras de GVWR con una clasificación de peso bruto combinado (camión más remolque) superior a 26,000 libras. Fuente: MN DVS Commercial Driver's License Manual, Parte A."},"18":{"q":"Según las reglas de Minnesota, un vehículo de una sola unidad con un GVWR superior a 26,000 libras (que no remolca nada, o que remolca una unidad de 10,000 libras o menos) requiere qué clase de CDL?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"El Manual CDL de Minnesota define la Clase B como un vehículo de una sola unidad de más de 26,000 libras de GVWR; también cubre el remolque de una unidad que no exceda las 10,000 libras. Fuente: MN DVS CDL Manual, Parte A."},"19":{"q":"En Minnesota, un CDL Clase C aplica a un vehículo de una sola unidad de 26,000 libras de GVWR o menos solo cuando el vehículo se usa para qué propósito?","options":["Cualquier vehículo usado para alquiler sin importar la carga","Transporte de materiales peligrosos que requieren rótulos, o que lleva 16 o más pasajeros","Remolque de cualquier remolque de más de 10,000 libras","Operar cualquier vehículo fuera de Minnesota"],"explanation":"El Manual CDL de Minnesota establece que la Clase C es un vehículo de una sola unidad de 26,000 libras de GVWR o menos que transporta materiales peligrosos (rotulados), pasajeros, o que es un autobús escolar, lo cual requiere el endoso correspondiente. Fuente: MN DVS CDL Manual, Parte A."},"20":{"q":"¿Qué endoso requiere Minnesota para un conductor que opera un vehículo cisterna diseñado para transportar líquidos o gases en un tanque con una capacidad nominal individual de más de 119 galones y un total agregado de 1,000 galones o más?","options":["H (Materiales Peligrosos)","T (Dobles/Triples)","N (Vehículo Cisterna)","X (Cisterna y HazMat)"],"explanation":"El Manual CDL de Minnesota define el endoso N (Vehículo Cisterna) para cualquier CMV diseñado para transportar materiales líquidos o gaseosos en un tanque con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de 1,000 galones o más. Fuente: MN DVS CDL Manual, sección de Endosos."},"21":{"q":"En Minnesota, ¿qué endoso se necesita para arrastrar remolques dobles o triples, y con qué clase de vehículo se asocia generalmente?","options":["El endoso T, generalmente para conductores de Clase A","El endoso N, generalmente para conductores de Clase B","El endoso P, generalmente para conductores de Clase C","El endoso H, generalmente para conductores de Clase A"],"explanation":"El Manual CDL de Minnesota establece que el endoso T (Dobles/Triples) se agrega a las licencias de los conductores de Clase A que deseen arrastrar remolques dobles o triples, lo cual requiere un examen especial de conocimientos. Fuente: MN DVS CDL Manual, Endosos / Dobles y Triples."},"22":{"q":"¿Cuáles dos endosos combina Minnesota en el único endoso 'X'?","options":["Pasajeros y autobús escolar","Vehículo cisterna y materiales peligrosos","Dobles/triples y vehículo cisterna","Materiales peligrosos y pasajeros"],"explanation":"El Manual CDL de Minnesota enumera el endoso X como 'Cisterna y Materiales Peligrosos', requerido para conductores de vehículos cisterna que transportan materiales/desechos peligrosos en cantidades rotuladas, quienes deben aprobar tanto el examen de conocimientos de cisterna como el de HazMat. Fuente: MN DVS CDL Manual, Endosos."},"23":{"q":"En Minnesota, ¿qué se requiere antes de que se le pueda emitir a un conductor un endoso de materiales peligrosos (H), además de aprobar el examen de conocimientos de HazMat?","options":["Un examen de habilidades de manejo en un vehículo cisterna rotulado","Una evaluación de amenaza de seguridad de la TSA que incluye toma de huellas dactilares y verificación de antecedentes","Cinco años de experiencia verificable de manejo interestatal","Un permiso separado de tamaño/peso excesivo de MnDOT"],"explanation":"El Manual CDL de Minnesota establece que la Administración de Seguridad en el Transporte (TSA) realiza una verificación de antecedentes (registros penales, de inmigración y del FBI) y requiere huellas dactilares antes de que se emita o renueve un endoso de HazMat. Fuente: MN DVS CDL Manual, Materiales Peligrosos / Verificación de Antecedentes / Huellas Dactilares."},"24":{"q":"En Minnesota, el endoso de autobús escolar (S) solo se puede agregar a un CDL cuando el conductor también posee cuál otro endoso?","options":["Vehículo cisterna (N)","Dobles/triples (T)","Pasajeros (P)","Materiales peligrosos (H)"],"explanation":"Minnesota requiere que el endoso de autobús escolar (S) esté acompañado del endoso de pasajeros (P); la definición de Clase C en el manual especifica 'autobús escolar (con endoso de pasajeros)'. Fuente: MN DVS CDL Manual, Parte A / Endosos."},"25":{"q":"Para un endoso de pasajeros (P) en un CDL Clase B en Minnesota, el examen de habilidades (de manejo) debe aprobarse en un autobús con un GVWR superior a 26,000 libras y una capacidad de pasajeros de cuántos, incluyendo al conductor?","options":["Más de 8","Más de 10","Más de 15","Más de 24"],"explanation":"El Manual CDL de Minnesota establece que para un endoso de pasajeros (o de autobús escolar), el examen de habilidades debe aprobarse en un autobús con un GVWR superior a 26,000 libras y una capacidad de pasajeros de más de 15, incluyendo al conductor. Fuente: MN DVS CDL Manual, Parte A (Clase B)."},"26":{"q":"¿Cuál es la edad mínima para solicitar un CDL de Minnesota que esté restringido al manejo comercial intraestatal (dentro de Minnesota)?","options":["16 años","18 años","19 años","21 años"],"explanation":"El Manual CDL de Minnesota indica una edad mínima de 18 años para solicitar un CDL intraestatal (por ejemplo, un vehículo individual de más de 26,000 libras de GVW o una combinación de más de 26,000 libras de GCW). Fuente: MN DVS CDL Manual, Parte A (edad mínima)."},"27":{"q":"Según las reglas de Minnesota y federales, ¿cuál es generalmente la edad mínima para operar un CMV en el comercio interestatal o para transportar materiales peligrosos que requieren rótulos?","options":["18 años","19 años","20 años","21 años"],"explanation":"El Manual CDL de Minnesota señala que para cualquier tamaño de vehículo que requiera rótulos de materiales peligrosos usted debe, en la mayoría de los casos, tener 21 años, y la operación interestatal generalmente requiere tener 21 años. Fuente: MN DVS CDL Manual, Parte A (edad mínima / interestatal)."},"28":{"q":"¿Cuál es la edad mínima para obtener un Permiso de Aprendiz Comercial (CLP) de Minnesota, y qué debe poseer ya el solicitante?","options":["16, con un permiso de aprendiz","18, con una licencia de conducir de Minnesota válida","19, con una licencia de conducir de Minnesota válida","21, con una licencia Clase D válida"],"explanation":"El Manual CDL de Minnesota establece que debe tener al menos 18 años y poseer una licencia de conducir de Minnesota válida para obtener un CLP. Fuente: MN DVS CDL Manual, Commercial Learner Permit."},"29":{"q":"En Minnesota, ¿cuánto tiempo debe poseerse un Permiso de Aprendiz Comercial (CLP) antes de que el titular pueda tomar el examen de habilidades (de manejo) del CDL?","options":["7 días calendario","10 días calendario","14 días calendario","30 días calendario"],"explanation":"El Manual CDL de Minnesota establece que el CLP debe poseerse durante 14 días calendario antes de poder tomar los exámenes de manejo del CDL, coincidiendo con el mínimo federal. Fuente: MN DVS CDL Manual, Commercial Learner Permit."},"30":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Minnesota, y cuál es el período total máximo durante el cual puede permanecer válido mediante renovación?","options":["90 días, renovable hasta 6 meses en total","180 días, renovable siempre que no sea válido por más de un año desde la emisión inicial","1 año, no renovable","2 años, renovable una vez"],"explanation":"El Manual CDL de Minnesota establece que los CLP son válidos por 180 días y pueden renovarse siempre que el CLP no sea válido por más de un año desde la fecha de emisión inicial. Fuente: MN DVS CDL Manual, Commercial Learner Permit."},"31":{"q":"Mientras practica el manejo con un CLP de Minnesota, el titular del permiso debe estar acompañado por un conductor que posea qué?","options":["Cualquier licencia de conducir Clase D de Minnesota válida","Un CDL de la misma clase y endosos o superior","Un certificado de instructor de CDL de MnDOT","Solo un CDL con endoso de HazMat"],"explanation":"El Manual CDL de Minnesota requiere que el titular del CLP esté acompañado por un conductor con licencia válida de la misma clase de licencia y endosos o superior mientras practica el manejo. Fuente: MN DVS CDL Manual, Commercial Learner Permit."},"32":{"q":"¿Cuál de las siguientes es una actividad permitida para un titular de CLP de Minnesota?","options":["Transportar materiales peligrosos con un endoso H en el CLP","Operar un CMV con remolques dobles o triples","Practicar en un vehículo cisterna vacío (purgado) para obtener el endoso de cisterna","Llevar pasajeros que paguen para ganar experiencia"],"explanation":"El Manual CDL de Minnesota permite que un titular de CLP que practica para un endoso de cisterna opere únicamente un vehículo cisterna vacío y purgado de residuos; prohíbe transportar materiales peligrosos, arrastrar remolques dobles/triples y llevar pasajeros. Fuente: MN DVS CDL Manual, restricciones del Commercial Learner Permit."},"33":{"q":"¿Qué conjunto de endosos permite Minnesota que se agregue a un Permiso de Aprendiz Comercial (CLP)?","options":["Pasajeros (P), Autobús escolar (S) y Vehículo cisterna (N)","Materiales peligrosos (H) y Vehículo cisterna (N)","Dobles/Triples (T) y Pasajeros (P)","Los seis endosos pueden agregarse a un CLP"],"explanation":"El Manual CDL de Minnesota establece que los únicos endosos que pueden agregarse a un CLP son Pasajeros (P), Autobús escolar (S) y Vehículo cisterna (N). Fuente: MN DVS CDL Manual, Endosos (nota sobre CLP)."},"34":{"q":"La Capacitación Federal para Conductores de Nivel Inicial (ELDT), requerida en Minnesota, debe completarse a través de un proveedor incluido en qué, y aplica a los solicitantes a partir de qué fecha?","options":["El Registro de Proveedores de Capacitación de la FMCSA, a partir del 7 de febrero de 2022","El Registro Nacional de Examinadores Médicos Certificados, a partir del 21 de mayo de 2014","La Lista de Capacitadores Aprobados de la TSA, a partir del 20 de marzo de 2025","La lista de la Oficina de Servicios para Transportistas Motorizados de MnDOT, a partir del 1 de enero de 2020"],"explanation":"El Manual CDL de Minnesota explica que los requisitos de ELDT aplican a las personas que obtienen un CDL de Clase A/B o un endoso S, P o H a partir del 7 de febrero de 2022, con la capacitación impartida por un proveedor del Registro de Proveedores de Capacitación de la FMCSA. Fuente: MN DVS CDL Manual, ELDT / Training Provider Registry."},"35":{"q":"Bajo la capacitación teórica de ELDT aceptada en Minnesota, ¿qué puntaje mínimo debe lograr un conductor de nivel inicial en la evaluación teórica?","options":["Al menos 70%","Al menos 75%","Al menos 80%","Al menos 90%"],"explanation":"El Manual CDL de Minnesota describe la capacitación teórica de ELDT sin un número mínimo de horas pero requiriendo un puntaje de al menos 80% en la evaluación. Fuente: MN DVS CDL Manual, ELDT (Capacitación Teórica)."},"36":{"q":"Al solicitar un CLP o CDL de Minnesota, los solicitantes deben autocertificar su estado médico. ¿Qué conjunto de documentos debe proporcionar un solicitante no exento junto con el formulario de autocertificación?","options":["Un certificado válido de examinador médico de un examinador certificado del Registro Nacional","Solo una nota de cualquier médico con licencia","Una carta de evaluación de amenaza de seguridad de la TSA","Una exención intraestatal de MnDOT en todos los casos"],"explanation":"El Manual CDL de Minnesota requiere que los solicitantes de CDL/CLP completen el Formulario de Autocertificación Médica de la Licencia de Conducir Comercial y, si están sujetos a requisitos médicos, presenten un certificado válido de examinador médico de un examinador incluido en el Registro Nacional de Examinadores Médicos Certificados. Fuente: MN DVS CDL Manual, Medical Self-Certification."},"37":{"q":"Según la ley de Minnesota, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.02 por ciento","0.04 por ciento","0.08 por ciento","0.10 por ciento"],"explanation":"El Manual CDL de Minnesota (Sección 1.3.2) establece que es ilegal operar un CMV con un BAC de 0.04 por ciento o más, la mitad del límite de 0.08 para conductores no comerciales. Fuente: Minnesota DVS Commercial Driver's License Manual, Sec. 1.3.2; Minn. Stat. 169A.20."},"38":{"q":"A un conductor de CMV en Minnesota se le hace una prueba y muestra una cantidad detectable de alcohol que está por debajo de 0.04 por ciento. ¿Qué sucede?","options":["No se toma ninguna acción porque el nivel está por debajo del límite","El conductor es puesto fuera de servicio por 24 horas","El conductor pierde el CDL por 60 días","El conductor pierde el CDL por un año"],"explanation":"Minnesota sigue la regla de que cualquier alcohol detectable por debajo de 0.04 por ciento resulta en una orden de fuera de servicio por 24 horas, mientras que 0.04 o más es una descalificación de un año. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.2; Minn. Stat. 169A.20."},"39":{"q":"Al conducir un CMV en vías públicas en Minnesota, un conductor ha consentido automáticamente a una prueba de sangre, aliento u orina. ¿Cómo se llama esta regla?","options":["La ley de consentimiento implícito","La regla de renuncia presunta","La regla de sospecha razonable","La ley de pruebas obligatorias"],"explanation":"El Manual CDL de Minnesota explica que operar un CMV en vías públicas constituye consentimiento automático a las pruebas químicas bajo la Ley de Consentimiento Implícito. Fuente: Minnesota DVS CDL Manual, sección Implied Consent Law; Minn. Stat. 169A.51."},"40":{"q":"En Minnesota, ¿cuál es el período mínimo de descalificación para la PRIMERA infracción grave de un titular de CDL (como conducir un CMV con un BAC de 0.04 o más) cuando NO se transportan materiales peligrosos rotulados?","options":["60 días","90 días","Un año","Tres años"],"explanation":"El Manual CDL de Minnesota establece que un conductor pierde el CDL por al menos un año por una primera infracción grave como un BAC de 0.04+, DUI, negativa, abandonar la escena de un accidente o usar un CMV en un delito grave. Fuente: Minnesota DVS CDL Manual, Commercial License Disqualifications / Sec. 1.3.2; 49 CFR 383.51."},"41":{"q":"Si la primera infracción grave descalificadora de un titular de CDL ocurre mientras opera un CMV rotulado para materiales peligrosos, el período mínimo de descalificación aumenta a:","options":["Un año","Dos años","Tres años","Cinco años"],"explanation":"El Manual CDL de Minnesota establece que si una primera infracción descalificadora ocurre mientras se opera un CMV rotulado para materiales peligrosos, el conductor pierde el CDL por al menos tres años en lugar de uno. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51."},"42":{"q":"¿Cuál es el período de descalificación en Minnesota para la SEGUNDA infracción grave (descalificadora) de un titular de CDL?","options":["Tres años","Diez años","De por vida","Cinco años"],"explanation":"El Manual CDL de Minnesota establece que una segunda infracción descalificadora resulta en la pérdida de los privilegios del CDL de por vida (puede solicitarse la reinstalación después de 10 años en circunstancias limitadas). Fuente: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51."},"43":{"q":"A un conductor de CMV en Minnesota se le pide legalmente que tome una prueba química y se niega. ¿Cuál es la consecuencia para el CDL?","options":["Una advertencia sin descalificación","Descalificación por 60 días","Descalificación por un año","Descalificación por 90 días"],"explanation":"El Manual CDL de Minnesota establece que negarse a someterse a una prueba química descalifica a un conductor de operar un CMV por un año, y la licencia de conducir también se revoca por un año. La negativa se trata como una infracción grave. Fuente: Minnesota DVS CDL Manual, Implied Consent Law / Sec. 1.3.2."},"44":{"q":"En Minnesota, usar un CMV para cometer un delito grave que involucre sustancias controladas (como la distribución de drogas) resulta en qué penalidad para el CDL?","options":["Una descalificación de un año","Una descalificación de tres años","Una descalificación de por vida sin reinstalación","Una descalificación de 120 días"],"explanation":"El Manual CDL de Minnesota establece que un conductor pierde el CDL de por vida si se usa un CMV para cometer un delito grave que involucre sustancias controladas; esta prohibición de por vida no está sujeta a la reinstalación habitual de 10 años. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51."},"45":{"q":"¿Cuántas infracciones graves de tránsito dentro de un período de tres años (mientras se opera un CMV) activan una descalificación del CDL de 60 días en Minnesota?","options":["Una infracción","Dos infracciones","Tres infracciones","Cuatro infracciones"],"explanation":"El Manual CDL de Minnesota (Sec. 1.3.3) establece que dos infracciones graves de tránsito dentro de un período de tres años resultan en al menos una descalificación de 60 días. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51."},"46":{"q":"En Minnesota, tres infracciones graves de tránsito cometidas en un CMV dentro de un período de tres años resultan en una descalificación del CDL de al menos:","options":["60 días","90 días","120 días","Un año"],"explanation":"El Manual CDL de Minnesota (Sec. 1.3.3) establece que tres o más infracciones graves de tránsito dentro de un período de tres años resultan en al menos una descalificación de 120 días. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51."},"47":{"q":"Según el Manual CDL de Minnesota, ¿exceder el límite señalizado por cuánto califica como una 'infracción grave de tránsito'?","options":["10 mph o más por encima del límite","15 mph o más por encima del límite","20 mph o más por encima del límite","25 mph o más por encima del límite"],"explanation":"El Manual CDL de Minnesota (Sec. 1.3.3) define el exceso de velocidad de 15 mph o más por encima del límite señalizado como una infracción grave de tránsito. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.5."},"48":{"q":"¿Cuál de las siguientes NO está listada como una infracción grave de tránsito en el Manual CDL de Minnesota?","options":["Seguir a un vehículo demasiado de cerca","Cambios de carril indebidos o erráticos","Conducción imprudente","Estacionarse en una zona de no estacionar"],"explanation":"El Manual CDL de Minnesota (Sec. 1.3.3) enumera como infracciones graves el exceso de velocidad (15+ mph por encima), la conducción imprudente, los cambios de carril indebidos o erráticos y seguir demasiado de cerca, entre otras; una infracción de estacionamiento está expresamente excluida. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.3."},"49":{"q":"En Minnesota, ¿cuál es la descalificación mínima del CDL para la PRIMERA violación de una orden de fuera de servicio por parte de un conductor?","options":["30 días","60 días","90 días","Un año"],"explanation":"El Manual CDL de Minnesota (Sec. 1.3.4) establece que un conductor pierde el CDL por al menos 90 días por una primera violación de una orden de fuera de servicio. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51."},"50":{"q":"Según las reglas de Minnesota, dos violaciones de una orden de fuera de servicio dentro de un período de diez años resultan en una descalificación del CDL de al menos:","options":["90 días","Un año","Tres años","120 días"],"explanation":"El Manual CDL de Minnesota (Sec. 1.3.4) establece que dos violaciones de orden de fuera de servicio dentro de un período de diez años resultan en al menos una descalificación de un año. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51."},"51":{"q":"Tres o más violaciones de una orden de fuera de servicio dentro de un período de diez años resultan en una descalificación del CDL de Minnesota de al menos:","options":["Un año","Dos años","Tres años","Cinco años"],"explanation":"El Manual CDL de Minnesota (Sec. 1.3.4) establece que tres o más violaciones de orden de fuera de servicio dentro de un período de diez años resultan en al menos una descalificación de tres años. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51."},"52":{"q":"En Minnesota, una PRIMERA infracción en un cruce a nivel de ferrocarril y carretera resulta en una descalificación del CDL de al menos:","options":["30 días","60 días","90 días","120 días"],"explanation":"El Manual CDL de Minnesota (Sec. 1.3.5) establece que una primera infracción en un cruce a nivel de ferrocarril y carretera resulta en al menos una descalificación de 60 días. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51."},"53":{"q":"Según las reglas de Minnesota, una TERCERA infracción en un cruce a nivel de ferrocarril y carretera dentro de un período de tres años resulta en una descalificación del CDL de al menos:","options":["120 días","180 días","Un año","Tres años"],"explanation":"El Manual CDL de Minnesota (Sec. 1.3.5) dispone 60 días para la primera, 120 días para una segunda dentro de tres años, y al menos un año para una tercera dentro de un período de tres años. Fuente: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51."},"54":{"q":"¿Cuántas condenas por usar un teléfono móvil de mano mientras opera un CMV debe tener un conductor de Minnesota antes de que se descalifique el CDL?","options":["Una condena","Dos o más condenas","Tres o más condenas","Cinco o más condenas"],"explanation":"El Manual CDL de Minnesota establece que un CDL se descalifica después de dos o más condenas de una ley estatal sobre el uso de teléfono móvil de mano mientras se opera un CMV (60 días por la segunda dentro de 3 años, 120 días por tres o más). Fuente: Minnesota DVS CDL Manual, Sec. 2.9.4; Minn. Stat. 169.475."},"55":{"q":"Más allá de la descalificación del CDL, ¿cuál es la sanción civil máxima que un conductor de CMV de Minnesota puede enfrentar por cada infracción de teléfono de mano o mensajes de texto mientras conduce?","options":["Hasta $500","Hasta $1,000","Hasta $2,750","Hasta $11,000"],"explanation":"El Manual CDL de Minnesota establece que la primera y cada infracción posterior de teléfono de mano o mensajes de texto está sujeta a sanciones civiles para el conductor de hasta $2,750 (los empleadores que lo permiten o lo exigen enfrentan sanciones de hasta $11,000). Fuente: Minnesota DVS CDL Manual, Sec. 2.9.4 y 2.9.5."},"56":{"q":"Se descubre a un titular de CDL de Minnesota conduciendo un vehículo no comercial (personal) con un BAC de 0.08 por ciento o más. ¿Cuál es el efecto sobre el CDL?","options":["Ningún efecto, ya que no era un CMV","Descalificado de conducir CMVs por al menos un año","Descalificado por 60 días","Descalificado por 90 días"],"explanation":"El Manual CDL de Minnesota establece que un BAC de 0.08 por ciento o más en un vehículo no comercial revoca los privilegios de Clase D y descalifica al conductor de operar CMVs por al menos un año. Fuente: Minnesota DVS CDL Manual, Revocation of Class D Privileges and Disqualification of CDL Privileges; Minn. Stat. 171.165."},"57":{"q":"Al acercarse a un cruce a nivel de ferrocarril en Minnesota, un conductor que está obligado a detenerse (como un autobús que transporta pasajeros) debe detener el vehículo dentro de qué distancia del riel más cercano?","options":["Al menos 15 pies pero no más de 50 pies","Al menos 10 pies pero no más de 25 pies","Al menos 25 pies pero no más de 75 pies","Al menos 5 pies pero no más de 15 pies"],"explanation":"El manual de CDL de Minnesota y la Minn. Stat. 169.28 exigen que los vehículos que deben detenerse en los cruces a nivel de ferrocarril se detengan a no menos de 15 pies y no más de 50 pies del riel más cercano. Fuente: Manual de CDL de Minnesota (Cruce a Nivel de Ferrocarril); Minn. Stat. 169.28."},"58":{"q":"Según las reglas de CDL de Minnesota, ¿qué grupo de vehículos debe detenerse en TODOS los cruces a nivel de ferrocarril, ya sea que se aproxime un tren o no?","options":["Autobuses que transportan pasajeros, autobuses escolares (con o sin pasajeros) y vehículos con placas de identificación (placards)","Solo los vehículos de más de 26,001 libras de peso bruto","Solo las combinaciones de triple remolque y los camiones cisterna de más de 1,000 galones","Cualquier vehículo comercial que remolque un tráiler de cualquier tipo"],"explanation":"El manual de CDL de Minnesota enumera los vehículos que deben detenerse en cada cruce a nivel de ferrocarril como autobuses que transportan pasajeros, autobuses escolares (lleven o no pasajeros) y vehículos con placas de identificación (placards). Fuente: Manual de CDL de Minnesota (Cruce a Nivel de Ferrocarril); 49 CFR 392.10 según fue adoptado en Minnesota."},"59":{"q":"En una carretera de dos carriles de Minnesota con tráfico en ambos sentidos, cuando un autobús escolar está detenido con su brazo de pare extendido y las luces rojas intermitentes encendidas, ¿a qué distancia mínima del autobús debe detenerse un conductor que se aproxima?","options":["Al menos a 20 pies de distancia","Al menos a 10 pies de distancia","Al menos a 30 pies de distancia","Al menos a 50 pies de distancia"],"explanation":"La Minn. Stat. 169.444, subd. 1 y el manual de CDL de Minnesota exigen que un conductor que se aproxima a un autobús escolar detenido que muestra un brazo de señal de pare extendido y luces rojas intermitentes se detenga al menos a 20 pies de distancia y permanezca detenido hasta que el brazo se retraiga y las luces dejen de parpadear. Fuente: Minn. Stat. 169.444; Manual de CDL de Minnesota."},"60":{"q":"Según la ley de Minnesota, ¿en qué tipo de vía un conductor NO está obligado a detenerse por un autobús escolar que está cargando o descargando en el lado opuesto?","options":["Una vía con calzadas separadas divididas por una barrera física, un camellón elevado o un camellón deprimido","Cualquier carretera con dos o más carriles en cada sentido","Cualquier carretera con una línea central pintada que marca los carriles opuestos","Cualquier carretera con un carril central de giro a la izquierda de doble sentido"],"explanation":"La Minn. Stat. 169.444, subd. 4 exime a un conductor de detenerse solo cuando el autobús está en una calzada distinta y las calzadas están 'separadas', es decir, divididas por una barrera física, un camellón elevado o un camellón deprimido. Una línea pintada o un carril central de giro no constituyen una calzada separada. Fuente: Minn. Stat. 169.444, subd. 4."},"61":{"q":"¿Cuál es el límite de velocidad máximo establecido por ley en una carretera interestatal rural de Minnesota fuera de cualquier área urbanizada?","options":["70 mph","65 mph","75 mph","60 mph"],"explanation":"La Minn. Stat. 169.14 fija el límite de velocidad en 70 mph en las carreteras interestatales fuera de los límites de cualquier área urbanizada, y en 65 mph dentro de un área urbanizada. Fuente: Minn. Stat. 169.14, subd. 2; MnDOT."},"62":{"q":"En Minnesota, ¿qué límite de velocidad aplica a un camión semirremolque cargado en una carretera interestatal rural en comparación con un automóvil de pasajeros?","options":["El mismo límite que los automóviles; Minnesota no establece un límite de velocidad más bajo separado para camiones","10 mph por debajo del límite señalado para automóviles","Un máximo fijo de 60 mph para camiones en todo el estado","5 mph por debajo del límite señalado para automóviles"],"explanation":"Minnesota no establece un límite de velocidad separado y más bajo para los camiones ni los vehículos comerciales. Los límites establecidos por ley y señalados en la Minn. Stat. 169.14 aplican por igual a todos los vehículos. Fuente: Minn. Stat. 169.14; orientación sobre límites de velocidad de MnDOT."},"63":{"q":"Según la ley 'Ted Foss' de Cambio de Carril (Move Over) de Minnesota, en una carretera con exactamente dos carriles en el mismo sentido, ¿qué debe hacer un conductor al acercarse a un vehículo autorizado detenido que muestra luces intermitentes o de advertencia?","options":["Cambiarse de manera segura al carril más alejado del vehículo autorizado, si es posible","Detenerse por completo hasta que el vehículo autorizado se retire","Tocar la bocina y mantener el carril y la velocidad actuales","Cambiarse al carril más cercano al vehículo autorizado para pasar de cerca y despacio"],"explanation":"La Minn. Stat. 169.18, subd. 11(b) exige que un conductor se cambie de manera segura al carril más alejado de un vehículo autorizado detenido con las luces activadas cuando hay dos carriles en el mismo sentido. Fuente: Minn. Stat. 169.18, subd. 11; Minnesota DPS (ley Ted Foss de Cambio de Carril)."},"64":{"q":"Según la ley de Cambio de Carril (Move Over) de Minnesota, en una carretera con MÁS de dos carriles en el mismo sentido, ¿qué se le exige al conductor al pasar junto a un vehículo autorizado detenido con las luces activadas?","options":["Dejar un carril completo vacío entre el conductor y el carril que ocupa el vehículo autorizado, si es seguro","Detenerse por completo en el carril del extremo derecho","Reducir la velocidad a exactamente la mitad del límite señalado pero permanecer en el mismo carril","Cambiarse al carril inmediatamente contiguo al vehículo autorizado"],"explanation":"La Minn. Stat. 169.18, subd. 11(c) exige que un conductor en una carretera con más de dos carriles en el mismo sentido se cambie de manera segura para dejar un carril completo vacío entre el conductor y cualquier carril que ocupe el vehículo autorizado. Fuente: Minn. Stat. 169.18, subd. 11."},"65":{"q":"¿Cuál de las siguientes opciones está incluida en la definición de Minnesota de un 'vehículo autorizado' protegido por la ley de Cambio de Carril (Move Over)?","options":["Una grúa de remolque, un vehículo de una empresa de servicios públicos o un vehículo de residuos sólidos/reciclaje con las luces activadas","Solo las patrullas policiales identificadas","Solo las ambulancias y los camiones de bomberos","Cualquier automóvil de pasajeros con las luces de estacionamiento encendidas"],"explanation":"La Minn. Stat. 169.18, subd. 11(a) define 'vehículo autorizado' de manera amplia para incluir vehículos de emergencia, grúas de remolque, vehículos de patrulla de servicio en autopistas, vehículos de mantenimiento de carreteras, vehículos de empresas de servicios públicos, vehículos de construcción, vehículos del servicio postal y vehículos de residuos sólidos o reciclaje. Fuente: Minn. Stat. 169.18, subd. 11(a)."},"66":{"q":"Si un vehículo comercial debe detenerse en o junto a una carretera de un solo sentido o dividida de Minnesota, ¿dónde debe colocar el conductor los tres dispositivos de advertencia de emergencia?","options":["A 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima","A 25 pies, 100 pies y 300 pies hacia el tráfico que se aproxima","A 10 pies, 50 pies y 150 pies hacia el tráfico que se aproxima","A 15 pies, 75 pies y 250 pies hacia el tráfico que se aproxima"],"explanation":"El manual de CDL de Minnesota (y la 49 CFR 392.22) exigen que en una carretera de un solo sentido o dividida los tres dispositivos de advertencia se coloquen a 10 pies, 100 pies y 200 pies del vehículo hacia el tráfico que se aproxima. Fuente: Manual de CDL de Minnesota (Comunicar Su Presencia); 49 CFR 392.22."},"67":{"q":"¿Dentro de cuántos minutos de haberse detenido en una carretera o en el acotamiento debe un conductor comercial de Minnesota colocar los dispositivos de advertencia de emergencia requeridos?","options":["Dentro de 10 minutos","Dentro de 5 minutos","Dentro de 15 minutos","Dentro de 30 minutos"],"explanation":"El manual de CDL de Minnesota establece que si debe detenerse en una carretera o en el acotamiento, debe colocar sus dispositivos de advertencia de emergencia dentro de diez minutos. Fuente: Manual de CDL de Minnesota (Comunicar Su Presencia); 49 CFR 392.22."},"68":{"q":"En una carretera de Minnesota no dividida de dos carriles con tráfico en ambos sentidos, ¿dónde debe colocar un conductor comercial detenido los dispositivos de advertencia?","options":["A no más de 10 pies de las esquinas delanteras o traseras y a 100 pies detrás y delante del vehículo","A 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima únicamente","Solo un dispositivo a 500 pies hacia la parte trasera","A no más de 50 pies del vehículo únicamente del lado del tráfico"],"explanation":"El manual de CDL de Minnesota especifica que en una carretera de dos carriles con tráfico en ambos sentidos (una carretera no dividida), se deben colocar los dispositivos de advertencia a no más de 10 pies de las esquinas delanteras o traseras para señalar el vehículo, y a 100 pies detrás y delante del vehículo. Fuente: Manual de CDL de Minnesota (Comunicar Su Presencia); 49 CFR 392.22."},"69":{"q":"¿Cuántos triángulos reflectantes rojos necesita un vehículo comercial de Minnesota como dispositivos de advertencia requeridos para vehículo detenido?","options":["Tres triángulos reflectantes (o 6 bengalas o 3 bengalas de combustible líquido)","Dos triángulos reflectantes","Cuatro triángulos reflectantes","Un triángulo reflectante más una bandera"],"explanation":"El manual de CDL de Minnesota exige dispositivos de advertencia para vehículos estacionados que consisten en tres triángulos reflectantes, o al menos 6 bengalas, o 3 bengalas de combustible líquido. Fuente: Manual de CDL de Minnesota (Dispositivos de Advertencia para vehículos estacionados); 49 CFR 393.95."},"70":{"q":"En Minnesota, cuando un camión o un autobús circula por una vía fuera de un distrito comercial o residencial, ¿a qué distancia mínima de otro vehículo no puede circular detrás de él?","options":["500 pies","300 pies","200 pies","100 pies"],"explanation":"La Minn. Stat. 169.18, subd. 8(b) dispone que el conductor de un camión de carga, un autobús o un vehículo que remolca otro vehículo no debe circular a menos de 500 pies de otro vehículo cuando viaja fuera de un distrito comercial o residencial. Fuente: Minn. Stat. 169.18, subd. 8."},"71":{"q":"Un conductor de autobús escolar en Minnesota debe activar las luces intermitentes de advertencia de cuatro direcciones ¿a qué distancia antes del riel más cercano en un cruce de ferrocarril?","options":["Al menos a 100 pies del riel más cercano","Al menos a 25 pies del riel más cercano","Al menos a 300 pies del riel más cercano","Al menos a 50 pies del riel más cercano"],"explanation":"La sección de Autobuses Escolares del manual de CDL de Minnesota exige que el conductor del autobús escolar encienda las luces intermitentes de advertencia de cuatro direcciones al menos a 100 pies del riel más cercano, con el interruptor principal apagado, y prohíbe usar el sistema de 8 luces en un cruce de ferrocarril. Fuente: Manual de CDL de Minnesota (Cruces de Ferrocarril de Autobuses Escolares)."},"72":{"q":"Un conductor de Minnesota que no se detiene ante un autobús escolar que muestra su brazo de pare extendido y luces rojas intermitentes es, como mínimo, culpable de ¿qué delito?","options":["Un delito menor (misdemeanor) sancionable con una multa de no menos de $500","Un delito menor leve (petty misdemeanor) con una multa máxima de $50","Una infracción sin multa por una primera ofensa","Un delito grave (felony) en todos los casos"],"explanation":"Según la Minn. Stat. 169.444 y el manual de CDL de Minnesota, un conductor que no se detiene ante un autobús escolar como se requiere es culpable de un delito menor (misdemeanor) sancionable con una multa de no menos de $500, con posible suspensión de la licencia. Fuente: Minn. Stat. 169.444; Manual de CDL de Minnesota."},"73":{"q":"Adelantar a un autobús escolar detenido por el lado derecho (el de la puerta de pasajeros), o adelantar cuando hay un niño afuera en la vía, eleva el delito de un conductor de Minnesota ¿a qué nivel?","options":["Un delito menor grave (gross misdemeanor) sujeto a revocación de la licencia","Una simple citación de tránsito con solo puntos","Un delito menor leve (petty misdemeanor)","Una infracción civil de estacionamiento"],"explanation":"La Minn. Stat. 169.444 y el manual de CDL de Minnesota convierten en un delito menor grave (gross misdemeanor), sujeto a revocación, el no detenerse y ya sea adelantar por el lado derecho de la puerta de pasajeros del autobús o adelantar mientras un niño escolar está afuera en la calle, carretera o acera adyacente. Fuente: Minn. Stat. 169.444; Manual de CDL de Minnesota."},"74":{"q":"En cuanto a los peajes, ¿qué afirmación describe mejor el sistema de carreteras interestatales y vías de Minnesota para los conductores comerciales?","options":["Minnesota no tiene carreteras de peaje tradicionales; solo existen los carriles exprés opcionales E-ZPass MN (antes MnPASS) en el área metropolitana de Twin Cities","Todas las carreteras interestatales de Minnesota requieren un transpondedor de peaje para los camiones","Los camiones deben pagar un peaje por eje en cada carretera interestatal de Minnesota","Minnesota opera una red de autopistas de peaje en todo el estado, como la Indiana Toll Road"],"explanation":"Minnesota no tiene carreteras de peaje tradicionales; su único cobro de peaje son los carriles exprés opcionales E-ZPass Minnesota (antes MnPASS) en la I-394, la I-35W y la I-35E en el área metropolitana de Twin Cities, con carriles de uso general gratuitos siempre disponibles al lado. Fuente: MnDOT; Minnesota DPS."},"75":{"q":"Un titular de CDL de Minnesota condenado por una sola infracción en un cruce a nivel de ferrocarril mientras operaba un vehículo comercial queda descalificado para operar un CMV por al menos ¿cuánto tiempo?","options":["60 días","30 días","120 días","1 año"],"explanation":"El manual de CDL de Minnesota establece que un conductor queda descalificado por 60 días por una primera infracción en un cruce a nivel de ferrocarril, 120 días por dos en cualquier periodo de tres años, y un año por tres o más en cualquier periodo de tres años. Fuente: Manual de CDL de Minnesota (Infracción en Cruce a Nivel de Ferrocarril); 49 CFR 383.51."},"76":{"q":"En una carretera de varios carriles de Minnesota, ¿qué le exige la regla estatal de uso de carriles a un vehículo comercial que circula más lento que la velocidad normal del tráfico?","options":["Circular por el carril derecho o lo más cerca posible del borde derecho, excepto al adelantar o al girar a la izquierda","Permanecer en el carril central en todo momento para que el tráfico más rápido pueda usar ambos carriles exteriores","Ocupar el carril izquierdo para mantener el carril derecho libre para el tráfico que se incorpora","Usar el acotamiento siempre que el tráfico sea más pesado de lo habitual"],"explanation":"La Minn. Stat. 169.18, subd. 10 exige que un vehículo que circula más lento que el tráfico normal sea conducido por el carril derecho disponible entonces, o lo más cerca posible del bordillo o borde derecho, excepto al rebasar y adelantar, al prepararse para un giro a la izquierda, o donde un carril esté designado para un uso específico. Fuente: Minn. Stat. 169.18, subd. 10."},"77":{"q":"¿Qué agencia de Minnesota emite las licencias de conducir comerciales y administra los exámenes de CDL en el estado?","options":["El Departamento de Seguridad Pública, Servicios de Conductores y Vehículos (DVS)","La Sección de Vehículos Comerciales de la Patrulla Estatal de Minnesota","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Transporte de Minnesota (MnDOT)"],"explanation":"Las CDL en Minnesota son emitidas por el Departamento de Seguridad Pública a través de su división de Servicios de Conductores y Vehículos (DVS), que también administra los exámenes de conocimientos y de habilidades. MnDOT maneja las exenciones médicas intraestatales y los permisos de sobredimensión/sobrepeso, no las licencias. Fuente: Manual de CDL de Minnesota, Parte A (DVS, Departamento de Seguridad Pública)."},"78":{"q":"En Minnesota, todo solicitante de una CDL primero debe obtener ¿qué credencial que permite practicar la conducción supervisada en un vehículo comercial?","options":["Un permiso de aprendiz comercial (CLP)","Un certificado temporal de examen de habilidades","Una exención de CDL para instrucción","Un endoso comercial provisional"],"explanation":"Minnesota exige que todos los solicitantes de una CDL primero obtengan un permiso de aprendiz comercial (CLP), que permite practicar la conducción únicamente con otro conductor debidamente licenciado de la misma clase o superior dentro del vehículo. Fuente: Manual de CDL de Minnesota, Parte A, Exámenes de Licencia de Conducir Comercial."},"79":{"q":"¿Cuál es la edad mínima para obtener un permiso de aprendiz comercial (CLP) de Minnesota?","options":["18 años de edad","17 años de edad","21 años de edad","16 años de edad"],"explanation":"Debe tener al menos 18 años de edad y poseer una licencia de conducir válida de Minnesota para obtener un CLP. Debe tener 21 años para conducir un vehículo comercial en el comercio interestatal. Fuente: Manual de CDL de Minnesota, Parte A, Exámenes de Licencia de Conducir Comercial."},"80":{"q":"Después de solicitar un CLP de Minnesota, ¿cuánto tiempo debe poseerlo el solicitante antes de que se le permita presentar el examen de habilidades (manejo en carretera) de la CDL?","options":["14 días calendario","10 días calendario","7 días calendario","30 días calendario"],"explanation":"Minnesota exige que el CLP se posea durante 14 días calendario a partir de la fecha de la solicitud antes de que el solicitante pueda presentar el examen de habilidades de la CDL. Fuente: Manual de CDL de Minnesota, Parte A, Exámenes de Licencia de Conducir Comercial."},"81":{"q":"¿Por cuánto tiempo es válido un permiso de aprendiz comercial (CLP) de Minnesota a partir de su fecha de emisión?","options":["1 año","2 años","90 días","180 días"],"explanation":"Un CLP de Minnesota es válido por 180 días. Puede renovarse, pero no puede ser válido por más de un año a partir de la fecha de emisión inicial. Fuente: Manual de CDL de Minnesota, Parte A, Exámenes de Licencia de Conducir Comercial."},"82":{"q":"El examen de habilidades de la CDL de Minnesota se divide en ¿cuáles tres fases?","options":["Revisión de frenos de aire, acoplamiento/desacoplamiento y manejo en carretera","Examen escrito, evaluación de la visión y prueba de manejo","Inspección del vehículo, habilidades de control básico y la prueba de manejo en carretera","Papeleo previo al viaje, retroceso en pista y un cuestionario de manejo defensivo"],"explanation":"El examen de habilidades de la CDL de Minnesota tiene tres fases: (1) la inspección del vehículo (previa al viaje), (2) la prueba de habilidades de control básico y (3) la prueba de manejo en carretera. Las tres deben presentarse en el tipo de vehículo para el cual desea obtener la licencia. Fuente: Manual de CDL de Minnesota, Parte A, Exámenes de Habilidades."},"83":{"q":"Durante la fase de inspección del vehículo de la CDL de Minnesota, ¿qué debe hacer el solicitante para recibir crédito por cada elemento?","options":["Completar la inspección en silencio dentro de un límite de tiempo fijo","Reemplazar cualquier pieza desgastada que se encuentre durante la revisión","Meterse debajo del vehículo y verificar todos los niveles de fluidos","Señalar cada elemento y explicar qué problemas hay que buscar en un vehículo frío"],"explanation":"En la inspección del vehículo, el solicitante debe señalar cada elemento al examinador y explicar qué problemas hay que buscar en un vehículo frío, mencionando los puntos principales para obtener crédito. No se requiere meterse debajo del vehículo ni revisar los fluidos. Fuente: Manual de CDL de Minnesota, Parte A, Inspección del Vehículo."},"84":{"q":"¿Cuántas veces al día puede un solicitante de CDL de Minnesota intentar cada examen de conocimientos individual?","options":["Tres veces al día","Dos veces al día","Intentos ilimitados al día","Una vez al día"],"explanation":"El examen de conocimientos de la CDL se ofrece en inglés en papel o por computadora, y un solicitante puede intentar cada examen de conocimientos solo una vez al día. Fuente: Manual de CDL de Minnesota, Parte A, Exámenes de Conocimientos."},"85":{"q":"La Capacitación para Conductores de Nivel Inicial (ELDT) se volvió obligatoria para los solicitantes de Clase A/Clase B por primera vez en Minnesota y para ciertos endosos en ¿qué fecha?","options":["21 de mayo de 2014","1 de noviembre de 2021","7 de febrero de 2022","4 de enero de 2020"],"explanation":"Los requisitos de ELDT aplican a las personas que obtienen una CDL de Clase A o B (o un endoso S, P o H) en o después del 7 de febrero de 2022. Un solicitante cuyo CLP válido fue emitido antes de esa fecha está exento si obtiene la CDL antes de que expire el CLP. Fuente: Manual de CDL de Minnesota, ELDT (Registro de Proveedores de Capacitación de la FMCSA)."},"86":{"q":"Según la regla federal de ELDT aplicada en Minnesota, ¿qué se requiere para aprobar la parte teórica (de aula) de la capacitación?","options":["Obtener al menos 70% en la evaluación teórica","Obtener al menos 80% en la evaluación teórica","Aprobar una evaluación en simulador de manejo","Completar un mínimo de 30 horas de aula"],"explanation":"La capacitación teórica de ELDT no tiene un número mínimo de horas, pero el aprendiz debe obtener al menos 80% en la evaluación teórica. La capacitación al volante no tiene horas mínimas y se evalúa según la competencia juzgada por el proveedor. Fuente: Manual de CDL de Minnesota, ELDT (Registro de Proveedores de Capacitación de la FMCSA)."},"87":{"q":"Antes de que un conductor de nivel inicial pueda tomar la parte al volante (BTW) de la ELDT en Minnesota, ¿qué debe poseer ya?","options":["Únicamente un certificado de examinador médico del DOT","Un permiso de aprendiz comercial (CLP)","Una CDL completa sin restricciones","Una calificación aprobatoria en la prueba de manejo en carretera de la CDL"],"explanation":"La parte al volante de la ELDT no puede tomarse antes de que el solicitante obtenga un CLP, y debe completarse dentro de un año de la capacitación de aula (teórica). Fuente: Manual de CDL de Minnesota / página de CLP del DVS del DPS."},"88":{"q":"En el formulario de autocertificación de Minnesota, ¿qué categoría exige que un conductor que opera en el comercio INTERESTATAL no exento también proporcione un certificado de examinador médico vigente?","options":["Categoría 4 - Intraestatal exento","Categoría 1 - Interestatal no exento (sujeto a 49 CFR parte 391)","Categoría 2 - Interestatal exento","Categoría 3 - Intraestatal no exento (sujeto al capítulo 221 de los Estatutos de Minnesota)"],"explanation":"La Categoría 1, interestatal no exento, certifica que el conductor está sujeto a y cumple con los requisitos médicos federales del DOT de la 49 CFR parte 391, y debe proporcionar un certificado de examinador médico vigente y cualquier exención. Fuente: Formulario/Preguntas Frecuentes de Autocertificación Médica de CDL de Minnesota (DVS del DPS)."},"89":{"q":"¿Qué categoría de autocertificación de Minnesota corresponde a un conductor INTRAESTATAL NO EXENTO que está sujeto a los requisitos estatales de examen médico?","options":["Categoría 4 - Intraestatal exento","Categoría 2 - Interestatal exento","Categoría 3 - Intraestatal no exento, conforme al capítulo 221 de los Estatutos de Minnesota","Categoría 1 - Interestatal no exento, conforme a 49 CFR parte 391"],"explanation":"La Categoría 3, intraestatal no exento, aplica a los conductores sujetos a los requisitos estatales de examen médico del capítulo 221 de los Estatutos de Minnesota, quienes también deben proporcionar un certificado de examinador médico vigente y cualquier exención. Fuente: Formulario/Preguntas Frecuentes de Autocertificación Médica de CDL de Minnesota (DVS del DPS)."},"90":{"q":"¿Cuántas categorías de autocertificación enumera el Formulario de Autocertificación Médica de la Licencia de Conducir Comercial de Minnesota?","options":["Dos categorías","Cuatro categorías","Tres categorías","Cinco categorías"],"explanation":"El formulario de autocertificación de Minnesota enumera cuatro categorías: interestatal no exento, interestatal exento, intraestatal no exento e intraestatal exento. Dos de las cuatro (las categorías no exentas) requieren un certificado de examinador médico. Fuente: Formulario/Preguntas Frecuentes de Autocertificación Médica de CDL de Minnesota (DVS del DPS)."},"91":{"q":"¿Dónde presenta un titular de CDL de Minnesota el formulario de autocertificación completo y el certificado de examinador médico válido?","options":["El Departamento de Seguridad Pública / Servicios de Conductores y Vehículos (DVS)","La Oficina de Servicios de Autotransportes de MnDOT","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Registro Nacional de Examinadores Médicos Certificados"],"explanation":"Los conductores presentan el formulario de autocertificación y el certificado de examinador médico válido ante la Unidad de CDL del Departamento de Seguridad Pública / DVS (en línea en drive.mn.gov, por correo, fax o en persona en una estación de exámenes de conductores). Luego la información del certificado se anota en el historial de manejo. Fuente: Manual de CDL de Minnesota, Requisitos Médicos; Preguntas Frecuentes de Autocertificación del DVS del DPS."},"92":{"q":"Un certificado de examinador médico del DOT de Minnesota generalmente es válido por ¿qué periodo máximo?","options":["Cinco años","Tres años","Hasta dos años","Un año"],"explanation":"Un certificado de examinador médico puede ser válido por hasta dos años, aunque el examinador puede emitirlo por un periodo más corto según el historial médico del conductor. Fuente: Manual de CDL de Minnesota, Renovación del Certificado Médico; Preguntas Frecuentes de Autocertificación del DVS del DPS."},"93":{"q":"¿Cuántos días antes de que expire un certificado de examinador médico envía el Departamento de Seguridad Pública de Minnesota un aviso al conductor?","options":["45 días antes","90 días antes","60 días antes","30 días antes"],"explanation":"El Departamento de Seguridad Pública envía un aviso a la última dirección conocida del conductor 60 días antes de la fecha de expiración del certificado de examinador médico o de la exención registrada. Fuente: Manual de CDL de Minnesota, Renovación del Certificado Médico."},"94":{"q":"Si una CDL de Minnesota es degradada por no presentar un certificado de examinador médico requerido, ¿dentro de qué periodo puede el conductor reinstaurar la CDL simplemente presentando un certificado válido?","options":["Dentro de dos años","Dentro de 6 meses","Dentro de 30 días","Dentro de un año"],"explanation":"Un conductor puede reinstaurar una CDL degradada y sus endosos dentro de un año presentando un certificado de examinador médico válido con el formulario de autocertificación. Si está degradada o entregada por más de un año, el conductor debe volver a presentar los exámenes de conocimientos y de manejo en carretera correspondientes. Fuente: Manual de CDL de Minnesota, Renovación del Certificado Médico; Preguntas Frecuentes del DVS del DPS."},"95":{"q":"¿Por cuánto tiempo es válida una licencia de conducir comercial de Minnesota antes de que deba renovarse?","options":["Dos años","Cuatro años","Cinco años","Ocho años"],"explanation":"Una CDL de Minnesota (Clase A, B o C) es válida por cuatro años y luego debe renovarse, el mismo ciclo que una licencia regular Clase D. Fuente: páginas de Clase de CDL del DVS del DPS (Departamento de Seguridad Pública)."}},"hi":{"0":{"q":"मिनेसोटा के राजमार्गों पर किसी वाणिज्यिक वाहन की अधिकतम कानूनी चौड़ाई कितनी है, जिसमें दर्पण (मिरर) और भार-बांधने वाले उपकरण शामिल नहीं हैं?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","8 feet 4 inches (100 inches)"],"explanation":"मिनेसोटा क़ानून 169.80 अधिकतम कुल बाहरी चौड़ाई 102 inches (8 feet 6 inches) निर्धारित करता है। यह संघीय मानक से मेल खाता है। स्रोत: Minn. Stat. 169.80; MnDOT CVO।"},"1":{"q":"मिनेसोटा के राजमार्गों पर किसी वाहन की, चाहे लदा हो या बिना लदा, अधिकतम कानूनी ऊँचाई कितनी है?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","14 feet 6 inches"],"explanation":"मिनेसोटा क़ानून 169.81 कहता है कि कोई भी वाहन, बिना भार के या भार के साथ, 13 feet 6 inches की ऊँचाई से अधिक नहीं होना चाहिए। स्रोत: Minn. Stat. 169.81; Minnesota CDL Manual।"},"2":{"q":"बिना परमिट के मिनेसोटा की सड़कों और राजमार्गों पर किसी वाहन या वाहनों के संयोजन का अधिकतम सकल वजन कितना है?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"मिनेसोटा क़ानून 169.824 सभी सड़कों और राजमार्गों पर सकल वाहन वजन को 80,000 pounds तक सीमित करता है, जो संघीय सीमा के अनुरूप है। स्रोत: Minn. Stat. 169.824; MnDOT।"},"3":{"q":"मिनेसोटा कानून के तहत, पक्के (पेव्ड) राजमार्ग पर एक एकल धुरी (सिंगल एक्सल) पर अधिकतम कितना वजन अनुमत है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"मिनेसोटा क़ानून 169.823 पक्की सड़कों और राजमार्गों पर एकल धुरी को 20,000 pounds तक सीमित करता है। स्रोत: Minn. Stat. 169.823; MnDOT CVO Truck Book।"},"4":{"q":"मिनेसोटा में एक टैंडम धुरी समूह (टैंडम एक्सल ग्रुप) पर अधिकतम कितना वजन अनुमत है?","options":["32,000 pounds","36,000 pounds","34,000 pounds","40,000 pounds"],"explanation":"मिनेसोटा संघीय टैंडम-धुरी सीमा 34,000 pounds का पालन करता है, जो Minn. Stat. 169.824 की धुरी-वजन अनुसूची में संहिताबद्ध है। स्रोत: Minn. Stat. 169.824; Minnesota CDL Manual।"},"5":{"q":"मिनेसोटा के राजमार्ग पर एक एकल (अ-जुड़े/नॉन-आर्टिकुलेटेड) वाहन की अधिकतम कुल लंबाई कितनी है, जिसमें भार और बंपर शामिल हैं?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"मिनेसोटा क़ानून 169.81 एक एकल वाहन को कुल मिलाकर 45 feet तक सीमित करता है, जिसमें भार और आगे व पीछे के बंपर शामिल हैं (मोबाइल क्रेन 48 feet तक पहुँच सकते हैं)। स्रोत: Minn. Stat. 169.81।"},"6":{"q":"बिना परमिट के मिनेसोटा के राजमार्गों पर एक दो-इकाई (ट्रैक्टर-सेमीट्रेलर) संयोजन की अधिकतम कुल लंबाई कितनी है?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"मिनेसोटा क़ानून 169.81 वाहनों के दो-इकाई संयोजन की अधिकतम लंबाई 75 feet निर्धारित करता है। स्रोत: Minn. Stat. 169.81; MnDOT CVO।"},"7":{"q":"मिनेसोटा में एक ट्रैक्टर-सेमीट्रेलर संयोजन में सेमीट्रेलर आम तौर पर किस लंबाई से अधिक नहीं हो सकता?","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"मिनेसोटा क़ानून 169.81 प्रावधान करता है कि एक सेमीट्रेलर आम तौर पर 48 feet से अधिक नहीं हो सकता, हालाँकि जब किंगपिन-से-पिछली-धुरी की दूरी 43 feet से अधिक न हो तो 53 feet तक अनुमत है। स्रोत: Minn. Stat. 169.81।"},"8":{"q":"मिनेसोटा लगातार धुरियों के समूह पर अधिकतम अनुमेय वजन निर्धारित करने के लिए, धुरी अंतराल और धुरियों की संख्या के आधार पर, किस सूत्र का उपयोग करता है?","options":["The Federal Bridge Formula","The Gross Combination Rating formula","The Minnesota Tonnage Index","The Axle Load Equivalency formula"],"explanation":"Minn. Stat. 169.824 में मिनेसोटा की धुरी-समूह वजन तालिका Federal Bridge Formula को लागू करती है, जो धुरियों और अंतराल बढ़ने पर अधिक वजन की अनुमति देती है। स्रोत: Minn. Stat. 169.824; Minnesota CDL Manual।"},"9":{"q":"मिनेसोटा राजमार्ग पर भार ले जाने के लिए MnDOT का ओवरसाइज़/ओवरवेट (OSOW) परमिट कब आवश्यक होता है?","options":["केवल जब भार 100,000 pounds से अधिक हो","जब वाहन या भार किसी भी कानूनी आकार या वजन सीमा से अधिक हो","केवल 10 feet से अधिक चौड़े भार के लिए","केवल इंटरस्टेट राजमार्गों पर"],"explanation":"जब भी कोई वाहन या भार किसी कानूनी आकार या वजन सीमा से अधिक हो और मिनेसोटा राजमार्ग पर या उसके पार चले, तब MnDOT OSOW परमिट आवश्यक होता है। स्रोत: Minn. Stat. 169.86; MnDOT CVO Oversize/Overweight Permits।"},"10":{"q":"102-inch की कानूनी चौड़ाई से परे, मिनेसोटा में ऐसे रियरव्यू दर्पण या भार-बांधने वाले उपकरण जो वाहन का अभिन्न हिस्सा नहीं हैं, प्रत्येक ओर कानूनी रूप से कितनी दूर तक बाहर निकल सकते हैं?","options":["प्रत्येक ओर 3 inches तक","प्रत्येक ओर 6 inches तक","वे बिल्कुल बाहर नहीं निकल सकते","प्रत्येक ओर 12 inches तक"],"explanation":"मिनेसोटा क़ानून 169.80 ऐसे दर्पण या भार-बांधने वाले उपकरण जो वाहन का अभिन्न हिस्सा नहीं हैं, को प्रत्येक ओर 102-inch की चौड़ाई से 3 inches तक बाहर निकलने की अनुमति देता है। स्रोत: Minn. Stat. 169.80।"},"11":{"q":"कमिश्नर द्वारा घोषित शीतकालीन वजन वृद्धि के दौरान, मिनेसोटा की मौसमी सकल और धुरी वजन सीमाएँ पात्र सड़कों पर कितनी बढ़ाई जा सकती हैं?","options":["5 percent","10 percent","15 percent","20 percent"],"explanation":"मिनेसोटा क़ानून 169.826 कमिश्नर को प्रत्येक ज़ोन के लिए निर्धारित शीतकालीन (जमी-सड़क) अवधि के दौरान वजन सीमाओं को 10 percent तक बढ़ाने का अधिकार देता है। स्रोत: Minn. Stat. 169.826; MnDOT।"},"12":{"q":"वार्षिक परमिट के तहत संचालित होने वाली एक डबल-डेक बस मिनेसोटा में मानक 13-foot-6-inch सीमा से ऊपर किस ऊँचाई तक पहुँच सकती है?","options":["13 feet 9 inches","14 feet 0 inches","14 feet 3 inches","15 feet 0 inches"],"explanation":"मिनेसोटा क़ानून 169.81 एक डबल-डेक बस को वार्षिक परमिट के तहत संचालित होने पर 14 feet 3 inches की ऊँचाई तक पहुँचने की अनुमति देता है। स्रोत: Minn. Stat. 169.81।"},"13":{"q":"क़ानून 169.826 के तहत मिनेसोटा की कटाई-मौसम की 10 percent वजन वृद्धि किन कच्चे कृषि उत्पादों को खेत से पहले उतारने के स्थान तक ले जाने पर लागू होती है?","options":["मक्का, सोयाबीन और गेहूँ","चुकंदर (शुगर बीट), गाजर और आलू","घास (हे), पुआल (स्ट्रॉ) और साइलेज","सेब, अंगूर और प्याज"],"explanation":"मिनेसोटा क़ानून 169.826, उप-धारा 1a, परमिट के साथ चुकंदर (शुगर बीट), गाजर और आलू को कटाई के खेत से पहले उतारने के स्थान तक, 30 नवंबर तक ले जाने के लिए कटाई-मौसम की 10 percent वृद्धि प्रदान करता है। स्रोत: Minn. Stat. 169.826।"},"14":{"q":"MnDOT से ओवरसाइज़/ओवरवेट परमिट और ट्रिप लॉग सबसे आम तौर पर कैसे प्राप्त किया जाता है?","options":["व्यक्तिगत रूप से किसी काउंटी शेरिफ के कार्यालय जाकर","भुगतान के बाद MnDOT CVO वेब अकाउंट के माध्यम से ऑनलाइन","विधानमंडल को कागज़ी फॉर्म डाक से भेजकर","CDL के साथ स्वतः जारी किया जाता है"],"explanation":"MnDOT वार्षिक, मौसमी, या एकल-यात्रा OSOW परमिट ऑनलाइन जारी करता है; वाहक एक CVO वेब अकाउंट स्थापित करता है और परमिट जारी होने से पहले भुगतान करता है। स्रोत: MnDOT CVO Oversize/Overweight Permits।"},"15":{"q":"मिनेसोटा में एक विस्तारित सेमीट्रेलर 53 feet तक केवल तभी पहुँच सकता है जब किंगपिन से सबसे पिछली धुरी के केंद्र तक की दूरी किस आँकड़े से अधिक न हो?","options":["40 feet","41 feet","43 feet","46 feet"],"explanation":"मिनेसोटा क़ानून 169.81 एक सेमीट्रेलर को 53 feet तक अनुमति देता है बशर्ते किंगपिन-से-पिछली-धुरी-केंद्र की दूरी 43 feet से अधिक न हो। स्रोत: Minn. Stat. 169.81।"},"16":{"q":"केवल पशुधन (लाइवस्टॉक) ढोने वाले छह-धुरी वाले वाहन परमिट के तहत मिनेसोटा के ट्रंक राजमार्गों (इंटरस्टेट के अलावा) पर अधिकतम कितने सकल वजन पर संचालित हो सकते हैं?","options":["80,000 pounds","84,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"मिनेसोटा क़ानून 169.8261/169.824 इंटरस्टेट के अलावा ट्रंक राजमार्गों पर केवल पशुधन ढोने वाले छह या अधिक धुरियों वाले वाहनों के लिए 88,000 pounds तक का परमिटयुक्त सकल वजन अनुमत करता है। स्रोत: Minn. Stat. 169.824; MnDOT CVO।"},"17":{"q":"मिनेसोटा में, ऐसे वाहनों के संयोजन को संचालित करने के लिए कौन-सा CDL वर्ग आवश्यक है जिसकी सकल संयोजन वजन रेटिंग 26,000 pounds से अधिक हो, जहाँ खींची जाने वाली इकाई की GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"Minnesota CDL Manual (Part A) Class A को किसी ऐसे वाहन के रूप में परिभाषित करता है जो 10,000 pounds GVWR से अधिक की इकाई खींचता हो और जिसकी सकल संयोजन वजन रेटिंग (ट्रक प्लस ट्रेलर) 26,000 pounds से अधिक हो। स्रोत: MN DVS Commercial Driver's License Manual, Part A।"},"18":{"q":"मिनेसोटा नियमों के तहत, 26,000 pounds से अधिक GVWR वाला एक एकल-इकाई वाहन (जो कुछ न खींच रहा हो, या 10,000 pounds या उससे कम की इकाई खींच रहा हो) किस CDL वर्ग की आवश्यकता रखता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"Minnesota CDL Manual Class B को एक एकल-इकाई वाहन के रूप में परिभाषित करता है जो 26,000 pounds GVWR से अधिक हो; यह 10,000 pounds से अधिक न होने वाली इकाई को खींचने को भी कवर करता है। स्रोत: MN DVS CDL Manual, Part A।"},"19":{"q":"मिनेसोटा में, 26,000 pounds GVWR या उससे कम के एकल-इकाई वाहन पर Class C CDL केवल तभी लागू होता है जब वाहन का उपयोग किस उद्देश्य के लिए किया जाता है?","options":["माल की परवाह किए बिना किराये पर उपयोग किया जाने वाला कोई भी वाहन","प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री का परिवहन, या 16 या अधिक यात्रियों को ले जाना","10,000 pounds से अधिक किसी भी ट्रेलर को खींचना","मिनेसोटा के बाहर किसी भी वाहन का संचालन"],"explanation":"Minnesota CDL Manual कहता है कि Class C एक एकल-इकाई वाहन है जो 26,000 pounds GVWR या उससे कम का हो और जो खतरनाक सामग्री (प्लेकार्डयुक्त), यात्रियों को ले जाता हो, या एक स्कूल बस हो, जिसके लिए संबंधित एंडोर्समेंट की आवश्यकता होती है। स्रोत: MN DVS CDL Manual, Part A।"},"20":{"q":"मिनेसोटा ऐसे चालक के लिए कौन-सा एंडोर्समेंट आवश्यक करता है जो ऐसे टैंक वाहन का संचालन करता है जिसे तरल या गैसों के परिवहन के लिए डिज़ाइन किया गया हो, जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक हो और कुल क्षमता 1,000 gallons या अधिक हो?","options":["H (Hazardous Materials)","T (Doubles/Triples)","N (Tank Vehicle)","X (Tanker and HazMat)"],"explanation":"Minnesota CDL Manual N (Tank Vehicle) एंडोर्समेंट को किसी भी ऐसे CMV के लिए परिभाषित करता है जिसे टैंक में तरल या गैसीय सामग्री के परिवहन के लिए डिज़ाइन किया गया हो जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक और कुल रेटेड क्षमता 1,000 gallons या अधिक हो। स्रोत: MN DVS CDL Manual, Endorsements section।"},"21":{"q":"मिनेसोटा में, डबल या ट्रिपल ट्रेलर खींचने के लिए कौन-सा एंडोर्समेंट आवश्यक है, और यह आम तौर पर किस वर्ग के वाहन से जुड़ा होता है?","options":["T एंडोर्समेंट, आम तौर पर Class A चालकों के लिए","N एंडोर्समेंट, आम तौर पर Class B चालकों के लिए","P एंडोर्समेंट, आम तौर पर Class C चालकों के लिए","H एंडोर्समेंट, आम तौर पर Class A चालकों के लिए"],"explanation":"Minnesota CDL Manual कहता है कि T (Doubles/Triples) एंडोर्समेंट उन Class A चालकों के लाइसेंस में जोड़ा जाता है जो डबल या ट्रिपल ट्रेलर खींचना चाहते हैं, जिसके लिए एक विशेष ज्ञान परीक्षा आवश्यक होती है। स्रोत: MN DVS CDL Manual, Endorsements / Doubles and Triples।"},"22":{"q":"मिनेसोटा किन दो एंडोर्समेंट को एकल 'X' एंडोर्समेंट में संयोजित करता है?","options":["यात्री और स्कूल बस","टैंक वाहन और खतरनाक सामग्री","डबल/ट्रिपल और टैंक वाहन","खतरनाक सामग्री और यात्री"],"explanation":"Minnesota CDL Manual X एंडोर्समेंट को 'Tanker and Hazardous Materials' के रूप में सूचीबद्ध करता है, जो प्लेकार्डयुक्त मात्राओं में खतरनाक सामग्री/अपशिष्ट ढोने वाले टैंक वाहनों के चालकों के लिए आवश्यक है, जिन्हें टैंक और HazMat दोनों ज्ञान परीक्षाएँ पास करनी होती हैं। स्रोत: MN DVS CDL Manual, Endorsements।"},"23":{"q":"मिनेसोटा में, HazMat ज्ञान परीक्षा पास करने के अतिरिक्त, किसी चालक को खतरनाक सामग्री (H) एंडोर्समेंट जारी किए जाने से पहले क्या आवश्यक है?","options":["प्लेकार्डयुक्त टैंक वाहन में एक रोड कौशल परीक्षा","एक TSA सुरक्षा खतरा मूल्यांकन जिसमें फिंगरप्रिंटिंग और पृष्ठभूमि जाँच शामिल हो","पाँच वर्षों का सत्यापन योग्य इंटरस्टेट ड्राइविंग अनुभव","एक अलग MnDOT ओवरसाइज़/ओवरवेट परमिट"],"explanation":"Minnesota CDL Manual कहता है कि Transportation Security Administration एक पृष्ठभूमि जाँच (आपराधिक, आव्रजन, और FBI रिकॉर्ड) करता है और HazMat एंडोर्समेंट जारी या नवीनीकृत किए जाने से पहले फिंगरप्रिंट की आवश्यकता रखता है। स्रोत: MN DVS CDL Manual, Hazardous Materials / Background Check / Fingerprints।"},"24":{"q":"मिनेसोटा में, स्कूल बस (S) एंडोर्समेंट केवल तभी CDL में जोड़ा जा सकता है जब चालक के पास निम्नलिखित में से कौन-सा अन्य एंडोर्समेंट भी हो?","options":["टैंक वाहन (N)","डबल/ट्रिपल (T)","यात्री (P)","खतरनाक सामग्री (H)"],"explanation":"मिनेसोटा आवश्यक करता है कि स्कूल बस (S) एंडोर्समेंट के साथ यात्री (P) एंडोर्समेंट हो; मैनुअल में Class C परिभाषा 'school bus (with passenger endorsement)' निर्दिष्ट करती है। स्रोत: MN DVS CDL Manual, Part A / Endorsements।"},"25":{"q":"मिनेसोटा में Class B CDL पर यात्री (P) एंडोर्समेंट के लिए, कौशल (रोड) परीक्षा ऐसी बस में पास करनी होती है जिसकी GVWR 26,000 pounds से अधिक हो और जिसकी यात्री क्षमता, चालक सहित, कितनी हो?","options":["8 से अधिक","10 से अधिक","15 से अधिक","24 से अधिक"],"explanation":"Minnesota CDL Manual कहता है कि यात्री (या स्कूल बस) एंडोर्समेंट के लिए, कौशल परीक्षा ऐसी बस में पास करनी होती है जिसकी GVWR 26,000 pounds से अधिक हो और जिसकी यात्री क्षमता, चालक सहित, 15 से अधिक हो। स्रोत: MN DVS CDL Manual, Part A (Class B)।"},"26":{"q":"इंट्रास्टेट (मिनेसोटा के भीतर) वाणिज्यिक ड्राइविंग तक सीमित मिनेसोटा CDL के लिए आवेदन करने की न्यूनतम आयु क्या है?","options":["16 वर्ष","18 वर्ष","19 वर्ष","21 वर्ष"],"explanation":"Minnesota CDL Manual इंट्रास्टेट CDL (जैसे, 26,000 lbs GVW से अधिक का एकल वाहन या 26,000 lbs GCW से अधिक का संयोजन) के लिए आवेदन करने हेतु न्यूनतम आयु 18 सूचीबद्ध करता है। स्रोत: MN DVS CDL Manual, Part A (minimum age)।"},"27":{"q":"मिनेसोटा और संघीय नियमों के तहत, इंटरस्टेट वाणिज्य में CMV संचालित करने या प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री के परिवहन के लिए आम तौर पर न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"Minnesota CDL Manual नोट करता है कि खतरनाक सामग्री प्लेकार्ड की आवश्यकता वाले किसी भी आकार के वाहन के लिए आपको ज़्यादातर मामलों में 21 होना चाहिए, और इंटरस्टेट संचालन के लिए आम तौर पर 21 वर्ष की आयु आवश्यक है। स्रोत: MN DVS CDL Manual, Part A (minimum age / interstate)।"},"28":{"q":"मिनेसोटा कमर्शियल लर्नर परमिट (CLP) प्राप्त करने की न्यूनतम आयु क्या है, और आवेदक के पास पहले से क्या होना चाहिए?","options":["16, एक लर्नर परमिट के साथ","18, एक वैध मिनेसोटा ड्राइवर लाइसेंस के साथ","19, एक वैध मिनेसोटा ड्राइवर लाइसेंस के साथ","21, एक वैध Class D लाइसेंस के साथ"],"explanation":"Minnesota CDL Manual कहता है कि CLP प्राप्त करने के लिए आपको कम से कम 18 वर्ष का होना चाहिए और एक वैध मिनेसोटा ड्राइवर लाइसेंस होना चाहिए। स्रोत: MN DVS CDL Manual, Commercial Learner Permit।"},"29":{"q":"मिनेसोटा में, CDL कौशल (रोड) परीक्षा देने से पहले एक कमर्शियल लर्नर परमिट (CLP) को कितने समय तक धारण किया जाना चाहिए?","options":["7 कैलेंडर दिन","10 कैलेंडर दिन","14 कैलेंडर दिन","30 कैलेंडर दिन"],"explanation":"Minnesota CDL Manual कहता है कि CDL रोड परीक्षाएँ देने में सक्षम होने से पहले CLP को 14 कैलेंडर दिनों तक धारण किया जाना चाहिए, जो संघीय न्यूनतम से मेल खाता है। स्रोत: MN DVS CDL Manual, Commercial Learner Permit।"},"30":{"q":"एक मिनेसोटा कमर्शियल लर्नर परमिट (CLP) कितने समय तक वैध रहता है, और नवीनीकरण के माध्यम से यह अधिकतम कुल कितनी अवधि तक वैध रह सकता है?","options":["90 दिन, कुल मिलाकर 6 महीने तक नवीकरणीय","180 दिन, नवीकरणीय बशर्ते यह प्रारंभिक जारी होने से एक वर्ष से अधिक के लिए वैध न हो","1 वर्ष, गैर-नवीकरणीय","2 वर्ष, एक बार नवीकरणीय"],"explanation":"Minnesota CDL Manual कहता है कि CLP 180 दिनों के लिए वैध होते हैं और इन्हें नवीनीकृत किया जा सकता है बशर्ते CLP प्रारंभिक जारी होने की तिथि से एक वर्ष से अधिक के लिए वैध न हो। स्रोत: MN DVS CDL Manual, Commercial Learner Permit।"},"31":{"q":"मिनेसोटा CLP के साथ अभ्यास ड्राइविंग करते समय, परमिट धारक के साथ ऐसा चालक होना चाहिए जिसके पास क्या हो?","options":["कोई भी वैध मिनेसोटा Class D ड्राइवर लाइसेंस","समान वर्ग और एंडोर्समेंट का या उससे ऊँचा एक CDL","MnDOT से एक CDL प्रशिक्षक प्रमाणपत्र","केवल एक HazMat-एंडोर्स्ड CDL"],"explanation":"Minnesota CDL Manual आवश्यक करता है कि अभ्यास ड्राइविंग करते समय CLP धारक के साथ समान वर्ग के लाइसेंस और एंडोर्समेंट या उससे ऊँचा एक वैध लाइसेंसधारी चालक हो। स्रोत: MN DVS CDL Manual, Commercial Learner Permit।"},"32":{"q":"निम्नलिखित में से कौन-सी एक मिनेसोटा CLP धारक के लिए अनुमत गतिविधि है?","options":["CLP पर H एंडोर्समेंट के साथ खतरनाक सामग्री का परिवहन","डबल या ट्रिपल ट्रेलर के साथ CMV का संचालन","टैंक एंडोर्समेंट प्राप्त करने के लिए एक खाली (शुद्ध किए गए) टैंक वाहन में अभ्यास करना","अनुभव प्राप्त करने के लिए भुगतान करने वाले यात्रियों को ले जाना"],"explanation":"Minnesota CDL Manual टैंक एंडोर्समेंट के लिए अभ्यास कर रहे CLP धारक को केवल एक खाली टैंक वाहन जो अवशेष से शुद्ध किया गया हो, संचालित करने की अनुमति देता है; यह खतरनाक सामग्री ढोने, डबल/ट्रिपल ट्रेलर खींचने, और यात्रियों को ले जाने पर रोक लगाता है। स्रोत: MN DVS CDL Manual, Commercial Learner Permit restrictions।"},"33":{"q":"मिनेसोटा एंडोर्समेंट के किस समूह को कमर्शियल लर्नर परमिट (CLP) में जोड़ने की अनुमति देता है?","options":["यात्री (P), स्कूल बस (S), और टैंक वाहन (N)","खतरनाक सामग्री (H) और टैंक वाहन (N)","डबल/ट्रिपल (T) और यात्री (P)","सभी छह एंडोर्समेंट CLP में जोड़े जा सकते हैं"],"explanation":"Minnesota CDL Manual कहता है कि CLP में जोड़े जा सकने वाले एकमात्र एंडोर्समेंट यात्री (P), स्कूल बस (S), और टैंक वाहन (N) हैं। स्रोत: MN DVS CDL Manual, Endorsements (CLP note)।"},"34":{"q":"मिनेसोटा में आवश्यक संघीय एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) किस सूची में सूचीबद्ध प्रदाता के माध्यम से पूरी की जानी चाहिए, और यह किस तिथि को या उसके बाद के आवेदकों पर लागू होती है?","options":["The FMCSA Training Provider Registry, on or after Feb. 7, 2022","The National Registry of Certified Medical Examiners, on or after May 21, 2014","The TSA Approved Trainer List, on or after March 20, 2025","The MnDOT Office of Motor Carrier Services list, on or after Jan. 1, 2020"],"explanation":"Minnesota CDL Manual समझाता है कि ELDT आवश्यकताएँ Feb. 7, 2022 को या उसके बाद Class A/B CDL या S, P, या H एंडोर्समेंट प्राप्त करने वाले व्यक्तियों पर लागू होती हैं, जिसमें प्रशिक्षण FMCSA Training Provider Registry के किसी प्रदाता द्वारा दिया जाता है। स्रोत: MN DVS CDL Manual, ELDT / Training Provider Registry।"},"35":{"q":"मिनेसोटा में स्वीकृत ELDT थ्योरी प्रशिक्षण के तहत, एक एंट्री-लेवल चालक को थ्योरी मूल्यांकन में न्यूनतम कितना स्कोर प्राप्त करना चाहिए?","options":["कम से कम 70%","कम से कम 75%","कम से कम 80%","कम से कम 90%"],"explanation":"Minnesota CDL Manual ELDT थ्योरी प्रशिक्षण का वर्णन करता है जिसमें न्यूनतम घंटों की कोई संख्या नहीं है लेकिन मूल्यांकन में कम से कम 80% का स्कोर आवश्यक है। स्रोत: MN DVS CDL Manual, ELDT (Theory Training)।"},"36":{"q":"मिनेसोटा CLP या CDL के लिए आवेदन करते समय, आवेदकों को अपनी चिकित्सा स्थिति का स्व-प्रमाणन करना होता है। एक गैर-छूट प्राप्त आवेदक को स्व-प्रमाणन फॉर्म के साथ कौन-सा दस्तावेज़ सेट प्रदान करना चाहिए?","options":["National Registry पर किसी प्रमाणित परीक्षक से एक वैध मेडिकल एग्ज़ामिनर प्रमाणपत्र","केवल किसी भी लाइसेंसधारी चिकित्सक का एक डॉक्टर का नोट","एक TSA सुरक्षा खतरा मूल्यांकन पत्र","हर मामले में एक MnDOT इंट्रास्टेट छूट (वेवर)"],"explanation":"Minnesota CDL Manual आवश्यक करता है कि CDL/CLP आवेदक Commercial Driver License Medical Self-Certification Form भरें और, यदि चिकित्सा आवश्यकताओं के अधीन हों, तो National Registry of Certified Medical Examiners पर सूचीबद्ध किसी परीक्षक से एक वैध मेडिकल एग्ज़ामिनर प्रमाणपत्र जमा करें। स्रोत: MN DVS CDL Manual, Medical Self-Certification।"},"37":{"q":"मिनेसोटा कानून के तहत, अधिकतम रक्त अल्कोहल सांद्रता (BAC) कितनी है जिस पर कोई व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) चला सकता है?","options":["0.02 percent","0.04 percent","0.08 percent","0.10 percent"],"explanation":"मिनेसोटा का CDL Manual (Section 1.3.2) कहता है कि 0.04 percent या अधिक BAC के साथ CMV चलाना अवैध है, जो गैर-वाणिज्यिक चालकों के लिए 0.08 सीमा का आधा है। स्रोत: Minnesota DVS Commercial Driver's License Manual, Sec. 1.3.2; Minn. Stat. 169A.20।"},"38":{"q":"मिनेसोटा में एक CMV चालक का परीक्षण किया जाता है और उसमें 0.04 percent से कम मात्रा में पता लगाने योग्य अल्कोहल दिखता है। क्या होता है?","options":["कोई कार्रवाई नहीं की जाती क्योंकि स्तर सीमा से नीचे है","चालक को 24 घंटे के लिए सेवा से बाहर (आउट ऑफ सर्विस) कर दिया जाता है","चालक 60 दिनों के लिए CDL खो देता है","चालक एक वर्ष के लिए CDL खो देता है"],"explanation":"मिनेसोटा इस नियम का पालन करता है कि 0.04 percent से कम कोई भी पता लगाने योग्य अल्कोहल 24-घंटे के आउट-ऑफ-सर्विस आदेश में परिणत होता है, जबकि 0.04 या अधिक एक-वर्ष की अयोग्यता है। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.2; Minn. Stat. 169A.20।"},"39":{"q":"मिनेसोटा में सार्वजनिक सड़कों पर एक CMV चलाकर, एक चालक स्वतः ही रक्त, साँस, या मूत्र के परीक्षण के लिए सहमति दे चुका होता है। इस नियम को क्या कहा जाता है?","options":["निहित सहमति (इम्प्लाइड कंसेंट) कानून","अनुमानित छूट (वेवर) नियम","उचित संदेह नियम","अनिवार्य परीक्षण अधिनियम"],"explanation":"मिनेसोटा का CDL Manual समझाता है कि सार्वजनिक सड़कों पर एक CMV का संचालन Implied Consent Law के तहत रासायनिक परीक्षण के लिए स्वतः सहमति माना जाता है। स्रोत: Minnesota DVS CDL Manual, Implied Consent Law section; Minn. Stat. 169A.51।"},"40":{"q":"मिनेसोटा में, जब प्लेकार्डयुक्त खतरनाक सामग्री का परिवहन नहीं हो रहा हो, तब किसी CDL धारक के पहले गंभीर अपराध (जैसे 0.04 या अधिक BAC के साथ CMV चलाना) के लिए न्यूनतम अयोग्यता अवधि क्या है?","options":["60 days","90 days","एक वर्ष","तीन वर्ष"],"explanation":"मिनेसोटा का CDL Manual कहता है कि पहले गंभीर अपराध जैसे 0.04+ BAC, DUI, इनकार, दुर्घटना स्थल छोड़ना, या किसी अपराध (फेलनी) में CMV का उपयोग करने के लिए चालक कम से कम एक वर्ष के लिए CDL खो देता है। स्रोत: Minnesota DVS CDL Manual, Commercial License Disqualifications / Sec. 1.3.2; 49 CFR 383.51।"},"41":{"q":"यदि किसी CDL धारक का पहला अयोग्यता-कारक गंभीर अपराध ऐसे CMV का संचालन करते समय होता है जो खतरनाक सामग्री के लिए प्लेकार्डयुक्त है, तो न्यूनतम अयोग्यता अवधि बढ़कर हो जाती है:","options":["एक वर्ष","दो वर्ष","तीन वर्ष","पाँच वर्ष"],"explanation":"मिनेसोटा का CDL Manual कहता है कि यदि कोई पहला अयोग्यता-कारक अपराध खतरनाक सामग्री के लिए प्लेकार्डयुक्त CMV का संचालन करते समय होता है, तो चालक एक के बजाय कम से कम तीन वर्ष के लिए CDL खो देता है। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51।"},"42":{"q":"मिनेसोटा में किसी CDL धारक के दूसरे गंभीर (अयोग्यता-कारक) अपराध के लिए अयोग्यता अवधि क्या है?","options":["तीन वर्ष","दस वर्ष","आजीवन","पाँच वर्ष"],"explanation":"मिनेसोटा का CDL Manual कहता है कि दूसरा अयोग्यता-कारक अपराध आजीवन CDL विशेषाधिकार खोने में परिणत होता है (सीमित परिस्थितियों में 10 वर्षों के बाद पुनर्बहाली का अनुरोध किया जा सकता है)। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51।"},"43":{"q":"एक मिनेसोटा CMV चालक से कानूनी रूप से रासायनिक परीक्षण कराने को कहा जाता है और वह इनकार कर देता है। CDL के लिए इसका क्या परिणाम होता है?","options":["बिना किसी अयोग्यता के एक चेतावनी","60 दिनों के लिए अयोग्यता","एक वर्ष के लिए अयोग्यता","90 दिनों के लिए अयोग्यता"],"explanation":"मिनेसोटा का CDL Manual कहता है कि रासायनिक परीक्षण कराने से इनकार करना चालक को एक वर्ष के लिए CMV संचालित करने से अयोग्य कर देता है, और चालक का लाइसेंस भी एक वर्ष के लिए निरस्त कर दिया जाता है। इनकार को एक गंभीर अपराध माना जाता है। स्रोत: Minnesota DVS CDL Manual, Implied Consent Law / Sec. 1.3.2।"},"44":{"q":"मिनेसोटा में, नियंत्रित पदार्थों से जुड़े किसी अपराध (फेलनी) को करने के लिए CMV का उपयोग (जैसे ड्रग वितरण) करने पर CDL के लिए क्या दंड होता है?","options":["एक-वर्ष की अयोग्यता","तीन-वर्ष की अयोग्यता","बिना पुनर्बहाली के आजीवन अयोग्यता","120-दिन की अयोग्यता"],"explanation":"मिनेसोटा का CDL Manual कहता है कि यदि नियंत्रित पदार्थों से जुड़े किसी अपराध को करने के लिए CMV का उपयोग किया जाता है तो चालक आजीवन CDL खो देता है; यह आजीवन प्रतिबंध सामान्य 10-वर्ष की पुनर्बहाली के अधीन नहीं है। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.2; 49 CFR 383.51।"},"45":{"q":"मिनेसोटा में तीन-वर्ष की अवधि के भीतर (CMV संचालित करते समय) कितने गंभीर यातायात उल्लंघन 60-दिन की CDL अयोग्यता को सक्रिय करते हैं?","options":["एक उल्लंघन","दो उल्लंघन","तीन उल्लंघन","चार उल्लंघन"],"explanation":"मिनेसोटा का CDL Manual (Sec. 1.3.3) कहता है कि तीन-वर्ष की अवधि के भीतर दो गंभीर यातायात उल्लंघन कम से कम 60-दिन की अयोग्यता में परिणत होते हैं। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51।"},"46":{"q":"मिनेसोटा में, तीन-वर्ष की अवधि के भीतर किसी CMV में किए गए तीन गंभीर यातायात उल्लंघन कम से कम कितनी CDL अयोग्यता में परिणत होते हैं:","options":["60 days","90 days","120 days","एक वर्ष"],"explanation":"मिनेसोटा का CDL Manual (Sec. 1.3.3) कहता है कि तीन-वर्ष की अवधि के भीतर तीन या अधिक गंभीर यातायात उल्लंघन कम से कम 120-दिन की अयोग्यता में परिणत होते हैं। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.51।"},"47":{"q":"Minnesota CDL Manual के अनुसार, निर्धारित सीमा से कितना ऊपर गति करना एक 'गंभीर यातायात उल्लंघन' के रूप में योग्य होता है?","options":["सीमा से 10 mph या अधिक","सीमा से 15 mph या अधिक","सीमा से 20 mph या अधिक","सीमा से 25 mph या अधिक"],"explanation":"मिनेसोटा का CDL Manual (Sec. 1.3.3) निर्धारित सीमा से 15 mph या अधिक की अत्यधिक गति को एक गंभीर यातायात उल्लंघन के रूप में परिभाषित करता है। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.3; 49 CFR 383.5।"},"48":{"q":"निम्नलिखित में से कौन-सा Minnesota CDL Manual में एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध नहीं है?","options":["किसी वाहन के बहुत करीब चलना (फॉलोइंग टू क्लोज़ली)","अनुचित या अनियमित लेन परिवर्तन","लापरवाह ड्राइविंग (रेकलेस ड्राइविंग)","नो-पार्किंग ज़ोन में पार्किंग"],"explanation":"मिनेसोटा का CDL Manual (Sec. 1.3.3) गंभीर उल्लंघनों में अत्यधिक गति (15+ mph ऊपर), लापरवाह ड्राइविंग, अनुचित या अनियमित लेन परिवर्तन, और बहुत करीब चलना, अन्य के बीच, सूचीबद्ध करता है; एक पार्किंग उल्लंघन स्पष्ट रूप से बाहर रखा गया है। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.3।"},"49":{"q":"मिनेसोटा में, किसी चालक के आउट-ऑफ-सर्विस आदेश के पहले उल्लंघन के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["30 days","60 days","90 days","एक वर्ष"],"explanation":"मिनेसोटा का CDL Manual (Sec. 1.3.4) कहता है कि पहले आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए चालक कम से कम 90 दिनों के लिए CDL खो देता है। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51।"},"50":{"q":"मिनेसोटा नियमों के तहत, दस-वर्ष की अवधि के भीतर किसी आउट-ऑफ-सर्विस आदेश के दो उल्लंघन कम से कम कितनी CDL अयोग्यता में परिणत होते हैं:","options":["90 days","एक वर्ष","तीन वर्ष","120 days"],"explanation":"मिनेसोटा का CDL Manual (Sec. 1.3.4) कहता है कि दस-वर्ष की अवधि के भीतर दो आउट-ऑफ-सर्विस आदेश उल्लंघन कम से कम एक-वर्ष की अयोग्यता में परिणत होते हैं। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51।"},"51":{"q":"दस-वर्ष की अवधि के भीतर किसी आउट-ऑफ-सर्विस आदेश के तीन या अधिक उल्लंघन कम से कम कितनी मिनेसोटा CDL अयोग्यता में परिणत होते हैं:","options":["एक वर्ष","दो वर्ष","तीन वर्ष","पाँच वर्ष"],"explanation":"मिनेसोटा का CDL Manual (Sec. 1.3.4) कहता है कि दस-वर्ष की अवधि के भीतर तीन या अधिक आउट-ऑफ-सर्विस आदेश उल्लंघन कम से कम तीन-वर्ष की अयोग्यता में परिणत होते हैं। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.4; 49 CFR 383.51।"},"52":{"q":"मिनेसोटा में, एक पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कम से कम कितनी CDL अयोग्यता में परिणत होता है:","options":["30 days","60 days","90 days","120 days"],"explanation":"मिनेसोटा का CDL Manual (Sec. 1.3.5) कहता है कि एक पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कम से कम 60-दिन की अयोग्यता में परिणत होता है। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51।"},"53":{"q":"मिनेसोटा नियमों के तहत, तीन-वर्ष की अवधि के भीतर एक तीसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कम से कम कितनी CDL अयोग्यता में परिणत होता है:","options":["120 days","180 days","एक वर्ष","तीन वर्ष"],"explanation":"मिनेसोटा का CDL Manual (Sec. 1.3.5) पहले के लिए 60 दिन, तीन वर्षों के भीतर दूसरे के लिए 120 दिन, और तीन-वर्ष की अवधि के भीतर तीसरे के लिए कम से कम एक वर्ष प्रदान करता है। स्रोत: Minnesota DVS CDL Manual, Sec. 1.3.5; 49 CFR 383.51।"},"54":{"q":"एक मिनेसोटा चालक को CDL अयोग्य होने से पहले CMV संचालित करते समय हैंड-हेल्ड मोबाइल फोन का उपयोग करने के लिए कितनी दोषसिद्धियाँ (कन्विक्शन) होनी चाहिए?","options":["एक दोषसिद्धि","दो या अधिक दोषसिद्धियाँ","तीन या अधिक दोषसिद्धियाँ","पाँच या अधिक दोषसिद्धियाँ"],"explanation":"मिनेसोटा का CDL Manual कहता है कि CMV संचालित करते समय हैंड-हेल्ड मोबाइल फोन उपयोग पर राज्य कानून की दो या अधिक दोषसिद्धियों के बाद CDL अयोग्य हो जाता है (3 वर्षों के भीतर दूसरे के लिए 60 दिन, तीन या अधिक के लिए 120 दिन)। स्रोत: Minnesota DVS CDL Manual, Sec. 2.9.4; Minn. Stat. 169.475।"},"55":{"q":"CDL अयोग्यता के अलावा, एक मिनेसोटा CMV चालक को ड्राइविंग करते समय प्रत्येक हैंड-हेल्ड फोन या टेक्स्टिंग उल्लंघन के लिए अधिकतम कितना दीवानी दंड (सिविल पेनल्टी) झेलना पड़ सकता है?","options":["$500 तक","$1,000 तक","$2,750 तक","$11,000 तक"],"explanation":"मिनेसोटा का CDL Manual कहता है कि पहला और प्रत्येक बाद का हैंड-हेल्ड फोन या टेक्स्टिंग उल्लंघन चालक पर $2,750 तक के दीवानी दंड के अधीन है (जो नियोक्ता इसकी अनुमति देते हैं या इसकी मांग करते हैं उन्हें $11,000 तक के दंड का सामना करना पड़ता है)। स्रोत: Minnesota DVS CDL Manual, Sec. 2.9.4 and 2.9.5।"},"56":{"q":"एक मिनेसोटा CDL धारक को 0.08 percent या अधिक BAC के साथ एक गैर-वाणिज्यिक (निजी) वाहन चलाते हुए पाया जाता है। CDL पर इसका क्या प्रभाव होता है?","options":["कोई प्रभाव नहीं, क्योंकि यह एक CMV नहीं था","कम से कम एक वर्ष के लिए CMV चलाने से अयोग्य","60 दिनों के लिए अयोग्य","90 दिनों के लिए अयोग्य"],"explanation":"मिनेसोटा का CDL Manual कहता है कि एक गैर-वाणिज्यिक वाहन में 0.08 percent या अधिक BAC Class D विशेषाधिकार निरस्त कर देता है और चालक को कम से कम एक वर्ष के लिए CMV संचालित करने से अयोग्य कर देता है। स्रोत: Minnesota DVS CDL Manual, Revocation of Class D Privileges and Disqualification of CDL Privileges; Minn. Stat. 171.165।"},"57":{"q":"मिनेसोटा में किसी रेलरोड ग्रेड क्रॉसिंग के पास पहुँचते समय, जिस चालक को रुकना आवश्यक है (जैसे यात्रियों को ले जाने वाली बस), उसे वाहन को निकटतम रेल से कितनी दूरी के भीतर रोकना चाहिए?","options":["कम से कम 15 feet लेकिन 50 feet से अधिक नहीं","कम से कम 10 feet लेकिन 25 feet से अधिक नहीं","कम से कम 25 feet लेकिन 75 feet से अधिक नहीं","कम से कम 5 feet लेकिन 15 feet से अधिक नहीं"],"explanation":"मिनेसोटा का CDL मैनुअल और Minn. Stat. 169.28 के अनुसार जिन वाहनों को रेलरोड ग्रेड क्रॉसिंग पर रुकना आवश्यक है, उन्हें निकटतम रेल से 15 feet से कम नहीं और 50 feet से अधिक नहीं की दूरी पर रुकना चाहिए। स्रोत: Minnesota CDL Manual (Railroad Grade Crossing); Minn. Stat. 169.28."},"58":{"q":"मिनेसोटा के CDL नियमों के तहत, वाहनों के किस समूह को सभी रेलरोड ग्रेड क्रॉसिंग पर रुकना आवश्यक है, चाहे ट्रेन आ रही हो या नहीं?","options":["यात्रियों को ले जाने वाली बसें, स्कूल बसें (भरी हुई हों या नहीं), और प्लेकार्ड वाले वाहन","केवल 26,001 pounds सकल वजन से अधिक के वाहन","केवल ट्रिपल-ट्रेलर संयोजन और 1,000 gallons से अधिक के टैंकर","किसी भी प्रकार का ट्रेलर खींचने वाला कोई भी वाणिज्यिक वाहन"],"explanation":"मिनेसोटा CDL मैनुअल उन वाहनों को सूचीबद्ध करता है जिन्हें हर रेलरोड ग्रेड क्रॉसिंग पर रुकना आवश्यक है: यात्रियों को ले जाने वाली बसें, स्कूल बसें (चाहे यात्रियों को ले जा रही हों या नहीं), और प्लेकार्ड वाले वाहन। स्रोत: Minnesota CDL Manual (Railroad Grade Crossing); मिनेसोटा में अपनाए गए 49 CFR 392.10."},"59":{"q":"दोनों दिशाओं में यातायात ले जाने वाली मिनेसोटा की दो-लेन सड़क पर, जब एक स्कूल बस अपनी स्टॉप आर्म फैलाकर और लाल बत्तियाँ चमकाते हुए रुकी हुई हो, तो पास आ रहे चालक को बस से कम से कम कितनी दूरी पर रुकना चाहिए?","options":["कम से कम 20 feet दूर","कम से कम 10 feet दूर","कम से कम 30 feet दूर","कम से कम 50 feet दूर"],"explanation":"Minn. Stat. 169.444, subd. 1 और मिनेसोटा CDL मैनुअल के अनुसार, फैली हुई स्टॉप-सिग्नल आर्म और चमकती लाल बत्तियाँ दिखाने वाली रुकी हुई स्कूल बस के पास आ रहे चालक को कम से कम 20 feet दूर रुकना चाहिए और तब तक रुके रहना चाहिए जब तक आर्म वापस न हो जाए और बत्तियाँ चमकना बंद न कर दें। स्रोत: Minn. Stat. 169.444; Minnesota CDL Manual."},"60":{"q":"मिनेसोटा कानून के तहत, किस प्रकार की सड़क पर चालक को विपरीत दिशा में चढ़ने या उतारने वाली स्कूल बस के लिए रुकना आवश्यक नहीं है?","options":["एक ऐसी सड़क जिसमें भौतिक अवरोध, उठे हुए मध्यवर्ती (median), या धँसे हुए मध्यवर्ती द्वारा विभाजित अलग-अलग रास्ते हों","प्रत्येक दिशा में दो या अधिक लेन वाली कोई भी सड़क","विपरीत लेन को चिह्नित करने वाली रंगी हुई केंद्र रेखा वाली कोई भी सड़क","केंद्र में दो-तरफ़ा बाएँ-मुड़ने वाली लेन वाली कोई भी सड़क"],"explanation":"Minn. Stat. 169.444, subd. 4 चालक को रुकने से केवल तभी छूट देता है जब बस एक अलग रास्ते पर हो और रास्ते 'अलग' किए गए हों, अर्थात् भौतिक अवरोध, उठे हुए मध्यवर्ती, या धँसे हुए मध्यवर्ती द्वारा विभाजित हों। रंगी हुई रेखा या केंद्र मोड़ लेन एक अलग किया गया रास्ता नहीं है। स्रोत: Minn. Stat. 169.444, subd. 4."},"61":{"q":"किसी भी शहरीकृत क्षेत्र के बाहर ग्रामीण मिनेसोटा इंटरस्टेट राजमार्ग पर अधिकतम वैधानिक गति सीमा क्या है?","options":["70 mph","65 mph","75 mph","60 mph"],"explanation":"Minn. Stat. 169.14 किसी भी शहरीकृत क्षेत्र की सीमा के बाहर इंटरस्टेट राजमार्गों पर गति सीमा 70 mph और शहरीकृत क्षेत्र के भीतर 65 mph निर्धारित करता है। स्रोत: Minn. Stat. 169.14, subd. 2; MnDOT."},"62":{"q":"मिनेसोटा में, एक यात्री कार की तुलना में ग्रामीण इंटरस्टेट राजमार्ग पर लदे हुए सेमी-ट्रक पर कौन सी गति सीमा लागू होती है?","options":["कारों के समान ही सीमा; मिनेसोटा ट्रकों के लिए कोई अलग कम गति सीमा निर्धारित नहीं करता","लगाई गई कार सीमा से 10 mph कम","राज्यव्यापी एक समान 60 mph ट्रक अधिकतम","लगाई गई कार सीमा से 5 mph कम"],"explanation":"मिनेसोटा ट्रकों या वाणिज्यिक वाहनों के लिए कोई अलग, कम गति सीमा निर्धारित नहीं करता। Minn. Stat. 169.14 में लगाई गई वैधानिक सीमाएँ सभी वाहनों पर समान रूप से लागू होती हैं। स्रोत: Minn. Stat. 169.14; MnDOT गति सीमा मार्गदर्शन।"},"63":{"q":"मिनेसोटा के 'Ted Foss' Move Over कानून के तहत, एक ही दिशा में ठीक दो लेन वाली सड़क पर, चमकती या चेतावनी बत्तियाँ दिखाने वाले रुके हुए अधिकृत वाहन के पास पहुँचते समय चालक को क्या करना चाहिए?","options":["यदि संभव हो तो सुरक्षित रूप से अधिकृत वाहन से सबसे दूर वाली लेन में जाएँ","अधिकृत वाहन के जाने तक पूरी तरह रुक जाएँ","हॉर्न बजाएँ और वर्तमान लेन और गति बनाए रखें","करीब से और धीरे-धीरे गुजरने के लिए अधिकृत वाहन के सबसे निकट वाली लेन में जाएँ"],"explanation":"Minn. Stat. 169.18, subd. 11(b) के अनुसार जब एक ही दिशा में दो लेन हों तो चालक को सक्रिय बत्तियों वाले रुके हुए अधिकृत वाहन से सबसे दूर वाली लेन में सुरक्षित रूप से जाना आवश्यक है। स्रोत: Minn. Stat. 169.18, subd. 11; Minnesota DPS (Ted Foss Move Over law)."},"64":{"q":"मिनेसोटा के Move Over कानून के तहत, एक ही दिशा में दो से अधिक लेन वाली सड़क पर, अपनी बत्तियाँ सक्रिय किए हुए रुके हुए अधिकृत वाहन को पार करते समय चालक को क्या करना आवश्यक है?","options":["यदि सुरक्षित हो तो चालक और अधिकृत वाहन की लेन के बीच एक पूरी लेन खाली छोड़ें","सबसे दाहिनी लेन में पूरी तरह रुक जाएँ","गति को लगाई गई सीमा से ठीक आधी तक कम करें लेकिन उसी लेन में रहें","अधिकृत वाहन के ठीक बगल वाली लेन में जाएँ"],"explanation":"Minn. Stat. 169.18, subd. 11(c) के अनुसार एक ही दिशा में दो से अधिक लेन वाली सड़क पर चालक को सुरक्षित रूप से इस तरह जाना आवश्यक है कि चालक और अधिकृत वाहन की किसी भी लेन के बीच एक पूरी लेन खाली रहे। स्रोत: Minn. Stat. 169.18, subd. 11."},"65":{"q":"निम्नलिखित में से कौन सा मिनेसोटा की Move Over कानून द्वारा संरक्षित 'अधिकृत वाहन' की परिभाषा में शामिल है?","options":["बत्तियाँ सक्रिय किए हुए एक टो ट्रक, उपयोगिता कंपनी का वाहन, या ठोस कचरा/रीसाइक्लिंग वाहन","केवल चिह्नित कानून-प्रवर्तन स्क्वाड कारें","केवल एम्बुलेंस और अग्निशमन उपकरण","अपनी पार्किंग बत्तियाँ जलाए हुए कोई भी यात्री कार"],"explanation":"Minn. Stat. 169.18, subd. 11(a) 'अधिकृत वाहन' को व्यापक रूप से परिभाषित करता है जिसमें आपातकालीन वाहन, टो ट्रक, फ्रीवे सेवा गश्ती वाहन, सड़क रखरखाव वाहन, उपयोगिता कंपनी वाहन, निर्माण वाहन, डाक सेवा वाहन, और ठोस कचरा या रीसाइक्लिंग वाहन शामिल हैं। स्रोत: Minn. Stat. 169.18, subd. 11(a)."},"66":{"q":"यदि किसी वाणिज्यिक वाहन को मिनेसोटा के एक-तरफ़ा या विभाजित राजमार्ग पर या उसके पास रुकना पड़े, तो चालक को तीन आपातकालीन चेतावनी उपकरण कहाँ रखने चाहिए?","options":["पास आ रहे यातायात की ओर 10 feet, 100 feet, और 200 feet पर","पास आ रहे यातायात की ओर 25 feet, 100 feet, और 300 feet पर","पास आ रहे यातायात की ओर 10 feet, 50 feet, और 150 feet पर","पास आ रहे यातायात की ओर 15 feet, 75 feet, और 250 feet पर"],"explanation":"मिनेसोटा CDL मैनुअल (और 49 CFR 392.22) के अनुसार एक-तरफ़ा या विभाजित राजमार्ग पर तीन चेतावनी उपकरणों को वाहन से पास आ रहे यातायात की ओर 10 feet, 100 feet, और 200 feet पर रखा जाना चाहिए। स्रोत: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22."},"67":{"q":"सड़क या किनारे पर रुकने के कितने मिनट के भीतर मिनेसोटा के वाणिज्यिक चालक को आवश्यक आपातकालीन चेतावनी उपकरण निकालने चाहिए?","options":["10 मिनट के भीतर","5 मिनट के भीतर","15 मिनट के भीतर","30 मिनट के भीतर"],"explanation":"मिनेसोटा CDL मैनुअल कहता है कि यदि आपको सड़क या किनारे पर रुकना पड़े तो आपको दस मिनट के भीतर अपने आपातकालीन चेतावनी उपकरण निकालने चाहिए। स्रोत: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22."},"68":{"q":"दोनों दिशाओं में यातायात ले जाने वाली अविभाजित दो-लेन मिनेसोटा सड़क पर, एक रुके हुए वाणिज्यिक चालक को चेतावनी उपकरण कहाँ रखने चाहिए?","options":["आगे या पीछे के कोनों के 10 feet के भीतर और वाहन के 100 feet पीछे और आगे","केवल पास आ रहे यातायात की ओर 10 feet, 100 feet, और 200 feet पर","केवल एक उपकरण पीछे की ओर 500 feet पर","केवल यातायात की ओर वाहन के 50 feet के भीतर"],"explanation":"मिनेसोटा CDL मैनुअल निर्दिष्ट करता है कि दोनों दिशाओं में यातायात ले जाने वाली दो-लेन सड़क (अविभाजित राजमार्ग) पर, वाहन को चिह्नित करने के लिए चेतावनी उपकरण आगे या पीछे के कोनों के 10 feet के भीतर और वाहन के 100 feet पीछे और आगे रखें। स्रोत: Minnesota CDL Manual (Communicating Your Presence); 49 CFR 392.22."},"69":{"q":"मिनेसोटा के वाणिज्यिक वाहन को अपने आवश्यक रुके-हुए-वाहन चेतावनी उपकरणों के रूप में कितने लाल परावर्तक त्रिकोण की आवश्यकता होती है?","options":["तीन परावर्तक त्रिकोण (या 6 फ्यूज़ या 3 तरल-दहन फ्लेयर)","दो परावर्तक त्रिकोण","चार परावर्तक त्रिकोण","एक परावर्तक त्रिकोण और एक झंडा"],"explanation":"मिनेसोटा CDL मैनुअल के अनुसार पार्क किए गए वाहनों के लिए चेतावनी उपकरण तीन परावर्तक त्रिकोण, या कम से कम 6 फ्यूज़, या 3 तरल-दहन फ्लेयर होने चाहिए। स्रोत: Minnesota CDL Manual (Warning Devices for parked vehicles); 49 CFR 393.95."},"70":{"q":"मिनेसोटा में, जब एक ट्रक या बस किसी व्यवसाय या आवासीय जिले के बाहर सड़क पर चल रही हो, तो वह दूसरे वाहन का कितनी दूरी से अधिक करीब से पीछा नहीं कर सकती?","options":["500 feet","300 feet","200 feet","100 feet"],"explanation":"Minn. Stat. 169.18, subd. 8(b) प्रावधान करता है कि किसी मोटर ट्रक, बस, या किसी अन्य वाहन को खींचने वाले वाहन का चालक किसी व्यवसाय या आवासीय जिले के बाहर चलते समय दूसरे वाहन के 500 feet के भीतर पीछा नहीं करेगा। स्रोत: Minn. Stat. 169.18, subd. 8."},"71":{"q":"मिनेसोटा में एक स्कूल बस चालक को रेलरोड क्रॉसिंग पर निकटतम रेल से कितनी दूरी पहले फोर-वे हैज़र्ड चेतावनी बत्तियाँ सक्रिय करनी चाहिए?","options":["निकटतम रेल से कम से कम 100 feet","निकटतम रेल से कम से कम 25 feet","निकटतम रेल से कम से कम 300 feet","निकटतम रेल से कम से कम 50 feet"],"explanation":"CDL मैनुअल का मिनेसोटा स्कूल बस अनुभाग चालक को निकटतम रेल से कम से कम 100 feet पर मास्टर स्विच बंद करके फोर-वे हैज़र्ड चेतावनी बत्तियाँ चालू करने की आवश्यकता बताता है, और रेलरोड क्रॉसिंग पर 8-लाइट सिस्टम का उपयोग करने से मना करता है। स्रोत: Minnesota CDL Manual (School Bus Railroad Crossings)."},"72":{"q":"एक मिनेसोटा चालक जो अपनी फैली हुई स्टॉप आर्म और चमकती लाल बत्तियाँ दिखा रही स्कूल बस के लिए रुकने में विफल रहता है, वह कम से कम किस अपराध का दोषी होता है?","options":["एक मिसडिमीनर जिसके लिए $500 से कम का जुर्माना नहीं होता","अधिकतम $50 जुर्माने वाला एक पेटी मिसडिमीनर","पहले अपराध के लिए बिना जुर्माने वाला एक उल्लंघन","हर मामले में एक फेलनी"],"explanation":"Minn. Stat. 169.444 और मिनेसोटा CDL मैनुअल के तहत, जो चालक आवश्यकतानुसार स्कूल बस के लिए रुकने में विफल रहता है, वह एक मिसडिमीनर का दोषी होता है जिसके लिए $500 से कम का जुर्माना नहीं होता, और लाइसेंस निलंबन संभव है। स्रोत: Minn. Stat. 169.444; Minnesota CDL Manual."},"73":{"q":"रुकी हुई स्कूल बस को दाहिनी ओर (यात्री-दरवाज़े वाली ओर) से पार करना, या जब कोई बच्चा सड़क पर बाहर हो तब पार करना, मिनेसोटा चालक के अपराध को किस स्तर तक बढ़ा देता है?","options":["एक ग्रॉस मिसडिमीनर जिसमें लाइसेंस रद्द किया जा सकता है","केवल पॉइंट वाली एक साधारण ट्रैफ़िक सिटेशन","एक पेटी मिसडिमीनर","एक सिविल पार्किंग उल्लंघन"],"explanation":"Minn. Stat. 169.444 और मिनेसोटा CDL मैनुअल इसे एक ग्रॉस मिसडिमीनर बनाते हैं, जिसमें लाइसेंस रद्द किया जा सकता है, यदि कोई रुकने में विफल रहे और या तो बस की दाहिनी यात्री-दरवाज़े वाली ओर से पार करे या जब कोई स्कूली बच्चा सड़क, राजमार्ग, या आसन्न फुटपाथ पर बाहर हो तब पार करे। स्रोत: Minn. Stat. 169.444; Minnesota CDL Manual."},"74":{"q":"टोल के संबंध में, कौन सा कथन वाणिज्यिक चालकों के लिए मिनेसोटा की इंटरस्टेट और राजमार्ग प्रणाली का सबसे अच्छा वर्णन करता है?","options":["मिनेसोटा में कोई पारंपरिक टोल सड़कें नहीं हैं; केवल वैकल्पिक E-ZPass MN (पूर्व में MnPASS) एक्सप्रेस लेन ट्विन सिटीज़ मेट्रो में मौजूद हैं","सभी मिनेसोटा इंटरस्टेट के लिए ट्रकों हेतु एक टोल ट्रांसपोंडर आवश्यक है","ट्रकों को हर मिनेसोटा इंटरस्टेट पर प्रति-धुरी टोल देना पड़ता है","मिनेसोटा Indiana Toll Road की तरह एक राज्यव्यापी टोलवे नेटवर्क संचालित करता है"],"explanation":"मिनेसोटा में कोई पारंपरिक टोल सड़कें नहीं हैं; इसका एकमात्र टोलिंग ट्विन सिटीज़ मेट्रो में I-394, I-35W, और I-35E पर वैकल्पिक E-ZPass Minnesota (पूर्व में MnPASS) एक्सप्रेस लेन है, जिसके साथ-साथ मुफ़्त सामान्य-उद्देश्य वाली लेन हमेशा उपलब्ध रहती हैं। स्रोत: MnDOT; Minnesota DPS."},"75":{"q":"एक मिनेसोटा CDL धारक जो वाणिज्यिक वाहन चलाते समय एक ही रेलरोड ग्रेड क्रॉसिंग उल्लंघन का दोषी ठहराया जाता है, उसे कम से कम कितने समय के लिए CMV चलाने से अयोग्य घोषित किया जाता है?","options":["60 दिन","30 दिन","120 दिन","1 वर्ष"],"explanation":"मिनेसोटा CDL मैनुअल कहता है कि चालक को पहले रेलरोड ग्रेड क्रॉसिंग उल्लंघन के लिए 60 दिन, किसी भी तीन-वर्षीय अवधि में दो के लिए 120 दिन, और किसी भी तीन-वर्षीय अवधि में तीन या अधिक के लिए एक वर्ष के लिए अयोग्य घोषित किया जाता है। स्रोत: Minnesota CDL Manual (Railroad Grade Crossing Violation); 49 CFR 383.51."},"76":{"q":"एक बहु-लेन मिनेसोटा राजमार्ग पर, राज्य का लेन-उपयोग नियम यातायात की सामान्य गति से धीमे चल रहे वाणिज्यिक वाहन से क्या अपेक्षा करता है?","options":["दाहिनी ओर वाली लेन में या जितना व्यावहारिक हो उतना दाहिने किनारे के करीब चलें, सिवाय पार करते समय या बाएँ मुड़ते समय","हर समय केंद्र लेन में रहें ताकि तेज़ यातायात दोनों बाहरी लेन का उपयोग कर सके","मिलने वाले यातायात के लिए दाहिनी लेन खुली रखने हेतु बाईं लेन में रहें","जब भी यातायात सामान्य से अधिक हो तब किनारे (shoulder) का उपयोग करें"],"explanation":"Minn. Stat. 169.18, subd. 10 के अनुसार सामान्य यातायात से धीमे चल रहे वाहन को तब उपलब्ध दाहिनी ओर वाली लेन में, या जितना व्यावहारिक हो उतना दाहिने कर्ब या किनारे के करीब चलाया जाना चाहिए, सिवाय आगे निकलने और पार करते समय, बाएँ मोड़ की तैयारी करते समय, या जहाँ कोई लेन किसी विशिष्ट उपयोग के लिए नामित हो। स्रोत: Minn. Stat. 169.18, subd. 10."},"77":{"q":"कौन सी मिनेसोटा एजेंसी वाणिज्यिक चालक लाइसेंस जारी करती है और राज्य में CDL परीक्षण का प्रशासन करती है?","options":["Department of Public Safety, Driver and Vehicle Services (DVS)","Minnesota State Patrol Commercial Vehicle Section","Federal Motor Carrier Safety Administration (FMCSA)","Minnesota Department of Transportation (MnDOT)"],"explanation":"मिनेसोटा में CDL, Department of Public Safety द्वारा अपने Driver and Vehicle Services (DVS) प्रभाग के माध्यम से जारी किए जाते हैं, जो ज्ञान और कौशल परीक्षणों का भी प्रशासन करता है। MnDOT लाइसेंसिंग नहीं, बल्कि इंट्रास्टेट मेडिकल वेवर और ओवरसाइज़/ओवरवेट परमिट संभालता है। स्रोत: Minnesota CDL Manual, Part A (DVS, Department of Public Safety)."},"78":{"q":"मिनेसोटा में, प्रत्येक CDL आवेदक को पहले कौन सा क्रेडेंशियल प्राप्त करना चाहिए जो वाणिज्यिक वाहन में पर्यवेक्षित अभ्यास ड्राइविंग की अनुमति देता है?","options":["एक commercial learner permit (CLP)","एक अस्थायी कौशल-परीक्षण प्रमाणपत्र","एक निर्देशात्मक CDL वेवर","एक अनंतिम वाणिज्यिक एंडोर्समेंट"],"explanation":"मिनेसोटा सभी CDL आवेदकों को पहले एक commercial learner permit (CLP) प्राप्त करने की आवश्यकता बताता है, जो अभ्यास ड्राइविंग की अनुमति केवल तभी देता है जब वाहन में उसी श्रेणी या उच्चतर का एक अन्य उचित रूप से लाइसेंसधारी चालक मौजूद हो। स्रोत: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"79":{"q":"मिनेसोटा commercial learner permit (CLP) प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","17 वर्ष","21 वर्ष","16 वर्ष"],"explanation":"CLP प्राप्त करने के लिए आपकी आयु कम से कम 18 वर्ष होनी चाहिए और आपके पास एक वैध मिनेसोटा चालक लाइसेंस होना चाहिए। इंटरस्टेट वाणिज्य में वाणिज्यिक वाहन चलाने के लिए आपकी आयु 21 वर्ष होनी चाहिए। स्रोत: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"80":{"q":"मिनेसोटा CLP के लिए आवेदन करने के बाद, CDL कौशल (सड़क) परीक्षण देने की अनुमति मिलने से पहले आवेदक को इसे कितने समय तक रखना चाहिए?","options":["14 कैलेंडर दिन","10 कैलेंडर दिन","7 कैलेंडर दिन","30 कैलेंडर दिन"],"explanation":"मिनेसोटा के अनुसार आवेदक द्वारा CDL कौशल परीक्षण देने से पहले CLP को आवेदन की तारीख से 14 कैलेंडर दिनों तक रखा जाना आवश्यक है। स्रोत: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"81":{"q":"एक मिनेसोटा commercial learner permit (CLP) अपनी जारी होने की तारीख से कितने समय तक वैध रहता है?","options":["1 वर्ष","2 वर्ष","90 दिन","180 दिन"],"explanation":"एक मिनेसोटा CLP 180 दिनों के लिए वैध होता है। इसे नवीनीकृत किया जा सकता है, लेकिन यह प्रारंभिक जारी होने की तारीख से एक वर्ष से अधिक के लिए वैध नहीं हो सकता। स्रोत: Minnesota CDL Manual, Part A, Commercial Driver's License Tests."},"82":{"q":"मिनेसोटा CDL कौशल परीक्षण किन तीन चरणों में विभाजित है?","options":["एयर ब्रेक जाँच, कपलिंग/अनकपलिंग, और राजमार्ग ड्राइविंग","लिखित परीक्षा, दृष्टि जाँच, और सड़क परीक्षण","वाहन निरीक्षण, बुनियादी नियंत्रण कौशल, और सड़क परीक्षण","प्री-ट्रिप पेपरवर्क, रेंज बैकिंग, और एक रक्षात्मक-ड्राइविंग क्विज़"],"explanation":"मिनेसोटा CDL कौशल परीक्षण के तीन चरण होते हैं: (1) वाहन निरीक्षण (प्री-ट्रिप), (2) बुनियादी नियंत्रण कौशल परीक्षण, और (3) सड़क परीक्षण। तीनों को उसी प्रकार के वाहन में लिया जाना चाहिए जिसके लिए आप लाइसेंस प्राप्त करना चाहते हैं। स्रोत: Minnesota CDL Manual, Part A, Skills Tests."},"83":{"q":"मिनेसोटा CDL वाहन निरीक्षण चरण के दौरान, प्रत्येक मद के लिए क्रेडिट प्राप्त करने हेतु आवेदक को क्या करना चाहिए?","options":["एक निश्चित समय सीमा के भीतर निरीक्षण चुपचाप पूरा करें","जाँच के दौरान पाए गए किसी भी घिसे हुए हिस्से को बदलें","वाहन के नीचे जाएँ और सभी द्रव स्तरों की पुष्टि करें","प्रत्येक मद की ओर इंगित करें और बताएँ कि ठंडे वाहन पर किन समस्याओं की तलाश करनी है"],"explanation":"वाहन निरीक्षण पर, आवेदक को परीक्षक को प्रत्येक मद की ओर इंगित करना चाहिए और बताना चाहिए कि ठंडे वाहन पर किन समस्याओं की तलाश करनी है, क्रेडिट अर्जित करने हेतु मुख्य बिंदुओं का उल्लेख करते हुए। आपको वाहन के नीचे जाने या द्रव जाँचने की आवश्यकता नहीं है। स्रोत: Minnesota CDL Manual, Part A, Vehicle Inspection."},"84":{"q":"एक मिनेसोटा CDL आवेदक प्रत्येक व्यक्तिगत ज्ञान परीक्षण का प्रतिदिन कितनी बार प्रयास कर सकता है?","options":["प्रतिदिन तीन बार","प्रतिदिन दो बार","प्रतिदिन असीमित प्रयास","प्रतिदिन एक बार"],"explanation":"CDL ज्ञान परीक्षण अंग्रेज़ी में कागज़ पर या कंप्यूटर पर पेश किया जाता है, और एक आवेदक प्रत्येक ज्ञान परीक्षण का प्रतिदिन केवल एक बार प्रयास कर सकता है। स्रोत: Minnesota CDL Manual, Part A, Knowledge Tests."},"85":{"q":"Entry-Level Driver Training (ELDT) पहली बार के मिनेसोटा Class A/Class B आवेदकों और कुछ एंडोर्समेंट के लिए किस तारीख को अनिवार्य हो गया?","options":["May 21, 2014","November 1, 2021","February 7, 2022","January 4, 2020"],"explanation":"ELDT आवश्यकताएँ उन व्यक्तियों पर लागू होती हैं जो Feb. 7, 2022 को या उसके बाद Class A या B CDL (या S, P, या H एंडोर्समेंट) प्राप्त करते हैं। जिस आवेदक का वैध CLP उस तारीख से पहले जारी हुआ था, उसे छूट है यदि वह CLP की समाप्ति से पहले CDL प्राप्त कर ले। स्रोत: Minnesota CDL Manual, ELDT (FMCSA Training Provider Registry)."},"86":{"q":"मिनेसोटा में लागू संघीय ELDT नियम के तहत, प्रशिक्षण के सिद्धांत (कक्षा) भाग को पास करने के लिए क्या आवश्यक है?","options":["सिद्धांत मूल्यांकन में कम से कम 70% स्कोर करना","सिद्धांत मूल्यांकन में कम से कम 80% स्कोर करना","एक बिहाइंड-द-व्हील सिम्युलेटर मूल्यांकन पास करना","न्यूनतम 30 कक्षा घंटे पूरे करना"],"explanation":"ELDT सिद्धांत प्रशिक्षण के लिए न्यूनतम घंटों की कोई संख्या नहीं है, लेकिन प्रशिक्षु को सिद्धांत मूल्यांकन में कम से कम 80% स्कोर करना चाहिए। बिहाइंड-द-व्हील प्रशिक्षण के लिए न्यूनतम घंटे नहीं हैं और इसे प्रदाता द्वारा प्रवीणता के आधार पर आँका जाता है। स्रोत: Minnesota CDL Manual, ELDT (FMCSA Training Provider Registry)."},"87":{"q":"इससे पहले कि कोई एंट्री-लेवल चालक मिनेसोटा में ELDT का बिहाइंड-द-व्हील (BTW) भाग ले सके, उसके पास पहले से क्या होना चाहिए?","options":["केवल एक DOT मेडिकल परीक्षक का प्रमाणपत्र","एक commercial learner permit (CLP)","एक पूर्ण अप्रतिबंधित CDL","CDL सड़क परीक्षण में एक उत्तीर्ण स्कोर"],"explanation":"ELDT का बिहाइंड-द-व्हील भाग आवेदक द्वारा CLP प्राप्त करने से पहले नहीं लिया जा सकता, और इसे कक्षा (सिद्धांत) प्रशिक्षण के एक वर्ष के भीतर पूरा किया जाना चाहिए। स्रोत: Minnesota CDL Manual / DPS DVS CLP page."},"88":{"q":"मिनेसोटा स्व-प्रमाणन फॉर्म पर, किस श्रेणी में एक ऐसे चालक को जो गैर-छूट प्राप्त इंटरस्टेट वाणिज्य में संचालन करता है, एक वर्तमान मेडिकल परीक्षक का प्रमाणपत्र भी प्रदान करना आवश्यक है?","options":["Category 4 - छूट प्राप्त इंट्रास्टेट","Category 1 - गैर-छूट प्राप्त इंटरस्टेट (49 CFR part 391 के अधीन)","Category 2 - छूट प्राप्त इंटरस्टेट","Category 3 - गैर-छूट प्राप्त इंट्रास्टेट (Minnesota Statutes chapter 221 के अधीन)"],"explanation":"Category 1, गैर-छूट प्राप्त इंटरस्टेट, प्रमाणित करता है कि चालक 49 CFR part 391 की संघीय DOT मेडिकल आवश्यकताओं के अधीन है और उन्हें पूरा करता है, और उसे एक वर्तमान मेडिकल परीक्षक का प्रमाणपत्र और कोई भी वेवर प्रदान करना चाहिए। स्रोत: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS)."},"89":{"q":"कौन सी मिनेसोटा स्व-प्रमाणन श्रेणी एक ऐसे गैर-छूट प्राप्त इंट्रास्टेट चालक को कवर करती है जो राज्य की मेडिकल परीक्षा आवश्यकताओं के अधीन है?","options":["Category 4 - छूट प्राप्त इंट्रास्टेट","Category 2 - छूट प्राप्त इंटरस्टेट","Category 3 - गैर-छूट प्राप्त इंट्रास्टेट, Minnesota Statutes chapter 221 के तहत","Category 1 - गैर-छूट प्राप्त इंटरस्टेट, 49 CFR part 391 के तहत"],"explanation":"Category 3, गैर-छूट प्राप्त इंट्रास्टेट, उन चालकों पर लागू होती है जो Minnesota Statutes, chapter 221 की राज्य मेडिकल परीक्षा आवश्यकताओं के अधीन हैं, जिन्हें एक वर्तमान मेडिकल परीक्षक का प्रमाणपत्र और कोई भी वेवर भी प्रदान करना चाहिए। स्रोत: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS)."},"90":{"q":"Minnesota Commercial Driver License Medical Self-Certification Form कितनी स्व-प्रमाणन श्रेणियाँ सूचीबद्ध करता है?","options":["दो श्रेणियाँ","चार श्रेणियाँ","तीन श्रेणियाँ","पाँच श्रेणियाँ"],"explanation":"मिनेसोटा स्व-प्रमाणन फॉर्म चार श्रेणियाँ सूचीबद्ध करता है: गैर-छूट प्राप्त इंटरस्टेट, छूट प्राप्त इंटरस्टेट, गैर-छूट प्राप्त इंट्रास्टेट, और छूट प्राप्त इंट्रास्टेट। चार में से दो (गैर-छूट प्राप्त श्रेणियाँ) के लिए एक मेडिकल परीक्षक का प्रमाणपत्र आवश्यक है। स्रोत: Minnesota CDL Medical Self-Certification Form/FAQs (DPS DVS)."},"91":{"q":"एक मिनेसोटा CDL धारक पूर्ण किया गया स्व-प्रमाणन फॉर्म और वैध मेडिकल परीक्षक का प्रमाणपत्र कहाँ जमा करता है?","options":["Department of Public Safety / Driver and Vehicle Services (DVS)","MnDOT's Office of Motor Carrier Services","Federal Motor Carrier Safety Administration (FMCSA)","National Registry of Certified Medical Examiners"],"explanation":"चालक स्व-प्रमाणन फॉर्म और वैध मेडिकल परीक्षक का प्रमाणपत्र Department of Public Safety / DVS CDL Unit को जमा करते हैं (drive.mn.gov पर ऑनलाइन, डाक, फ़ैक्स, या किसी ड्राइवर परीक्षा स्टेशन पर व्यक्तिगत रूप से)। फिर प्रमाणपत्र की जानकारी ड्राइविंग रिकॉर्ड पर नोट की जाती है। स्रोत: Minnesota CDL Manual, Medical Requirements; DPS DVS Self-Certification FAQs."},"92":{"q":"एक मिनेसोटा DOT मेडिकल परीक्षक का प्रमाणपत्र आम तौर पर अधिकतम कितनी अवधि के लिए वैध होता है?","options":["पाँच वर्ष","तीन वर्ष","अधिकतम दो वर्ष","एक वर्ष"],"explanation":"एक मेडिकल परीक्षक का प्रमाणपत्र अधिकतम दो वर्ष तक के लिए वैध हो सकता है, हालाँकि परीक्षक चालक के मेडिकल इतिहास के आधार पर इसे कम अवधि के लिए जारी कर सकता है। स्रोत: Minnesota CDL Manual, Medical Certificate Renewal; DPS DVS Self-Certification FAQs."},"93":{"q":"मेडिकल परीक्षक का प्रमाणपत्र समाप्त होने से कितने दिन पहले Minnesota Department of Public Safety चालक को एक सूचना भेजता है?","options":["45 दिन पहले","90 दिन पहले","60 दिन पहले","30 दिन पहले"],"explanation":"Department of Public Safety फ़ाइल पर मौजूद मेडिकल परीक्षक के प्रमाणपत्र या वेवर की समाप्ति तिथि से 60 दिन पहले चालक के अंतिम ज्ञात पते पर एक सूचना भेजता है। स्रोत: Minnesota CDL Manual, Medical Certificate Renewal."},"94":{"q":"यदि एक आवश्यक मेडिकल परीक्षक का प्रमाणपत्र जमा करने में विफल रहने के कारण मिनेसोटा CDL डाउनग्रेड किया जाता है, तो किस अवधि के भीतर चालक केवल एक वैध प्रमाणपत्र जमा करके CDL को बहाल कर सकता है?","options":["दो वर्ष के भीतर","6 महीने के भीतर","30 दिन के भीतर","एक वर्ष के भीतर"],"explanation":"एक चालक डाउनग्रेड किए गए CDL और एंडोर्समेंट को एक वर्ष के भीतर स्व-प्रमाणन फॉर्म के साथ एक वैध मेडिकल परीक्षक का प्रमाणपत्र जमा करके बहाल कर सकता है। यदि एक वर्ष से अधिक के लिए डाउनग्रेड या आत्मसमर्पित किया गया हो, तो चालक को लागू ज्ञान और सड़क परीक्षण फिर से देने होंगे। स्रोत: Minnesota CDL Manual, Medical Certificate Renewal; DPS DVS FAQs."},"95":{"q":"एक मिनेसोटा वाणिज्यिक चालक लाइसेंस नवीनीकृत किए जाने से पहले कितने समय तक वैध रहता है?","options":["दो वर्ष","चार वर्ष","पाँच वर्ष","आठ वर्ष"],"explanation":"एक मिनेसोटा CDL (Class A, B, या C) चार वर्ष के लिए वैध होता है और फिर इसे नवीनीकृत किया जाना चाहिए, जो एक नियमित Class D लाइसेंस के समान ही चक्र है। स्रोत: DPS DVS CDL Class pages (Department of Public Safety)."}},"ar":{"0":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة التجارية على طرق مينيسوتا السريعة، باستثناء المرايا وأجهزة تثبيت الحمولة؟","options":["8 أقدام و0 بوصة (96 بوصة)","8 أقدام و6 بوصات (102 بوصة)","9 أقدام و0 بوصة (108 بوصات)","8 أقدام و4 بوصات (100 بوصة)"],"explanation":"تحدد لائحة مينيسوتا 169.80 الحد الأقصى لإجمالي العرض الخارجي بـ 102 بوصة (8 أقدام و6 بوصات). وهذا يطابق المعيار الفيدرالي. المصدر: Minn. Stat. 169.80؛ MnDOT CVO."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، محمّلة أو غير محمّلة، على طرق مينيسوتا السريعة؟","options":["13 قدمًا و0 بوصة","14 قدمًا و0 بوصة","13 قدمًا و6 بوصات","14 قدمًا و6 بوصات"],"explanation":"تنص لائحة مينيسوتا 169.81 على أنه لا يجوز أن يتجاوز ارتفاع أي مركبة غير محمّلة أو مع حمولتها 13 قدمًا و6 بوصات. المصدر: Minn. Stat. 169.81؛ دليل CDL في مينيسوتا."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي لمركبة أو مجموعة مركبات على شوارع وطرق مينيسوتا دون تصريح؟","options":["73,280 رطلاً","80,000 رطل","84,000 رطل","88,000 رطل"],"explanation":"تحدد لائحة مينيسوتا 169.824 الوزن الإجمالي للمركبة بـ 80,000 رطل على جميع الشوارع والطرق السريعة، بما يتوافق مع الحد الفيدرالي. المصدر: Minn. Stat. 169.824؛ MnDOT."},"3":{"q":"بموجب قانون مينيسوتا، ما هو الحد الأقصى للوزن المسموح به على محور واحد على طريق سريع معبّد؟","options":["18,000 رطل","20,000 رطل","22,400 رطل","34,000 رطل"],"explanation":"تحدد لائحة مينيسوتا 169.823 وزن المحور الواحد بـ 20,000 رطل على الشوارع والطرق السريعة المعبّدة. المصدر: Minn. Stat. 169.823؛ كتاب الشاحنات MnDOT CVO."},"4":{"q":"ما هو الحد الأقصى للوزن المسموح به على مجموعة محاور مزدوجة (تاندم) في مينيسوتا؟","options":["32,000 رطل","36,000 رطل","34,000 رطل","40,000 رطل"],"explanation":"تتبع مينيسوتا الحد الفيدرالي للمحور المزدوج البالغ 34,000 رطل، المنصوص عليه في جدول أوزان المحاور في Minn. Stat. 169.824. المصدر: Minn. Stat. 169.824؛ دليل CDL في مينيسوتا."},"5":{"q":"على طريق سريع في مينيسوتا، ما هو الحد الأقصى للطول الإجمالي لمركبة مفردة (غير مفصلية)، بما في ذلك الحمولة والمصدات؟","options":["40 قدمًا","45 قدمًا","48 قدمًا","53 قدمًا"],"explanation":"تحدد لائحة مينيسوتا 169.81 طول المركبة المفردة بـ 45 قدمًا إجمالاً، بما في ذلك الحمولة والمصدات الأمامية والخلفية (قد تصل الرافعات المتنقلة إلى 48 قدمًا). المصدر: Minn. Stat. 169.81."},"6":{"q":"ما هو الحد الأقصى للطول الإجمالي لمجموعة من وحدتين (جرار-نصف مقطورة) على طرق مينيسوتا السريعة دون تصريح؟","options":["65 قدمًا","70 قدمًا","75 قدمًا","80 قدمًا"],"explanation":"تحدد لائحة مينيسوتا 169.81 الحد الأقصى لطول مجموعة المركبات المكونة من وحدتين بـ 75 قدمًا. المصدر: Minn. Stat. 169.81؛ MnDOT CVO."},"7":{"q":"نصف المقطورة ضمن مجموعة جرار-نصف مقطورة في مينيسوتا لا يجوز عمومًا أن تتجاوز أي طول؟","options":["45 قدمًا","48 قدمًا","53 قدمًا","57 قدمًا"],"explanation":"تنص لائحة مينيسوتا 169.81 على أن نصف المقطورة لا يجوز عمومًا أن تتجاوز 48 قدمًا، مع السماح بطول يصل إلى 53 قدمًا عندما لا تتجاوز المسافة من مسمار الارتكاز (الكينغ بين) إلى المحور الخلفي 43 قدمًا. المصدر: Minn. Stat. 169.81."},"8":{"q":"ما هي الصيغة التي تستخدمها مينيسوتا لتحديد الحد الأقصى للوزن المسموح به على مجموعة من المحاور المتتالية بناءً على تباعد المحاور وعددها؟","options":["صيغة الجسر الفيدرالية (Federal Bridge Formula)","صيغة تصنيف الوزن الإجمالي للمجموعة","مؤشر الحمولة في مينيسوتا","صيغة معادلة حمولة المحور"],"explanation":"ينفّذ جدول أوزان مجموعة المحاور في Minn. Stat. 169.824 صيغة الجسر الفيدرالية (Federal Bridge Formula)، التي تسمح بوزن أكبر كلما زاد عدد المحاور وتباعدها. المصدر: Minn. Stat. 169.824؛ دليل CDL في مينيسوتا."},"9":{"q":"متى يُطلب تصريح الحجم/الوزن الزائد (OSOW) من MnDOT لنقل حمولة على طريق سريع في مينيسوتا؟","options":["فقط عندما تتجاوز الحمولة 100,000 رطل","عندما تتجاوز المركبة أو الحمولة أي حد قانوني للحجم أو الوزن","فقط للحمولات التي يزيد عرضها عن 10 أقدام","فقط على الطرق السريعة بين الولايات (Interstate)"],"explanation":"يُطلب تصريح OSOW من MnDOT كلما تجاوزت المركبة أو الحمولة حدًا قانونيًا للحجم أو الوزن وستتحرك على طريق سريع في مينيسوتا أو تعبره. المصدر: Minn. Stat. 169.86؛ تصاريح الحجم/الوزن الزائد MnDOT CVO."},"10":{"q":"بعد العرض القانوني البالغ 102 بوصة، إلى أي مدى يجوز قانونيًا أن تمتد المرايا الخلفية أو أجهزة تثبيت الحمولة التي ليست جزءًا لا يتجزأ من المركبة على كل جانب في مينيسوتا؟","options":["حتى 3 بوصات على كل جانب","حتى 6 بوصات على كل جانب","لا يجوز أن تمتد على الإطلاق","حتى 12 بوصة على كل جانب"],"explanation":"تسمح لائحة مينيسوتا 169.80 للمرايا أو أجهزة تثبيت الحمولة التي ليست جزءًا لا يتجزأ من المركبة بالامتداد حتى 3 بوصات بعد العرض البالغ 102 بوصة على كل جانب. المصدر: Minn. Stat. 169.80."},"11":{"q":"خلال زيادة الوزن الشتوية التي يعلنها المفوّض، بأي نسبة يجوز رفع حدود الوزن الإجمالي وأوزان المحاور الموسمية في مينيسوتا على الطرق المؤهلة؟","options":["5 بالمئة","10 بالمئة","15 بالمئة","20 بالمئة"],"explanation":"تجيز لائحة مينيسوتا 169.826 للمفوّض زيادة حدود الوزن بنسبة 10 بالمئة خلال فترة الشتاء (الطرق المتجمدة) المحددة لكل منطقة. المصدر: Minn. Stat. 169.826؛ MnDOT."},"12":{"q":"ما هو الارتفاع الذي يحق لحافلة ذات طابقين تعمل بموجب تصريح سنوي الوصول إليه في مينيسوتا، فوق الحد القياسي البالغ 13 قدمًا و6 بوصات؟","options":["13 قدمًا و9 بوصات","14 قدمًا و0 بوصة","14 قدمًا و3 بوصات","15 قدمًا و0 بوصة"],"explanation":"تسمح لائحة مينيسوتا 169.81 للحافلة ذات الطابقين بالوصول إلى ارتفاع 14 قدمًا و3 بوصات عند تشغيلها بموجب تصريح سنوي. المصدر: Minn. Stat. 169.81."},"13":{"q":"زيادة الوزن بنسبة 10 بالمئة لموسم الحصاد في مينيسوتا بموجب اللائحة 169.826 تنطبق على نقل أي من المنتجات الزراعية الخام التالية من الحقل إلى أول نقطة تفريغ؟","options":["الذرة وفول الصويا والقمح","بنجر السكر والجزر والبطاطس","التبن والقش والسيلاج","التفاح والعنب والبصل"],"explanation":"تمنح لائحة مينيسوتا 169.826، البند الفرعي 1a، زيادة بنسبة 10 بالمئة لموسم الحصاد لنقل بنجر السكر والجزر والبطاطس من حقل الحصاد إلى أول نقطة تفريغ، حتى 30 نوفمبر، بموجب تصريح. المصدر: Minn. Stat. 169.826."},"14":{"q":"كيف يتم الحصول على تصريح الحجم/الوزن الزائد وسجل الرحلة من MnDOT في الغالب؟","options":["بزيارة مكتب شرطة المقاطعة شخصيًا","عبر الإنترنت من خلال حساب MnDOT CVO الإلكتروني بعد الدفع","بإرسال نموذج ورقي بالبريد إلى الهيئة التشريعية","يُصدر تلقائيًا مع رخصة CDL"],"explanation":"يصدر MnDOT تصاريح OSOW السنوية أو الموسمية أو لرحلة واحدة عبر الإنترنت؛ ينشئ الناقل حساب CVO إلكترونيًا ويدفع قبل إصدار التصريح. المصدر: تصاريح الحجم/الوزن الزائد MnDOT CVO."},"15":{"q":"نصف المقطورة الممدّدة في مينيسوتا يجوز أن تصل إلى 53 قدمًا فقط إذا كانت المسافة من مسمار الارتكاز (الكينغ بين) إلى مركز المحور الخلفي لا تتجاوز أي قيمة؟","options":["40 قدمًا","41 قدمًا","43 قدمًا","46 قدمًا"],"explanation":"تسمح لائحة مينيسوتا 169.81 بنصف مقطورة يصل طولها إلى 53 قدمًا شريطة ألا تتجاوز المسافة من مسمار الارتكاز إلى مركز المحور الخلفي 43 قدمًا. المصدر: Minn. Stat. 169.81."},"16":{"q":"المركبات ذات الستة محاور التي تنقل الماشية حصريًا يجوز أن تعمل بوزن إجمالي يصل إلى أي حد على الطرق السريعة الرئيسية في مينيسوتا (بخلاف الطرق بين الولايات) بموجب تصريح؟","options":["80,000 رطل","84,000 رطل","88,000 رطل","90,000 رطل"],"explanation":"تسمح لائحة مينيسوتا 169.8261/169.824 بوزن إجمالي مصرّح به يصل إلى 88,000 رطل للمركبات ذات الستة محاور أو أكثر التي تنقل الماشية حصريًا على الطرق السريعة الرئيسية بخلاف الطرق بين الولايات. المصدر: Minn. Stat. 169.824؛ MnDOT CVO."},"17":{"q":"في مينيسوتا، أي فئة من رخص CDL مطلوبة لتشغيل مجموعة مركبات بتصنيف وزن إجمالي للمجموعة يتجاوز 26,000 رطل حيث تكون الوحدة المقطورة بتصنيف وزن إجمالي للمركبة (GVWR) يزيد عن 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"يعرّف دليل CDL في مينيسوتا (الجزء A) الفئة A بأنها أي مركبة تقطر وحدة بتصنيف وزن إجمالي للمركبة (GVWR) يزيد عن 10,000 رطل مع تصنيف وزن إجمالي للمجموعة (الشاحنة زائد المقطورة) يتجاوز 26,000 رطل. المصدر: دليل رخصة القيادة التجارية MN DVS، الجزء A."},"18":{"q":"بموجب قواعد مينيسوتا، المركبة أحادية الوحدة بتصنيف وزن إجمالي للمركبة (GVWR) يزيد عن 26,000 رطل (لا تقطر شيئًا، أو تقطر وحدة وزنها 10,000 رطل أو أقل) تتطلب أي فئة من رخص CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"يعرّف دليل CDL في مينيسوتا الفئة B بأنها مركبة أحادية الوحدة يزيد تصنيف وزنها الإجمالي (GVWR) عن 26,000 رطل؛ كما تغطي قطر وحدة لا تتجاوز 10,000 رطل. المصدر: دليل CDL في MN DVS، الجزء A."},"19":{"q":"في مينيسوتا، تنطبق رخصة CDL من الفئة C على مركبة أحادية الوحدة بتصنيف وزن إجمالي للمركبة (GVWR) قدره 26,000 رطل أو أقل فقط عندما تُستخدم المركبة لأي غرض؟","options":["أي مركبة تُستخدم للأجرة بغض النظر عن الحمولة","نقل المواد الخطرة التي تتطلب لافتات تحذيرية، أو نقل 16 راكبًا أو أكثر","قطر أي مقطورة يزيد وزنها عن 10,000 رطل","تشغيل أي مركبة خارج مينيسوتا"],"explanation":"ينص دليل CDL في مينيسوتا على أن الفئة C هي مركبة أحادية الوحدة بتصنيف وزن إجمالي 26,000 رطل أو أقل تنقل مواد خطرة (بلافتات تحذيرية) أو ركابًا، أو هي حافلة مدرسية، وتتطلب التظهير المقابل. المصدر: دليل CDL في MN DVS، الجزء A."},"20":{"q":"أي تظهير تتطلبه مينيسوتا لسائق يشغّل مركبة صهريجية مصممة لنقل السوائل أو الغازات في صهريج بسعة فردية مقدّرة تزيد عن 119 غالونًا وسعة إجمالية قدرها 1,000 غالون أو أكثر؟","options":["H (المواد الخطرة)","T (المقطورات المزدوجة/الثلاثية)","N (المركبة الصهريجية)","X (الصهريج والمواد الخطرة)"],"explanation":"يعرّف دليل CDL في مينيسوتا تظهير N (المركبة الصهريجية) لأي مركبة تجارية مصممة لنقل مواد سائلة أو غازية في صهريج بسعة فردية مقدّرة تزيد عن 119 غالونًا وسعة إجمالية مقدّرة قدرها 1,000 غالون أو أكثر. المصدر: دليل CDL في MN DVS، قسم التظهيرات."},"21":{"q":"في مينيسوتا، أي تظهير مطلوب لقطر مقطورات مزدوجة أو ثلاثية، وبأي فئة مركبة يرتبط عمومًا؟","options":["تظهير T، عمومًا لسائقي الفئة A","تظهير N، عمومًا لسائقي الفئة B","تظهير P، عمومًا لسائقي الفئة C","تظهير H، عمومًا لسائقي الفئة A"],"explanation":"ينص دليل CDL في مينيسوتا على أن تظهير T (المقطورات المزدوجة/الثلاثية) يُضاف إلى رخص سائقي الفئة A الراغبين في قطر مقطورات مزدوجة أو ثلاثية، ويتطلب اختبار معرفة خاصًا. المصدر: دليل CDL في MN DVS، التظهيرات / المقطورات المزدوجة والثلاثية."},"22":{"q":"أي تظهيرين تدمجهما مينيسوتا في تظهير واحد هو 'X'؟","options":["الركاب والحافلة المدرسية","المركبة الصهريجية والمواد الخطرة","المقطورات المزدوجة/الثلاثية والمركبة الصهريجية","المواد الخطرة والركاب"],"explanation":"يدرج دليل CDL في مينيسوتا تظهير X بوصفه 'الصهريج والمواد الخطرة'، وهو مطلوب لسائقي المركبات الصهريجية الذين ينقلون مواد/نفايات خطرة بكميات تستلزم لافتات تحذيرية، ويجب عليهم اجتياز اختباري معرفة الصهريج والمواد الخطرة معًا. المصدر: دليل CDL في MN DVS، التظهيرات."},"23":{"q":"في مينيسوتا، ما المطلوب قبل أن يُمنح السائق تظهير المواد الخطرة (H)، بالإضافة إلى اجتياز اختبار معرفة المواد الخطرة (HazMat)؟","options":["اختبار مهارات قيادة في مركبة صهريجية مزوّدة بلافتات تحذيرية","تقييم تهديد أمني من إدارة TSA يتضمن أخذ البصمات وفحص السجل","خمس سنوات من الخبرة الموثّقة في القيادة بين الولايات","تصريح حجم/وزن زائد منفصل من MnDOT"],"explanation":"ينص دليل CDL في مينيسوتا على أن إدارة أمن النقل (TSA) تجري فحصًا للسجل (سجلات جنائية وهجرة وسجلات FBI) وتتطلب البصمات قبل إصدار تظهير HazMat أو تجديده. المصدر: دليل CDL في MN DVS، المواد الخطرة / فحص السجل / البصمات."},"24":{"q":"في مينيسوتا، لا يمكن إضافة تظهير الحافلة المدرسية (S) إلى رخصة CDL إلا عندما يحمل السائق أيضًا أي تظهير آخر؟","options":["المركبة الصهريجية (N)","المقطورات المزدوجة/الثلاثية (T)","الركاب (P)","المواد الخطرة (H)"],"explanation":"تتطلب مينيسوتا أن يكون تظهير الحافلة المدرسية (S) مصحوبًا بتظهير الركاب (P)؛ ويحدد تعريف الفئة C في الدليل 'الحافلة المدرسية (مع تظهير الركاب)'. المصدر: دليل CDL في MN DVS، الجزء A / التظهيرات."},"25":{"q":"للحصول على تظهير الركاب (P) على رخصة CDL من الفئة B في مينيسوتا، يجب اجتياز اختبار المهارات (القيادة) في حافلة بتصنيف وزن إجمالي (GVWR) يزيد عن 26,000 رطل وسعة ركاب تبلغ كم، بما في ذلك السائق؟","options":["أكثر من 8","أكثر من 10","أكثر من 15","أكثر من 24"],"explanation":"ينص دليل CDL في مينيسوتا على أنه لتظهير الركاب (أو الحافلة المدرسية)، يجب اجتياز اختبار المهارات في حافلة بتصنيف وزن إجمالي (GVWR) يزيد عن 26,000 رطل وسعة ركاب تزيد عن 15، بما في ذلك السائق. المصدر: دليل CDL في MN DVS، الجزء A (الفئة B)."},"26":{"q":"ما هو الحد الأدنى للسن للتقدم بطلب الحصول على رخصة CDL في مينيسوتا مقيّدة بالقيادة التجارية داخل الولاية (داخل مينيسوتا)؟","options":["16 عامًا","18 عامًا","19 عامًا","21 عامًا"],"explanation":"يدرج دليل CDL في مينيسوتا حدًا أدنى للسن قدره 18 عامًا للتقدم بطلب رخصة CDL داخل الولاية (مثل مركبة مفردة يزيد وزنها الإجمالي عن 26,000 رطل أو مجموعة يزيد وزنها الإجمالي عن 26,000 رطل). المصدر: دليل CDL في MN DVS، الجزء A (الحد الأدنى للسن)."},"27":{"q":"بموجب قواعد مينيسوتا والقواعد الفيدرالية، ما هو عمومًا الحد الأدنى للسن لتشغيل مركبة تجارية في التجارة بين الولايات أو لنقل مواد خطرة تتطلب لافتات تحذيرية؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"يشير دليل CDL في مينيسوتا إلى أنه بالنسبة لأي مركبة من أي حجم تتطلب لافتات تحذيرية للمواد الخطرة يجب في معظم الحالات أن يكون عمرك 21 عامًا، كما يتطلب التشغيل بين الولايات عمومًا سن 21 عامًا. المصدر: دليل CDL في MN DVS، الجزء A (الحد الأدنى للسن / بين الولايات)."},"28":{"q":"ما هو الحد الأدنى للسن للحصول على تصريح المتعلّم التجاري (CLP) في مينيسوتا، وما الذي يجب أن يحمله مقدّم الطلب بالفعل؟","options":["16، مع تصريح متعلّم","18، مع رخصة قيادة سارية في مينيسوتا","19، مع رخصة قيادة سارية في مينيسوتا","21، مع رخصة سارية من الفئة D"],"explanation":"ينص دليل CDL في مينيسوتا على أنه يجب أن يكون عمرك 18 عامًا على الأقل وأن تحمل رخصة قيادة سارية في مينيسوتا للحصول على تصريح CLP. المصدر: دليل CDL في MN DVS، تصريح المتعلّم التجاري."},"29":{"q":"في مينيسوتا، كم يجب الاحتفاظ بتصريح المتعلّم التجاري (CLP) قبل أن يتمكن حامله من إجراء اختبار مهارات (القيادة) لرخصة CDL؟","options":["7 أيام تقويمية","10 أيام تقويمية","14 يومًا تقويميًا","30 يومًا تقويميًا"],"explanation":"ينص دليل CDL في مينيسوتا على أنه يجب الاحتفاظ بتصريح CLP لمدة 14 يومًا تقويميًا قبل التمكن من إجراء اختبارات القيادة لرخصة CDL، بما يطابق الحد الأدنى الفيدرالي. المصدر: دليل CDL في MN DVS، تصريح المتعلّم التجاري."},"30":{"q":"ما مدة صلاحية تصريح المتعلّم التجاري (CLP) في مينيسوتا، وما هي الفترة الإجمالية القصوى التي يمكن أن يظل ساريًا خلالها عبر التجديد؟","options":["90 يومًا، قابل للتجديد حتى 6 أشهر إجمالاً","180 يومًا، قابل للتجديد شريطة ألا يكون ساريًا لأكثر من سنة واحدة من تاريخ الإصدار الأولي","سنة واحدة، غير قابل للتجديد","سنتان، قابل للتجديد مرة واحدة"],"explanation":"ينص دليل CDL في مينيسوتا على أن تصاريح CLP سارية لمدة 180 يومًا ويمكن تجديدها شريطة ألا يكون تصريح CLP ساريًا لأكثر من سنة واحدة من تاريخ الإصدار الأولي. المصدر: دليل CDL في MN DVS، تصريح المتعلّم التجاري."},"31":{"q":"أثناء التدرّب على القيادة بتصريح CLP في مينيسوتا، يجب أن يكون حامل التصريح مصحوبًا بسائق يحمل ماذا؟","options":["أي رخصة قيادة سارية من الفئة D في مينيسوتا","رخصة CDL من الفئة والتظهيرات نفسها أو أعلى","شهادة مدرّب CDL من MnDOT","رخصة CDL مظهّرة للمواد الخطرة فقط"],"explanation":"يتطلب دليل CDL في مينيسوتا أن يكون حامل تصريح CLP مصحوبًا بسائق مرخّص ساري الرخصة يحمل الفئة نفسها من الرخصة والتظهيرات أو أعلى أثناء التدرّب على القيادة. المصدر: دليل CDL في MN DVS، تصريح المتعلّم التجاري."},"32":{"q":"أي مما يلي يُعدّ نشاطًا مسموحًا به لحامل تصريح CLP في مينيسوتا؟","options":["نقل مواد خطرة بتظهير H على تصريح CLP","تشغيل مركبة تجارية بمقطورات مزدوجة أو ثلاثية","التدرّب في مركبة صهريجية فارغة (مطهّرة) للحصول على تظهير الصهريج","نقل ركاب مقابل أجر لاكتساب الخبرة"],"explanation":"يسمح دليل CDL في مينيسوتا لحامل تصريح CLP المتدرّب لتظهير الصهريج بتشغيل مركبة صهريجية فارغة مطهّرة من البقايا فقط؛ ويحظر نقل المواد الخطرة وقطر المقطورات المزدوجة/الثلاثية ونقل الركاب. المصدر: دليل CDL في MN DVS، قيود تصريح المتعلّم التجاري."},"33":{"q":"أي مجموعة من التظهيرات تسمح مينيسوتا بإضافتها إلى تصريح المتعلّم التجاري (CLP)؟","options":["الركاب (P) والحافلة المدرسية (S) والمركبة الصهريجية (N)","المواد الخطرة (H) والمركبة الصهريجية (N)","المقطورات المزدوجة/الثلاثية (T) والركاب (P)","يمكن إضافة جميع التظهيرات الستة إلى تصريح CLP"],"explanation":"ينص دليل CDL في مينيسوتا على أن التظهيرات الوحيدة التي يمكن إضافتها إلى تصريح CLP هي الركاب (P) والحافلة المدرسية (S) والمركبة الصهريجية (N). المصدر: دليل CDL في MN DVS، التظهيرات (ملاحظة CLP)."},"34":{"q":"التدريب الفيدرالي للسائقين المبتدئين (ELDT)، المطلوب في مينيسوتا، يجب إكماله عبر مزوّد مدرج في ماذا، وينطبق على المتقدمين في أو بعد أي تاريخ؟","options":["سجل مزوّدي التدريب التابع لـ FMCSA، في أو بعد 7 فبراير 2022","السجل الوطني لفاحصي الطب المعتمدين، في أو بعد 21 مايو 2014","قائمة المدرّبين المعتمدين من TSA، في أو بعد 20 مارس 2025","قائمة مكتب خدمات الناقلين الآليين التابع لـ MnDOT، في أو بعد 1 يناير 2020"],"explanation":"يوضّح دليل CDL في مينيسوتا أن متطلبات ELDT تنطبق على الأفراد الحاصلين على رخصة CDL من الفئة A/B أو تظهير S أو P أو H في أو بعد 7 فبراير 2022، مع تقديم التدريب من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA. المصدر: دليل CDL في MN DVS، ELDT / سجل مزوّدي التدريب."},"35":{"q":"بموجب التدريب النظري لـ ELDT المقبول في مينيسوتا، ما هو الحد الأدنى للدرجة التي يجب أن يحققها السائق المبتدئ في التقييم النظري؟","options":["70% على الأقل","75% على الأقل","80% على الأقل","90% على الأقل"],"explanation":"يصف دليل CDL في مينيسوتا التدريب النظري لـ ELDT بأنه لا يتطلب حدًا أدنى من عدد الساعات لكنه يتطلب درجة لا تقل عن 80% في التقييم. المصدر: دليل CDL في MN DVS، ELDT (التدريب النظري)."},"36":{"q":"عند التقدم بطلب الحصول على تصريح CLP أو رخصة CDL في مينيسوتا، يجب على المتقدمين التصديق الذاتي على حالتهم الطبية. أي مجموعة مستندات يجب أن يقدّمها المتقدم غير المعفى إلى جانب نموذج التصديق الذاتي؟","options":["شهادة فاحص طبي سارية من فاحص معتمد في السجل الوطني","مجرد مذكرة من أي طبيب مرخّص","خطاب تقييم تهديد أمني من TSA","إعفاء داخل الولاية من MnDOT في كل حالة"],"explanation":"يتطلب دليل CDL في مينيسوتا أن يكمل المتقدمون لرخصة CDL/CLP نموذج التصديق الطبي الذاتي لرخصة القيادة التجارية، وأن يقدّموا، إذا كانوا خاضعين للمتطلبات الطبية، شهادة فاحص طبي سارية من فاحص مدرج في السجل الوطني لفاحصي الطب المعتمدين. المصدر: دليل CDL في MN DVS، التصديق الطبي الذاتي."},"37":{"q":"بموجب قانون مينيسوتا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده للشخص قانونيًا تشغيل مركبة تجارية (CMV)؟","options":["0.02 بالمئة","0.04 بالمئة","0.08 بالمئة","0.10 بالمئة"],"explanation":"ينص دليل CDL في مينيسوتا (القسم 1.3.2) على أنه من غير القانوني تشغيل مركبة تجارية بتركيز كحول في الدم (BAC) قدره 0.04 بالمئة أو أكثر، أي نصف حد 0.08 المقرر للسائقين غير التجاريين. المصدر: دليل رخصة القيادة التجارية Minnesota DVS، القسم 1.3.2؛ Minn. Stat. 169A.20."},"38":{"q":"يخضع سائق مركبة تجارية في مينيسوتا للاختبار ويُظهر كمية قابلة للكشف من الكحول تقل عن 0.04 بالمئة. ماذا يحدث؟","options":["لا يُتخذ أي إجراء لأن المستوى دون الحد","يُوضع السائق خارج الخدمة لمدة 24 ساعة","يفقد السائق رخصة CDL لمدة 60 يومًا","يفقد السائق رخصة CDL لمدة سنة واحدة"],"explanation":"تتبع مينيسوتا القاعدة التي تقضي بأن أي كمية كحول قابلة للكشف تقل عن 0.04 بالمئة تؤدي إلى أمر بالإيقاف عن الخدمة لمدة 24 ساعة، بينما تؤدي 0.04 أو أكثر إلى عدم الأهلية لمدة سنة واحدة. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.2؛ Minn. Stat. 169A.20."},"39":{"q":"بقيادة مركبة تجارية على الطرق العامة في مينيسوتا، يكون السائق قد وافق تلقائيًا على اختبار الدم أو النفَس أو البول. ماذا تُسمى هذه القاعدة؟","options":["قانون الموافقة الضمنية (Implied Consent Law)","قاعدة التنازل المفترض","قاعدة الاشتباه المعقول","قانون الاختبار الإلزامي"],"explanation":"يوضّح دليل CDL في مينيسوتا أن تشغيل مركبة تجارية على الطرق العامة يُشكّل موافقة تلقائية على الاختبار الكيميائي بموجب قانون الموافقة الضمنية. المصدر: دليل CDL في Minnesota DVS، قسم قانون الموافقة الضمنية؛ Minn. Stat. 169A.51."},"40":{"q":"في مينيسوتا، ما هو الحد الأدنى لفترة عدم الأهلية بالنسبة لحامل رخصة CDL عند أول مخالفة كبرى (مثل قيادة مركبة تجارية بتركيز كحول في الدم قدره 0.04 أو أكثر) عند عدم نقل مواد خطرة مزوّدة بلافتات تحذيرية؟","options":["60 يومًا","90 يومًا","سنة واحدة","ثلاث سنوات"],"explanation":"ينص دليل CDL في مينيسوتا على أن السائق يفقد رخصة CDL لمدة سنة واحدة على الأقل عند أول مخالفة كبرى مثل تركيز كحول في الدم 0.04+، أو القيادة تحت تأثير الكحول، أو الرفض، أو مغادرة موقع حادث، أو استخدام مركبة تجارية في جناية. المصدر: دليل CDL في Minnesota DVS، حالات عدم الأهلية للرخصة التجارية / القسم 1.3.2؛ 49 CFR 383.51."},"41":{"q":"إذا وقعت أول مخالفة كبرى مُسقطة للأهلية لحامل رخصة CDL أثناء تشغيل مركبة تجارية مزوّدة بلافتات تحذيرية للمواد الخطرة، فإن الحد الأدنى لفترة عدم الأهلية يزيد إلى:","options":["سنة واحدة","سنتان","ثلاث سنوات","خمس سنوات"],"explanation":"ينص دليل CDL في مينيسوتا على أنه إذا وقعت أول مخالفة مُسقطة للأهلية أثناء تشغيل مركبة تجارية مزوّدة بلافتات تحذيرية للمواد الخطرة، فإن السائق يفقد رخصة CDL لمدة ثلاث سنوات على الأقل بدلاً من سنة واحدة. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.2؛ 49 CFR 383.51."},"42":{"q":"ما هي فترة عدم الأهلية في مينيسوتا لثاني مخالفة كبرى (مُسقطة للأهلية) لحامل رخصة CDL؟","options":["ثلاث سنوات","عشر سنوات","مدى الحياة","خمس سنوات"],"explanation":"ينص دليل CDL في مينيسوتا على أن ثاني مخالفة مُسقطة للأهلية تؤدي إلى فقدان امتيازات رخصة CDL مدى الحياة (يمكن طلب إعادة الاستحقاق بعد 10 سنوات في ظروف محدودة). المصدر: دليل CDL في Minnesota DVS، القسم 1.3.2؛ 49 CFR 383.51."},"43":{"q":"يُطلب من سائق مركبة تجارية في مينيسوتا قانونيًا إجراء اختبار كيميائي فيرفض. ما هي العواقب على رخصة CDL؟","options":["تحذير دون عدم أهلية","عدم الأهلية لمدة 60 يومًا","عدم الأهلية لمدة سنة واحدة","عدم الأهلية لمدة 90 يومًا"],"explanation":"ينص دليل CDL في مينيسوتا على أن رفض الخضوع للاختبار الكيميائي يُسقط أهلية السائق لتشغيل مركبة تجارية لمدة سنة واحدة، كما تُلغى رخصة قيادة السائق لمدة سنة واحدة. ويُعامَل الرفض كمخالفة كبرى. المصدر: دليل CDL في Minnesota DVS، قانون الموافقة الضمنية / القسم 1.3.2."},"44":{"q":"في مينيسوتا، استخدام مركبة تجارية لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة (مثل توزيع المخدرات) يؤدي إلى أي عقوبة على رخصة CDL؟","options":["عدم الأهلية لمدة سنة واحدة","عدم الأهلية لمدة ثلاث سنوات","عدم الأهلية مدى الحياة دون إعادة استحقاق","عدم الأهلية لمدة 120 يومًا"],"explanation":"ينص دليل CDL في مينيسوتا على أن السائق يفقد رخصة CDL مدى الحياة إذا استُخدمت مركبة تجارية لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة؛ وهذا الحظر مدى الحياة لا يخضع لإعادة الاستحقاق المعتادة بعد 10 سنوات. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.2؛ 49 CFR 383.51."},"45":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة ثلاث سنوات (أثناء تشغيل مركبة تجارية) التي تستوجب عدم الأهلية لرخصة CDL لمدة 60 يومًا في مينيسوتا؟","options":["مخالفة واحدة","مخالفتان","ثلاث مخالفات","أربع مخالفات"],"explanation":"ينص دليل CDL في مينيسوتا (القسم 1.3.3) على أن مخالفتين مروريتين خطيرتين خلال فترة ثلاث سنوات تؤديان إلى عدم الأهلية لمدة 60 يومًا على الأقل. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.3؛ 49 CFR 383.51."},"46":{"q":"في مينيسوتا، ثلاث مخالفات مرورية خطيرة تُرتكب في مركبة تجارية خلال فترة ثلاث سنوات تؤدي إلى عدم الأهلية لرخصة CDL لمدة لا تقل عن:","options":["60 يومًا","90 يومًا","120 يومًا","سنة واحدة"],"explanation":"ينص دليل CDL في مينيسوتا (القسم 1.3.3) على أن ثلاث مخالفات مرورية خطيرة أو أكثر خلال فترة ثلاث سنوات تؤدي إلى عدم الأهلية لمدة 120 يومًا على الأقل. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.3؛ 49 CFR 383.51."},"47":{"q":"وفقًا لدليل CDL في مينيسوتا، تجاوز السرعة بأي مقدار فوق الحد المقرر يُعدّ 'مخالفة مرورية خطيرة'؟","options":["10 ميل/ساعة أو أكثر فوق الحد","15 ميل/ساعة أو أكثر فوق الحد","20 ميل/ساعة أو أكثر فوق الحد","25 ميل/ساعة أو أكثر فوق الحد"],"explanation":"يعرّف دليل CDL في مينيسوتا (القسم 1.3.3) السرعة المفرطة بأنها 15 ميل/ساعة أو أكثر فوق الحد المقرر بوصفها مخالفة مرورية خطيرة. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.3؛ 49 CFR 383.5."},"48":{"q":"أي مما يلي لا يُدرج كمخالفة مرورية خطيرة في دليل CDL في مينيسوتا؟","options":["السير خلف مركبة عن قرب شديد","تغيير المسار بشكل غير سليم أو متقلب","القيادة المتهورة","الوقوف في منطقة ممنوع الوقوف فيها"],"explanation":"يدرج دليل CDL في مينيسوتا (القسم 1.3.3) المخالفات الخطيرة على أنها السرعة المفرطة (15+ ميل/ساعة فوق الحد) والقيادة المتهورة وتغيير المسار غير السليم أو المتقلب والسير عن قرب شديد، من بين أخرى؛ وتُستثنى مخالفة الوقوف صراحةً. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.3."},"49":{"q":"في مينيسوتا، ما هو الحد الأدنى لعدم الأهلية لرخصة CDL عند أول مخالفة للسائق لأمر الإيقاف عن الخدمة؟","options":["30 يومًا","60 يومًا","90 يومًا","سنة واحدة"],"explanation":"ينص دليل CDL في مينيسوتا (القسم 1.3.4) على أن السائق يفقد رخصة CDL لمدة لا تقل عن 90 يومًا عند أول مخالفة لأمر الإيقاف عن الخدمة. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.4؛ 49 CFR 383.51."},"50":{"q":"بموجب قواعد مينيسوتا، مخالفتان لأمر الإيقاف عن الخدمة خلال فترة عشر سنوات تؤديان إلى عدم الأهلية لرخصة CDL لمدة لا تقل عن:","options":["90 يومًا","سنة واحدة","ثلاث سنوات","120 يومًا"],"explanation":"ينص دليل CDL في مينيسوتا (القسم 1.3.4) على أن مخالفتين لأمر الإيقاف عن الخدمة خلال فترة عشر سنوات تؤديان إلى عدم الأهلية لمدة سنة واحدة على الأقل. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.4؛ 49 CFR 383.51."},"51":{"q":"ثلاث مخالفات أو أكثر لأمر الإيقاف عن الخدمة خلال فترة عشر سنوات تؤدي إلى عدم الأهلية لرخصة CDL في مينيسوتا لمدة لا تقل عن:","options":["سنة واحدة","سنتان","ثلاث سنوات","خمس سنوات"],"explanation":"ينص دليل CDL في مينيسوتا (القسم 1.3.4) على أن ثلاث مخالفات أو أكثر لأمر الإيقاف عن الخدمة خلال فترة عشر سنوات تؤدي إلى عدم الأهلية لمدة ثلاث سنوات على الأقل. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.4؛ 49 CFR 383.51."},"52":{"q":"في مينيسوتا، أول مخالفة عند تقاطع السكة الحديدية مع الطريق السريع تؤدي إلى عدم الأهلية لرخصة CDL لمدة لا تقل عن:","options":["30 يومًا","60 يومًا","90 يومًا","120 يومًا"],"explanation":"ينص دليل CDL في مينيسوتا (القسم 1.3.5) على أن أول مخالفة عند تقاطع السكة الحديدية مع الطريق السريع تؤدي إلى عدم الأهلية لمدة 60 يومًا على الأقل. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.5؛ 49 CFR 383.51."},"53":{"q":"بموجب قواعد مينيسوتا، ثالث مخالفة عند تقاطع السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات تؤدي إلى عدم الأهلية لرخصة CDL لمدة لا تقل عن:","options":["120 يومًا","180 يومًا","سنة واحدة","ثلاث سنوات"],"explanation":"ينص دليل CDL في مينيسوتا (القسم 1.3.5) على 60 يومًا للأولى، و120 يومًا للثانية خلال ثلاث سنوات، وما لا يقل عن سنة واحدة للثالثة خلال فترة ثلاث سنوات. المصدر: دليل CDL في Minnesota DVS، القسم 1.3.5؛ 49 CFR 383.51."},"54":{"q":"كم عدد الإدانات لاستخدام هاتف محمول يدوي أثناء تشغيل مركبة تجارية التي يجب أن تكون لدى سائق في مينيسوتا قبل إسقاط أهلية رخصة CDL؟","options":["إدانة واحدة","إدانتان أو أكثر","ثلاث إدانات أو أكثر","خمس إدانات أو أكثر"],"explanation":"ينص دليل CDL في مينيسوتا على أن أهلية رخصة CDL تُسقط بعد إدانتين أو أكثر بموجب قانون الولاية المتعلق باستخدام هاتف محمول يدوي أثناء تشغيل مركبة تجارية (60 يومًا للإدانة الثانية خلال 3 سنوات، و120 يومًا لثلاث إدانات أو أكثر). المصدر: دليل CDL في Minnesota DVS، القسم 2.9.4؛ Minn. Stat. 169.475."},"55":{"q":"إلى جانب إسقاط أهلية رخصة CDL، ما هو الحد الأقصى للغرامة المدنية التي قد يواجهها سائق مركبة تجارية في مينيسوتا عن كل مخالفة استخدام هاتف يدوي أو إرسال رسائل نصية أثناء القيادة؟","options":["حتى 500 دولار","حتى 1,000 دولار","حتى 2,750 دولارًا","حتى 11,000 دولار"],"explanation":"ينص دليل CDL في مينيسوتا على أن أول مخالفة وكل مخالفة لاحقة لاستخدام هاتف يدوي أو إرسال رسائل نصية تخضع لغرامات مدنية على السائق تصل إلى 2,750 دولارًا (وأصحاب العمل الذين يسمحون بها أو يطلبونها يواجهون غرامات تصل إلى 11,000 دولار). المصدر: دليل CDL في Minnesota DVS، القسمان 2.9.4 و2.9.5."},"56":{"q":"يُضبط حامل رخصة CDL في مينيسوتا وهو يقود مركبة غير تجارية (شخصية) بتركيز كحول في الدم قدره 0.08 بالمئة أو أكثر. ما هو الأثر على رخصة CDL؟","options":["لا أثر، بما أنها لم تكن مركبة تجارية","عدم الأهلية لقيادة المركبات التجارية لمدة سنة واحدة على الأقل","عدم الأهلية لمدة 60 يومًا","عدم الأهلية لمدة 90 يومًا"],"explanation":"ينص دليل CDL في مينيسوتا على أن تركيز كحول في الدم قدره 0.08 بالمئة أو أكثر في مركبة غير تجارية يُلغي امتيازات الفئة D ويُسقط أهلية السائق لتشغيل المركبات التجارية لمدة سنة واحدة على الأقل. المصدر: دليل CDL في Minnesota DVS، إلغاء امتيازات الفئة D وإسقاط أهلية امتيازات CDL؛ Minn. Stat. 171.165."},"57":{"q":"عند الاقتراب من تقاطع سكة حديد في مينيسوتا، السائق الملزم بالتوقف (مثل حافلة تقل ركاباً) يجب أن يوقف المركبة ضمن أي مسافة من أقرب قضيب؟","options":["على الأقل 15 قدماً ولكن ليس أكثر من 50 قدماً","على الأقل 10 أقدام ولكن ليس أكثر من 25 قدماً","على الأقل 25 قدماً ولكن ليس أكثر من 75 قدماً","على الأقل 5 أقدام ولكن ليس أكثر من 15 قدماً"],"explanation":"يتطلب دليل CDL في مينيسوتا و Minn. Stat. 169.28 من المركبات الملزمة بالتوقف عند تقاطعات سكك الحديد أن تتوقف على مسافة لا تقل عن 15 قدماً ولا تزيد عن 50 قدماً من أقرب قضيب. المصدر: دليل CDL في مينيسوتا (تقاطع سكة الحديد)؛ Minn. Stat. 169.28."},"58":{"q":"بموجب قواعد CDL في مينيسوتا، أي مجموعة من المركبات يجب أن تتوقف عند جميع تقاطعات سكك الحديد سواء كان هناك قطار مقترب أم لا؟","options":["الحافلات التي تقل ركاباً، والحافلات المدرسية (محملة أو غير محملة)، والمركبات الحاملة للوحات تحذيرية","فقط المركبات التي يزيد وزنها الإجمالي عن 26,001 رطل","فقط تركيبات المقطورات الثلاثية والصهاريج التي تزيد سعتها عن 1,000 جالون","أي مركبة تجارية تجر مقطورة من أي نوع"],"explanation":"يُدرج دليل CDL في مينيسوتا المركبات الملزمة بالتوقف عند كل تقاطع سكة حديد على أنها الحافلات التي تقل ركاباً، والحافلات المدرسية (سواء كانت تقل ركاباً أم لا)، والمركبات الحاملة للوحات تحذيرية. المصدر: دليل CDL في مينيسوتا (تقاطع سكة الحديد)؛ 49 CFR 392.10 كما هو معتمد في مينيسوتا."},"59":{"q":"على طريق ذي مسارين في مينيسوتا يحمل حركة المرور في كلا الاتجاهين، عندما تتوقف حافلة مدرسية مع ذراع التوقف ممدودة والأضواء الحمراء وامضة، يجب على السائق المقترب أن يتوقف على مسافة لا تقل عن كم من الحافلة؟","options":["على الأقل 20 قدماً","على الأقل 10 أقدام","على الأقل 30 قدماً","على الأقل 50 قدماً"],"explanation":"يتطلب Minn. Stat. 169.444, subd. 1 ودليل CDL في مينيسوتا من السائق الذي يقترب من حافلة مدرسية متوقفة تعرض ذراع إشارة توقف ممدودة وأضواء حمراء وامضة أن يتوقف على مسافة لا تقل عن 20 قدماً وأن يبقى متوقفاً حتى تُسحب الذراع وتتوقف الأضواء عن الوميض. المصدر: Minn. Stat. 169.444؛ دليل CDL في مينيسوتا."},"60":{"q":"بموجب قانون مينيسوتا، على أي نوع من الطرق لا يكون السائق ملزماً بالتوقف لحافلة مدرسية تقوم بتحميل أو إنزال الركاب على الجانب المقابل؟","options":["طريق ذو مسارات منفصلة مقسومة بحاجز مادي، أو جزيرة وسطية مرتفعة، أو جزيرة وسطية منخفضة","أي طريق به مساران أو أكثر في كل اتجاه","أي طريق به خط وسطي مرسوم يفصل المسارات المتقابلة","أي طريق به مسار انعطاف يسار ثنائي الاتجاه في الوسط"],"explanation":"يعفي Minn. Stat. 169.444, subd. 4 السائق من التوقف فقط عندما تكون الحافلة على طريق مختلف وتكون الطرق 'منفصلة'، أي مقسومة بحاجز مادي، أو جزيرة وسطية مرتفعة، أو جزيرة وسطية منخفضة. الخط المرسوم أو مسار الانعطاف الوسطي ليس طريقاً منفصلاً. المصدر: Minn. Stat. 169.444, subd. 4."},"61":{"q":"ما هو الحد الأقصى للسرعة القانونية على طريق إنترستيت ريفي في مينيسوتا خارج أي منطقة حضرية؟","options":["70 mph","65 mph","75 mph","60 mph"],"explanation":"يحدد Minn. Stat. 169.14 حد السرعة بـ 70 mph على طرق الإنترستيت خارج حدود أي منطقة حضرية، و 65 mph داخل المنطقة الحضرية. المصدر: Minn. Stat. 169.14, subd. 2؛ MnDOT."},"62":{"q":"في مينيسوتا، ما هو حد السرعة الذي ينطبق على شاحنة نصف مقطورة محملة على طريق إنترستيت ريفي مقارنة بسيارة الركاب؟","options":["نفس الحد المطبق على السيارات؛ لا تحدد مينيسوتا حد سرعة أدنى منفصلاً للشاحنات","10 mph أقل من الحد المنشور للسيارات","حد أقصى ثابت قدره 60 mph للشاحنات على مستوى الولاية","5 mph أقل من الحد المنشور للسيارات"],"explanation":"لا تحدد مينيسوتا حد سرعة منفصلاً وأدنى للشاحنات أو المركبات التجارية. تنطبق الحدود القانونية المنشورة في Minn. Stat. 169.14 بالتساوي على جميع المركبات. المصدر: Minn. Stat. 169.14؛ إرشادات حدود السرعة من MnDOT."},"63":{"q":"بموجب قانون 'Ted Foss' للابتعاد (Move Over) في مينيسوتا، على طريق به مساران بالضبط في نفس الاتجاه، ماذا يجب على السائق أن يفعل عند الاقتراب من مركبة مُرخّصة متوقفة تعرض أضواءً وامضة أو تحذيرية؟","options":["الانتقال بأمان إلى المسار الأبعد عن المركبة المُرخّصة إن أمكن","التوقف توقفاً كاملاً حتى تغادر المركبة المُرخّصة","إطلاق البوق والحفاظ على المسار والسرعة الحاليين","الانتقال إلى المسار الأقرب من المركبة المُرخّصة للمرور بقربها وببطء"],"explanation":"يتطلب Minn. Stat. 169.18, subd. 11(b) من السائق الانتقال بأمان إلى المسار الأبعد عن مركبة مُرخّصة متوقفة مع أضواء مفعّلة عندما يكون هناك مساران في نفس الاتجاه. المصدر: Minn. Stat. 169.18, subd. 11؛ Minnesota DPS (قانون Ted Foss للابتعاد)."},"64":{"q":"بموجب قانون الابتعاد (Move Over) في مينيسوتا، على طريق به أكثر من مسارين في نفس الاتجاه، ما الذي يُطلب من السائق فعله عند تجاوز مركبة مُرخّصة متوقفة مع تفعيل أضوائها؟","options":["ترك مسار كامل فارغ بينه وبين المسار الذي تشغله المركبة المُرخّصة، إن كان ذلك آمناً","التوقف توقفاً كاملاً في المسار الأقصى يميناً","خفض السرعة إلى نصف الحد المنشور بالضبط مع البقاء في نفس المسار","الانتقال إلى المسار المجاور مباشرة للمركبة المُرخّصة"],"explanation":"يتطلب Minn. Stat. 169.18, subd. 11(c) من السائق على طريق به أكثر من مسارين في نفس الاتجاه أن ينتقل بأمان بحيث يترك مساراً كاملاً فارغاً بينه وبين أي مسار تشغله المركبة المُرخّصة. المصدر: Minn. Stat. 169.18, subd. 11."},"65":{"q":"أي مما يلي مشمول في تعريف مينيسوتا لـ 'المركبة المُرخّصة' المحمية بموجب قانون الابتعاد (Move Over)؟","options":["شاحنة قطر، أو مركبة تابعة لشركة مرافق، أو مركبة نفايات صلبة/إعادة تدوير مع تفعيل الأضواء","فقط سيارات إنفاذ القانون المعلّمة","فقط سيارات الإسعاف ومركبات الإطفاء","أي سيارة ركاب مع تشغيل أضواء الوقوف"],"explanation":"يعرّف Minn. Stat. 169.18, subd. 11(a) 'المركبة المُرخّصة' على نطاق واسع ليشمل مركبات الطوارئ، وشاحنات القطر، ومركبات دورية خدمة الطريق السريع، ومركبات صيانة الطرق، ومركبات شركات المرافق، ومركبات البناء، ومركبات خدمة البريد، ومركبات النفايات الصلبة أو إعادة التدوير. المصدر: Minn. Stat. 169.18, subd. 11(a)."},"66":{"q":"إذا اضطرت مركبة تجارية للتوقف على طريق سريع أحادي الاتجاه أو مقسوم في مينيسوتا أو بجانبه، أين يجب على السائق وضع أجهزة التحذير الطارئة الثلاثة؟","options":["10 أقدام، و100 قدم، و200 قدم باتجاه حركة المرور المقتربة","25 قدماً، و100 قدم، و300 قدم باتجاه حركة المرور المقتربة","10 أقدام، و50 قدماً، و150 قدماً باتجاه حركة المرور المقتربة","15 قدماً، و75 قدماً، و250 قدماً باتجاه حركة المرور المقتربة"],"explanation":"يتطلب دليل CDL في مينيسوتا (و49 CFR 392.22) أن توضع أجهزة التحذير الثلاثة على طريق سريع أحادي الاتجاه أو مقسوم على مسافة 10 أقدام، و100 قدم، و200 قدم من المركبة باتجاه حركة المرور المقتربة. المصدر: دليل CDL في مينيسوتا (الإعلان عن وجودك)؛ 49 CFR 392.22."},"67":{"q":"خلال كم دقيقة من التوقف على طريق أو على الكتف يجب على السائق التجاري في مينيسوتا أن يضع أجهزة التحذير الطارئة المطلوبة؟","options":["خلال 10 دقائق","خلال 5 دقائق","خلال 15 دقيقة","خلال 30 دقيقة"],"explanation":"ينص دليل CDL في مينيسوتا على أنه إذا اضطررت للتوقف على طريق أو كتف، فيجب عليك وضع أجهزة التحذير الطارئة خلال عشر دقائق. المصدر: دليل CDL في مينيسوتا (الإعلان عن وجودك)؛ 49 CFR 392.22."},"68":{"q":"على طريق غير مقسوم ذي مسارين في مينيسوتا يحمل حركة المرور في كلا الاتجاهين، أين يجب على السائق التجاري المتوقف وضع أجهزة التحذير؟","options":["ضمن 10 أقدام من الزوايا الأمامية أو الخلفية و100 قدم خلف المركبة وأمامها","10 أقدام، و100 قدم، و200 قدم باتجاه حركة المرور المقتربة فقط","جهاز واحد فقط على مسافة 500 قدم إلى الخلف","ضمن 50 قدماً من المركبة على جانب حركة المرور فقط"],"explanation":"يحدد دليل CDL في مينيسوتا أنه على طريق ذي مسارين يحمل حركة المرور في كلا الاتجاهين (طريق غير مقسوم)، توضع أجهزة التحذير ضمن 10 أقدام من الزوايا الأمامية أو الخلفية لتمييز المركبة، و100 قدم خلف المركبة وأمامها. المصدر: دليل CDL في مينيسوتا (الإعلان عن وجودك)؛ 49 CFR 392.22."},"69":{"q":"كم عدد المثلثات العاكسة الحمراء التي تحتاجها المركبة التجارية في مينيسوتا كأجهزة تحذير مطلوبة للمركبة المتوقفة؟","options":["ثلاثة مثلثات عاكسة (أو 6 شعلات أو 3 شعلات احتراق سائل)","مثلثان عاكسان","أربعة مثلثات عاكسة","مثلث عاكس واحد بالإضافة إلى راية واحدة"],"explanation":"يتطلب دليل CDL في مينيسوتا أجهزة تحذير للمركبات المتوقفة تتكون من ثلاثة مثلثات عاكسة، أو ما لا يقل عن 6 شعلات، أو 3 شعلات احتراق سائل. المصدر: دليل CDL في مينيسوتا (أجهزة التحذير للمركبات المتوقفة)؛ 49 CFR 393.95."},"70":{"q":"في مينيسوتا، عندما تسير شاحنة أو حافلة على طريق خارج منطقة تجارية أو سكنية، لا يجوز لها أن تتبع مركبة أخرى بمسافة أقرب من أي مسافة؟","options":["500 قدم","300 قدم","200 قدم","100 قدم"],"explanation":"ينص Minn. Stat. 169.18, subd. 8(b) على أنه لا يجوز لسائق شاحنة آلية، أو حافلة، أو مركبة تجر مركبة أخرى أن يتبع مركبة أخرى ضمن 500 قدم عند السير خارج منطقة تجارية أو سكنية. المصدر: Minn. Stat. 169.18, subd. 8."},"71":{"q":"يجب على سائق الحافلة المدرسية في مينيسوتا تفعيل أضواء التحذير الرباعية (أضواء الخطر) على أي مسافة قبل أقرب قضيب عند تقاطع سكة الحديد؟","options":["على الأقل 100 قدم من أقرب قضيب","على الأقل 25 قدماً من أقرب قضيب","على الأقل 300 قدم من أقرب قضيب","على الأقل 50 قدماً من أقرب قضيب"],"explanation":"يتطلب قسم الحافلة المدرسية من دليل CDL في مينيسوتا من سائق الحافلة المدرسية تشغيل أضواء التحذير الرباعية (أضواء الخطر) على مسافة لا تقل عن 100 قدم من أقرب قضيب، مع إيقاف المفتاح الرئيسي، ويحظر استخدام نظام الأضواء الثمانية عند تقاطع سكة الحديد. المصدر: دليل CDL في مينيسوتا (تقاطعات سكك الحديد للحافلات المدرسية)."},"72":{"q":"السائق في مينيسوتا الذي يفشل في التوقف لحافلة مدرسية تعرض ذراع توقفها الممدودة وأضواءها الحمراء الوامضة يكون، كحد أدنى، مذنباً بأي مخالفة؟","options":["جنحة يُعاقب عليها بغرامة لا تقل عن $500","جنحة بسيطة بغرامة قصوى قدرها $50","مخالفة بدون غرامة للمخالفة الأولى","جناية في كل حالة"],"explanation":"بموجب Minn. Stat. 169.444 ودليل CDL في مينيسوتا، يكون السائق الذي يفشل في التوقف لحافلة مدرسية كما هو مطلوب مذنباً بجنحة يُعاقب عليها بغرامة لا تقل عن $500، مع احتمال تعليق الرخصة. المصدر: Minn. Stat. 169.444؛ دليل CDL في مينيسوتا."},"73":{"q":"تجاوز حافلة مدرسية متوقفة من الجانب الأيمن (جانب باب الركاب)، أو التجاوز عندما يكون طفل في الخارج على الطريق، يرفع مخالفة السائق في مينيسوتا إلى أي مستوى؟","options":["جنحة جسيمة خاضعة لإلغاء الرخصة","مخالفة مرورية بسيطة بنقاط فقط","جنحة بسيطة","مخالفة وقوف مدنية"],"explanation":"يجعل Minn. Stat. 169.444 ودليل CDL في مينيسوتا من الفشل في التوقف ثم التجاوز من جانب باب الركاب الأيمن للحافلة، أو التجاوز بينما يكون طفل مدرسي في الخارج على الشارع أو الطريق السريع أو الرصيف المجاور، جنحة جسيمة خاضعة للإلغاء. المصدر: Minn. Stat. 169.444؛ دليل CDL في مينيسوتا."},"74":{"q":"فيما يتعلق بالرسوم، أي عبارة تصف على أفضل وجه نظام الإنترستيت والطرق السريعة في مينيسوتا بالنسبة للسائقين التجاريين؟","options":["لا تملك مينيسوتا طرقاً برسوم تقليدية؛ توجد فقط مسارات سريعة اختيارية E-ZPass MN (المعروفة سابقاً بـ MnPASS) في منطقة المدن التوأم","تتطلب جميع طرق الإنترستيت في مينيسوتا جهاز إرسال رسوم للشاحنات","يجب على الشاحنات دفع رسوم لكل محور على كل طريق إنترستيت في مينيسوتا","تشغّل مينيسوتا شبكة طرق برسوم على مستوى الولاية مثل Indiana Toll Road"],"explanation":"لا تملك مينيسوتا طرقاً برسوم تقليدية؛ والتحصيل الوحيد للرسوم هو في المسارات السريعة الاختيارية E-ZPass Minnesota (المعروفة سابقاً بـ MnPASS) على I-394 و I-35W و I-35E في منطقة المدن التوأم، مع توفر مسارات مجانية للأغراض العامة دائماً بجانبها. المصدر: MnDOT؛ Minnesota DPS."},"75":{"q":"حامل رخصة CDL في مينيسوتا المُدان بمخالفة واحدة لتقاطع سكة حديد أثناء تشغيل مركبة تجارية يُحرم من تشغيل مركبة تجارية لمدة لا تقل عن كم؟","options":["60 يوماً","30 يوماً","120 يوماً","سنة واحدة"],"explanation":"ينص دليل CDL في مينيسوتا على أن السائق يُحرم لمدة 60 يوماً للمخالفة الأولى لتقاطع سكة الحديد، و120 يوماً لمخالفتين في أي فترة ثلاث سنوات، وسنة واحدة لثلاث مخالفات أو أكثر في أي فترة ثلاث سنوات. المصدر: دليل CDL في مينيسوتا (مخالفة تقاطع سكة الحديد)؛ 49 CFR 383.51."},"76":{"q":"على طريق سريع متعدد المسارات في مينيسوتا، ماذا تتطلب قاعدة استخدام المسارات في الولاية من مركبة تجارية تسير بسرعة أبطأ من السرعة الطبيعية لحركة المرور؟","options":["القيادة في المسار الأيمن أو أقرب ما يمكن من الحافة اليمنى، إلا عند التجاوز أو الانعطاف يساراً","البقاء في المسار الأوسط دائماً حتى تتمكن حركة المرور الأسرع من استخدام كلا المسارين الخارجيين","شغل المسار الأيسر لإبقاء المسار الأيمن مفتوحاً لحركة المرور المندمجة","استخدام الكتف كلما كانت حركة المرور أكثف من المعتاد"],"explanation":"يتطلب Minn. Stat. 169.18, subd. 10 من المركبة التي تسير بسرعة أبطأ من حركة المرور الطبيعية أن تُقاد في المسار الأيمن المتاح حينها، أو أقرب ما يمكن من الرصيف أو الحافة اليمنى، إلا عند اللحاق والتجاوز، أو التحضير للانعطاف يساراً، أو حيث يكون المسار مخصصاً لاستخدام معين. المصدر: Minn. Stat. 169.18, subd. 10."},"77":{"q":"أي وكالة في مينيسوتا تُصدر رخص القيادة التجارية وتدير اختبارات CDL في الولاية؟","options":["إدارة السلامة العامة، خدمات السائقين والمركبات (DVS)","قسم المركبات التجارية في دورية ولاية مينيسوتا","الإدارة الفيدرالية لسلامة الناقلين بالمركبات الآلية (FMCSA)","وزارة النقل في مينيسوتا (MnDOT)"],"explanation":"تُصدر رخص CDL في مينيسوتا من قبل إدارة السلامة العامة من خلال شعبة خدمات السائقين والمركبات (DVS) التابعة لها، والتي تدير أيضاً اختبارات المعرفة والمهارات. تتولى MnDOT الإعفاءات الطبية داخل الولاية وتصاريح الحمولات الزائدة الحجم/الوزن، وليس الترخيص. المصدر: دليل CDL في مينيسوتا، الجزء A (DVS، إدارة السلامة العامة)."},"78":{"q":"في مينيسوتا، يجب على كل متقدم لرخصة CDL أولاً الحصول على أي وثيقة تسمح بالتدريب على القيادة تحت الإشراف في مركبة تجارية؟","options":["تصريح متعلّم تجاري (CLP)","شهادة مؤقتة لاختبار المهارات","إعفاء CDL تعليمي","تصديق تجاري مؤقت"],"explanation":"تتطلب مينيسوتا من جميع المتقدمين لرخصة CDL أولاً الحصول على تصريح متعلّم تجاري (CLP)، الذي يسمح بالتدريب على القيادة فقط مع سائق آخر مرخّص بشكل صحيح من نفس الفئة أو أعلى في المركبة. المصدر: دليل CDL في مينيسوتا، الجزء A، اختبارات رخصة القيادة التجارية."},"79":{"q":"ما هو الحد الأدنى للسن للحصول على تصريح متعلّم تجاري (CLP) في مينيسوتا؟","options":["18 عاماً","17 عاماً","21 عاماً","16 عاماً"],"explanation":"يجب أن يكون عمرك 18 عاماً على الأقل وأن تحمل رخصة قيادة سارية في مينيسوتا للحصول على CLP. يجب أن يكون عمرك 21 عاماً لقيادة مركبة تجارية في التجارة بين الولايات. المصدر: دليل CDL في مينيسوتا، الجزء A، اختبارات رخصة القيادة التجارية."},"80":{"q":"بعد التقدم بطلب للحصول على CLP في مينيسوتا، كم يجب على المتقدم أن يحتفظ به قبل السماح له بإجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["14 يوماً تقويمياً","10 أيام تقويمية","7 أيام تقويمية","30 يوماً تقويمياً"],"explanation":"تتطلب مينيسوتا الاحتفاظ بـ CLP لمدة 14 يوماً تقويمياً من تاريخ التقديم قبل أن يتمكن المتقدم من إجراء اختبار مهارات CDL. المصدر: دليل CDL في مينيسوتا، الجزء A، اختبارات رخصة القيادة التجارية."},"81":{"q":"كم تبلغ صلاحية تصريح المتعلّم التجاري (CLP) في مينيسوتا من تاريخ إصداره؟","options":["سنة واحدة","سنتان","90 يوماً","180 يوماً"],"explanation":"يكون CLP في مينيسوتا سارياً لمدة 180 يوماً. يمكن تجديده، لكنه لا يمكن أن يكون سارياً لأكثر من سنة واحدة من تاريخ الإصدار الأولي. المصدر: دليل CDL في مينيسوتا، الجزء A، اختبارات رخصة القيادة التجارية."},"82":{"q":"ينقسم اختبار مهارات CDL في مينيسوتا إلى أي ثلاث مراحل؟","options":["فحص فرامل الهواء، والوصل/الفصل، والقيادة على الطريق السريع","الامتحان التحريري، وفحص النظر، واختبار الطريق","فحص المركبة، ومهارات التحكم الأساسية، واختبار الطريق","أوراق ما قبل الرحلة، والرجوع للخلف في الساحة، واختبار القيادة الدفاعية"],"explanation":"يتكون اختبار مهارات CDL في مينيسوتا من ثلاث مراحل: (1) فحص المركبة (ما قبل الرحلة)، (2) اختبار مهارات التحكم الأساسية، و(3) اختبار الطريق. يجب إجراء جميع الثلاثة في نوع المركبة التي ترغب في الحصول على رخصة لها. المصدر: دليل CDL في مينيسوتا، الجزء A، اختبارات المهارات."},"83":{"q":"خلال مرحلة فحص المركبة في اختبار CDL في مينيسوتا، ماذا يجب على المتقدم أن يفعل ليحصل على درجة لكل بند؟","options":["إكمال الفحص بصمت ضمن حد زمني محدد","استبدال أي أجزاء بالية يتم العثور عليها أثناء الفحص","النزول تحت المركبة والتحقق من جميع مستويات السوائل","الإشارة إلى كل بند وشرح المشاكل التي يجب البحث عنها على مركبة باردة"],"explanation":"في فحص المركبة، يجب على المتقدم الإشارة إلى كل بند للفاحص وشرح المشاكل التي يجب البحث عنها على مركبة باردة، مع ذكر النقاط الرئيسية للحصول على الدرجة. لست مطالباً بالنزول تحت المركبة أو فحص السوائل. المصدر: دليل CDL في مينيسوتا، الجزء A، فحص المركبة."},"84":{"q":"كم مرة في اليوم يجوز للمتقدم لرخصة CDL في مينيسوتا أن يحاول كل اختبار معرفة على حدة؟","options":["ثلاث مرات في اليوم","مرتان في اليوم","محاولات غير محدودة في اليوم","مرة واحدة في اليوم"],"explanation":"يُقدَّم اختبار معرفة CDL باللغة الإنجليزية على ورق أو على الحاسوب، ويجوز للمتقدم أن يحاول كل اختبار معرفة مرة واحدة فقط في اليوم. المصدر: دليل CDL في مينيسوتا، الجزء A، اختبارات المعرفة."},"85":{"q":"أصبح تدريب السائقين المبتدئين (ELDT) إلزامياً للمتقدمين لأول مرة من الفئة A/الفئة B في مينيسوتا وبعض التصديقات في أي تاريخ؟","options":["21 مايو 2014","1 نوفمبر 2021","7 فبراير 2022","4 يناير 2020"],"explanation":"تنطبق متطلبات ELDT على الأفراد الذين يحصلون على رخصة CDL من الفئة A أو B (أو تصديق S أو P أو H) في أو بعد 7 فبراير 2022. ويُعفى المتقدم الذي صدر CLP الساري الخاص به قبل ذلك التاريخ إذا حصل على رخصة CDL قبل انتهاء صلاحية CLP. المصدر: دليل CDL في مينيسوتا، ELDT (سجل مزودي التدريب التابع لـ FMCSA)."},"86":{"q":"بموجب قاعدة ELDT الفيدرالية المطبقة في مينيسوتا، ما المطلوب لاجتياز الجزء النظري (الصفّي) من التدريب؟","options":["تحقيق ما لا يقل عن 70% في التقييم النظري","تحقيق ما لا يقل عن 80% في التقييم النظري","اجتياز تقييم محاكي القيادة خلف المقود","إكمال ما لا يقل عن 30 ساعة صفّية"],"explanation":"لا يوجد حد أدنى لعدد الساعات في التدريب النظري لـ ELDT، لكن يجب على المتدرب تحقيق ما لا يقل عن 80% في التقييم النظري. لا يوجد حد أدنى للساعات في التدريب خلف المقود ويُقيَّم على أساس الكفاءة من قبل المزود. المصدر: دليل CDL في مينيسوتا، ELDT (سجل مزودي التدريب التابع لـ FMCSA)."},"87":{"q":"قبل أن يتمكن السائق المبتدئ من إجراء جزء القيادة خلف المقود (BTW) من ELDT في مينيسوتا، ما الذي يجب أن يكون لديه بالفعل؟","options":["شهادة فاحص طبي DOT فقط","تصريح متعلّم تجاري (CLP)","رخصة CDL كاملة غير مقيدة","درجة ناجحة في اختبار الطريق لـ CDL"],"explanation":"لا يمكن إجراء جزء القيادة خلف المقود من ELDT قبل أن يحصل المتقدم على CLP، ويجب إكماله خلال سنة واحدة من التدريب الصفّي (النظري). المصدر: دليل CDL في مينيسوتا / صفحة CLP في DPS DVS."},"88":{"q":"في نموذج التصديق الذاتي في مينيسوتا، أي فئة تتطلب من السائق الذي يعمل في تجارة بين الولايات غير معفاة أن يقدّم أيضاً شهادة فاحص طبي سارية؟","options":["الفئة 4 - معفى داخل الولاية","الفئة 1 - غير معفى بين الولايات (خاضع لـ 49 CFR part 391)","الفئة 2 - معفى بين الولايات","الفئة 3 - غير معفى داخل الولاية (خاضع لـ Minnesota Statutes chapter 221)"],"explanation":"الفئة 1، غير معفى بين الولايات، تشهد بأن السائق خاضع لمتطلبات DOT الطبية الفيدرالية في 49 CFR part 391 ويستوفيها، ويجب أن يقدّم شهادة فاحص طبي سارية وأي إعفاءات. المصدر: نموذج/أسئلة شائعة للتصديق الذاتي الطبي لـ CDL في مينيسوتا (DPS DVS)."},"89":{"q":"أي فئة تصديق ذاتي في مينيسوتا تشمل السائق غير المعفى داخل الولاية الذي يخضع لمتطلبات الفحص الطبي الخاصة بالولاية؟","options":["الفئة 4 - معفى داخل الولاية","الفئة 2 - معفى بين الولايات","الفئة 3 - غير معفى داخل الولاية، بموجب Minnesota Statutes chapter 221","الفئة 1 - غير معفى بين الولايات، بموجب 49 CFR part 391"],"explanation":"الفئة 3، غير معفى داخل الولاية، تنطبق على السائقين الخاضعين لمتطلبات الفحص الطبي الخاصة بالولاية في Minnesota Statutes, chapter 221، والذين يجب أيضاً أن يقدّموا شهادة فاحص طبي سارية وأي إعفاءات. المصدر: نموذج/أسئلة شائعة للتصديق الذاتي الطبي لـ CDL في مينيسوتا (DPS DVS)."},"90":{"q":"كم عدد فئات التصديق الذاتي التي يدرجها نموذج التصديق الذاتي الطبي لرخصة القيادة التجارية في مينيسوتا؟","options":["فئتان","أربع فئات","ثلاث فئات","خمس فئات"],"explanation":"يدرج نموذج التصديق الذاتي في مينيسوتا أربع فئات: غير معفى بين الولايات، ومعفى بين الولايات، وغير معفى داخل الولاية، ومعفى داخل الولاية. اثنتان من الأربع (الفئتان غير المعفاتين) تتطلبان شهادة فاحص طبي. المصدر: نموذج/أسئلة شائعة للتصديق الذاتي الطبي لـ CDL في مينيسوتا (DPS DVS)."},"91":{"q":"أين يقدّم حامل رخصة CDL في مينيسوتا نموذج التصديق الذاتي المكتمل وشهادة الفاحص الطبي السارية؟","options":["إدارة السلامة العامة / خدمات السائقين والمركبات (DVS)","مكتب خدمات الناقلين بالمركبات الآلية التابع لـ MnDOT","الإدارة الفيدرالية لسلامة الناقلين بالمركبات الآلية (FMCSA)","السجل الوطني للفاحصين الطبيين المعتمدين"],"explanation":"يقدّم السائقون نموذج التصديق الذاتي وشهادة الفاحص الطبي السارية إلى إدارة السلامة العامة / وحدة CDL في DVS (عبر الإنترنت على drive.mn.gov، أو بالبريد، أو الفاكس، أو شخصياً في محطة فحص السائقين). ثم تُدوَّن معلومات الشهادة في سجل القيادة. المصدر: دليل CDL في مينيسوتا، المتطلبات الطبية؛ أسئلة شائعة للتصديق الذاتي في DPS DVS."},"92":{"q":"تكون شهادة الفاحص الطبي DOT في مينيسوتا سارية عموماً لأي فترة قصوى؟","options":["خمس سنوات","ثلاث سنوات","حتى سنتين","سنة واحدة"],"explanation":"يمكن أن تكون شهادة الفاحص الطبي سارية لمدة تصل إلى سنتين، رغم أن الفاحص قد يصدرها لفترة أقصر بناءً على التاريخ الطبي للسائق. المصدر: دليل CDL في مينيسوتا، تجديد الشهادة الطبية؛ أسئلة شائعة للتصديق الذاتي في DPS DVS."},"93":{"q":"كم يوماً قبل انتهاء صلاحية شهادة الفاحص الطبي ترسل إدارة السلامة العامة في مينيسوتا إشعاراً إلى السائق؟","options":["45 يوماً مسبقاً","90 يوماً مسبقاً","60 يوماً مسبقاً","30 يوماً مسبقاً"],"explanation":"ترسل إدارة السلامة العامة إشعاراً إلى آخر عنوان معروف للسائق قبل 60 يوماً من تاريخ انتهاء صلاحية شهادة الفاحص الطبي أو الإعفاء المسجل في الملف. المصدر: دليل CDL في مينيسوتا، تجديد الشهادة الطبية."},"94":{"q":"إذا تم تخفيض رخصة CDL في مينيسوتا بسبب الفشل في تقديم شهادة فاحص طبي مطلوبة، خلال أي فترة يجوز للسائق إعادة تفعيل رخصة CDL ببساطة عن طريق تقديم شهادة سارية؟","options":["خلال سنتين","خلال 6 أشهر","خلال 30 يوماً","خلال سنة واحدة"],"explanation":"يجوز للسائق إعادة تفعيل رخصة CDL المخفَّضة والتصديقات خلال سنة واحدة عن طريق تقديم شهادة فاحص طبي سارية مع نموذج التصديق الذاتي. إذا تم التخفيض أو التسليم لأكثر من سنة واحدة، يجب على السائق إعادة إجراء اختبارات المعرفة والطريق المطبقة. المصدر: دليل CDL في مينيسوتا، تجديد الشهادة الطبية؛ أسئلة شائعة في DPS DVS."},"95":{"q":"كم تبلغ صلاحية رخصة القيادة التجارية في مينيسوتا قبل أن يلزم تجديدها؟","options":["سنتان","أربع سنوات","خمس سنوات","ثماني سنوات"],"explanation":"تكون رخصة CDL في مينيسوتا (الفئة A أو B أو C) سارية لمدة أربع سنوات ثم يجب تجديدها، وهي نفس دورة رخصة الفئة D العادية. المصدر: صفحات فئات CDL في DPS DVS (إدارة السلامة العامة)."}}};
